-- =============================================================================
-- i-Nov Laureates Import (from MESR API)
-- =============================================================================
CREATE EXTENSION IF NOT EXISTS "unaccent";


-- Step 1: Create i-Nov program and editions
INSERT INTO programs (
  id, name, slug, program_type, description, country, source_url,
  created_at, updated_at
) VALUES (
  uuid_generate_v4(), 'i-Nov', 'i-nov', 'competition',
  'Concours d''innovation i-Nov, soutenu par Bpifrance et l''ADEME. Finances des projets innovants à fort potentiel pour l''économie française.',
  'France',
  'https://www.bpifrance.fr/catalogue-offres/soutien-a-linnovation/concours-dinnovation-i-nov',
  NOW(), NOW()
) ON CONFLICT (slug) DO NOTHING;

INSERT INTO program_editions (id, program_id, name, slug, year, cohort_label, created_at, updated_at)
SELECT uuid_generate_v4(), p.id, e.name, e.slug, e.year, e.cohort_label, NOW(), NOW()
FROM programs p
CROSS JOIN (VALUES ('i-Nov — 2018', 'i-nov-2018', 2018, '2018'),
  ('i-Nov — 2019', 'i-nov-2019', 2019, '2019'),
  ('i-Nov — 2020', 'i-nov-2020', 2020, '2020'),
  ('i-Nov — 2021', 'i-nov-2021', 2021, '2021'),
  ('i-Nov — 2022', 'i-nov-2022', 2022, '2022'),
  ('i-Nov — 2023', 'i-nov-2023', 2023, '2023'),
  ('i-Nov — 2024', 'i-nov-2024', 2024, '2024'),
  ('i-Nov — 2025', 'i-nov-2025', 2025, '2025')) AS e(name, slug, year, cohort_label)
WHERE p.slug = 'i-nov'
ON CONFLICT DO NOTHING;


-- Step 2: Create organizations (732)
WITH source AS (
  SELECT * FROM json_populate_recordset(NULL::record,
    $json$[{"name": "AB7 Industries", "description": "AB7 Industries fabrique et commercialise des produits d’entretien de la maison, du jardin et des piscines, des produits cosmétiques et répulsifs ainsi que des produits vétérinaires. La technologie d’AB7 Industries repose sur l’incorporation d’actif dans des matrices polymères pour permettre une diffusion contrôlée de l’actif dans le temps.", "siren": "349203760"}, {"name": "BIOMEDE", "description": "Afin de répondre de manière naturelle aux problèmes posés par l’accumulation de métaux lourds dans le sol, BIOMEDE développe et commercialise des semences de plantes phytoextractrices des métaux lourds à destination du monde agricole, de l’agriculture urbaine, des collectivités et des entreprises de la dépollution.", "siren": "838412088"}, {"name": "Metagritech", "description": "Metagritech développe et exploite des outils d’aide à la décision basés sur la donnée en agriculture avec le recours à une technologie de rupture en mesure chimique, aux objets connectés et au big data.", "siren": "830929386"}, {"name": "SPYGEN", "description": "SPYGEN est un laboratoire d’expertise scientifique et de recherche appliquée spécialisé dans le suivi de la biodiversité aquatique et terrestre grâce à l’ADN environnemental (ADNe). Les technologies développées permettent d’améliorer le suivi d’espèces rares ou discrètes et visent à renforcer les opérations de veille environnementale à l’échelle mondiale", "siren": "529756108"}, {"name": "DualSun", "description": "DualSun développe et commercialise un panneau solaire hybride de nouvelle génération qui fournit à la fois de l’électricité photovoltaïque et de l’énergie thermique avec un rendement optimal - jusqu’à trois fois supérieur par rapport aux solutions photovoltaïques standards du marché.", "siren": "523618320"}, {"name": "EnerBee", "description": "Société grenobloise créée en mars 2014, EnerBee développe et commercialise des capteurs complètement autonomes connectés et intelligents pour le secteur du bâtiment et de l’industrie. Ses solutions autonomes en énergie, reposent sur sa technologie innovante et unique de génération d’électricité à partir d’un mouvement quelconque, pouvant être très lent voire même irrégulier.", "siren": "800938920"}, {"name": "Kitewinder", "description": "KITEWINDER conçoit et fabrique des éoliennes aéroportées pour la production d’électricité.", "siren": "821889920"}, {"name": "REUNIWATT", "description": "REUNIWATT développe des outils de gestion intelligente de l’énergie à l’aide des Technologies de l’Information et de la Communication pour soutenir l’insertion massive et sécurisée de l’énergie photovoltaïque dans les réseaux électriques", "siren": "518919345"}, {"name": "SOLEAN", "description": "SOLEAN a l’ambition de transformer les techniques d’assemblage de panneaux solaires pour permettre le développement massif de l’industrie française du BIPV – le photovoltaïque intégré au bâtiment. L’entreprise développe un procédé d’automatisation intégré à des robots collaboratifs intelligents et offre des services ciblés pour maximiser la performance globale de la solution.", "siren": "822578845"}, {"name": "AP&BS", "description": "Le projet Symphonia ambitionne de réinventer radicalement la manière de composer de la musique en proposant une application mobile qui permet notamment grâce à des algorithmes d’intelligence artificielle de créer avec un simple smartphone des musiques magnifiques au rendu professionnel.", "siren": "529989147"}, {"name": "Georges.tech SAS", "description": "Georges est le premier robot comptable : une application en ligne capable d’automatiser la comptabilité et les déclarations fiscales des petites entreprises. Grâce à une intelligence artificielle, le logiciel effectue la saisie comptable en pilote automatique. L’indépendant contrôle le travail de son robot pour télétransmettre sa déclaration fiscale.", "siren": "820648830"}, {"name": "IoT.bzh", "description": "IoT.bzh conçoit des outils de développement open source pour les applications sécurisées de l’Internet des Objets Industriels. L’objectif d’IoT. bzh est de simplifier la mise en œuvre d’un modèle de vérification de la conformité et de la cybersécurité sur le très long terme dans le monde des objets industriels connectés.", "siren": "812383370"}, {"name": "LIBRICIEL SCOP SA", "description": "Depuis 2006, LIBRICIEL SCOP a constitué un catalogue d’applications métiers dédié à la dématérialisation des processus des collectivités territoriales et des administrations.\nDans ce cadre, LIBRICIEL SCOP propose ses prestations d’installation, d’intégration, de support associés à leur exploitation par ses clients.", "siren": "491011698"}, {"name": "MJVA-Creaminal", "description": "Creaminal est le leader de la synchronisation musicale (ou musique à l’image) indépendante en France, à l’interface entre les labels indépendants qui manquent de contacts dans les industries médiatiques et ces dernières qui n’ont pas de vision globale et transversale des catalogues indépendants.", "siren": "419675236"}, {"name": "NETATMO", "description": "Netatmo est le leader français des objets connectés pour la maison. Innovants, inspirants et au design élégant, les produits Netatmo permettent à leurs utilisateurs de vivre dans une maison plus sûre, plus saine et plus confortable.", "siren": "532501848"}, {"name": "Nextmind", "description": "Nextmind est une jeune société spécialisée dans les neurotechnologies. Elle développe un nouveau type de capteur cérébral miniature non invasif, et une solution d’algorithmes d’intelligence artificielle qui décode les signaux neuronaux pour effectuer des commandes directement par la pensée.", "siren": "832089031"}, {"name": "DNA Script", "description": "DNA Script développe un procédé de synthèse enzymatique de synthèse d’acides nucléiques sans brin matrice. Ce procédé est de plusieurs ordre de grandeurs plus rapide et plus efficace que les technologies actuelles, et a le potentiel d’accélérer considérablement le développement de nouveaux produits dans les sciences de la vie.", "siren": "801172834"}, {"name": "MYRIADE", "description": "Myriade développe et commercialise des solutions, appareillages, et consommables pour la détection et la caractérisation de nanoparticules vivantes (phages, virus, vésicules) et inorganiques (métaux, polluants).", "siren": "832320725"}, {"name": "AIRWEB", "description": "AIRWEB est un éditeur de solutions logicielles à destination des exploitants de réseaux de transports publics. Les solutions comprennent les fonctionnalités d’informations voyageur, de calcul d’itinéraire, et de billettique dématérialisée.", "siren": "428152607"}, {"name": "ALYCE", "description": "Fondée à Lyon en janvier 2000, ALYCE, spécialiste du recueil de données routières, réalise plus de 500 missions par an, en particulier des comptages, des mesures, et des enquêtes Origine Destination de tout type. Ces données servent de base de travail à la réalisation d’études, principalement dans les domaines de la circulation, des transports et de l’aménagement des infrastructures.", "siren": "429356884"}, {"name": "ADIONICS", "description": "Adionics est une société innovante développant une solution de traitement d’eaux salines, baptisée AquaOmnes. Cette solution repose sur une technologie de rupture d’extraction sélective et de valorisation des sels présents dans des eaux salines industrielles ou naturelles.", "siren": "750152522"}, {"name": "SITIA", "description": "SITIA comprend deux branches d’activités. L’activité bancs d’essais comprend la conception, la réalisation et la mise en service de machines spéciales industrielles pour l’industrie automobile et aéronautique principalement. L’activité robotique agricole est une activité de recherche appliquée qui vise à proposer un robot autonome polyvalent pour les cultures spécialisées.", "siren": "337954143"}, {"name": "CONNECTING FOOD", "description": "Le projet vise à fournir une suite de solutions intégrées basées sur la blockchain permettant le suivi en temps réel de chaque produit alimentaire en assurant l’interopérabilité avec les solutions de suivi actuelles.", "siren": "823043039"}, {"name": "DIGINOVE", "description": "Créée il y a deux ans, Diginove est une petite entreprise de quatre salariés qui se développe autour d’un savoir-faire, le traitement d’images, et de deux activités :\n• le développement et la commercialisation de produits pour la capture documentaire ;\n• le traitement et la visualisation d’images satellites.", "siren": "822255881"}, {"name": "NEXT4", "description": "L’entreprise développe un tracker de containers maritimes (et aériens) à première destination des clients expéditeurs internationaux, utilisant les réseaux de nanosatellites.\nNext4 est forte d’un savoir-faire et d’expériences industrielles des systèmes embarqués intelligents connectés à destination des entreprises et du grand public.", "siren": "838230340"}, {"name": "UNSEENLABS", "description": "UNSEENLABS est spécialisée dans le développement, la production et l’opération d’instruments innovants d’observation de la Terre, dans le spectre électromagnétique. Le premier service proposé par UNSEENLABS est un service de surveillance maritime, permettant la localisation et la caractérisation des navires en mer depuis l’espace, qu’ils soient coopérants ou non.", "siren": "811856376"}, {"name": "7HUGS LABS", "description": "SevenHugs a pour activité la fabrication et la commercialisation d’objets connectés innovants avec leur application logicielle et se positionne sur les applications « Smart Home ». Elle développe la Smart Remote, la première technologie, dont le concept est breveté, permettant de contrôler intuitivement tous les objets connectés de la maison.", "siren": "799970538"}, {"name": "ENHANCIA", "description": "Conception, fabrication et industrialisation d’objets innovants connectés à détection de mouvement par discrimination. L’activité est aujourd’hui centralisée sur la musique mais le marché évoluera en fonction de nos produits.", "siren": "832080469"}, {"name": "Spideo", "description": "Spideo développe et commercialise depuis 8 ans un système de recommandation pour le secteur du Film et de la Télévision. Il s’agit d’une solution logicielle articulant algorithmes, technologies d’enrichissement de données, et monitoring analytique. Outil de soutien aux équipes éditoriales, Spideo prolonge leurs efforts par des propositions personnalisées et expliquées.", "siren": "521942763"}, {"name": "IT CONTROL EXPERT", "description": "La société IT CONTROL EXPERT a pour activité l’expertise thermique, énergétique et l’ingénierie essentiellement dans les domaines du bâtiment et de l’industrie.", "siren": "530890599"}, {"name": "BBS SLAMA", "description": "BBS SLAMA développe et distribue des logiciels pour le bâtiment en thermique, climatique, réseaux hydrauliques/aérauliques. Leur principal logiciel ClimaWin réunit dans un modèle de bâtiment unique les calculs : RT2012, label E+C-, simulation thermique, dimensionnement des systèmes... ClimaWin existe en version plugin dans des environnements de modélisation numérique (BIM).", "siren": "332565035"}, {"name": "LXRepair", "description": "LXRepair possède une plateforme de tests uniques pour caractériser en temps réel les mécanismes de réparation de l’ADN qui déterminent la réponse des patients aux traitements anticancéreux. LXRepair accompagne les sociétés pharmaceutiques pour développer des médicaments plus performants et veut mettre sur le marché des kits diagnostiques pour personnaliser les traitements.", "siren": "797484771"}, {"name": "GoJob", "description": "Gojob est une agence d’intérim digitalisée dont l’ambition est d’offrir un travail avec un salaire décent, une protection sociale et une capacité à progresser à tous ceux qui veulent travailler, quels que soient leur expérience et diplôme. Gojob prend en charge l’ensemble de la partie administrative et comptable.", "siren": "813454717"}, {"name": "CITYTAPS", "description": "CityTaps est une entreprise francilienne ayant inventé un nouveau système d’information dédié à l’eau combinant une dimension matérielle d’objets connectés répartis sur les réseaux d’eau et une dimension logicielle permettant l’analyse et le contrôle de ces réseaux.", "siren": "432103141"}, {"name": "ANANKE", "description": "Conception d’un moteur à apport de chaleur externe qui permet la valorisation de la chaleur fatale industrielle. Celle-ci est convertie en chaleur utile et en électricité : système de cogénération. L’entreprise vise une installation sur site pilote fin 2019.", "siren": "810683078"}, {"name": "SWEETCH ENERGY", "description": "La société Sweetch Energy effectue exclusivement une activité R&D portée sur le développement d’une nouvelle technologie de production d’électricité. Au stade de prototype en début de projet, l’entreprise à un objectif d’industrialiser ces unités à partir de l’année 2023.", "siren": "810876177"}, {"name": "Heyday Integrated Circuits", "description": "Heyday conçoit et vend des gate drivers basés sur la technologie power- thru qu’elle a développée et brevetée. Le gate driver est un composant clé qui a un impact majeur sur l’efficacité énergétique des modules de conversion d’électricité (« power modules »)", "siren": "813603222"}, {"name": "METRON", "description": "METRON est une société située à la convergence du monde de l’énergie et de l’industrie, qui révolutionne l’utilisation des données dans le secteur industriel. METRON développe une plateforme d’intelligence énergétique s’appuyant sur une analyse fine et en temps réel de l’ensemble des données générées par l’usine concernée, afin de la rendre efficiente en énergie.", "siren": "819431834"}, {"name": "antidot", "description": "Antidot est un éditeur logiciel spécialisé dans les technologies de recherche d’information. Notre solution Fluid Topics transforme la façon de chercher et lire la documentation technique en passant de manuels statiques pré- générés à des interfaces dynamiques qui s’adaptent au profil de l’utilisateur.", "siren": "424933448"}, {"name": "imajing", "description": "Imajing conçoit une chaîne d’outils pour capturer, inventorier, mesurer, et surveiller les infrastructures de transport. Du capteur embarqué tout intégré, aux outils d’analyse et solutions de partage web, imajing propose des outils simplifiés à l’extrême pour les utilisateurs tout en offrant des performances dignes des plus gros systèmes.", "siren": "508794674"}, {"name": "Kleros", "description": "Kleros développe un protocole de résolution décentralisée des litiges fonctionnant grâce à la blockchain", "siren": "841671902"}, {"name": "alphée développement", "description": "Créée en 1995, ALPHEE DEVELOPPEMENT, société d’ingénierie, se positionne dans le domaine de l’électronique de puissance et la conversion d’énergie appliquées au transport et à l’industrie. Avec plus de 10 000 chargeurs en service dans les véhicules électriques, ALPHEE est un leader incontournable dans la conception et la fourniture d’alimentations, de chargeurs et convertisseurs embarqués dans le monde de l’électromobilité, ainsi que de stations de charge pour véhicules urbains électriques.", "siren": "403018237"}, {"name": "DASHDOC", "description": "Dashdoc a créé le premier logiciel Saas E-CMR qui structure et accélère les échanges de données et d’informations de la commande à la facturation dans le transport routier de marchandises. Les transporteurs, donneurs d’ordre, expéditeurs et destinataires optimisent leur gestion de transport avec l’échange de données.", "siren": "800970212"}, {"name": "DigiMobee", "description": "DigiMobee édite et exploite (en mode SaaS) des logiciels permettant d’améliorer la performance opérationnelle de flottes de véhicules et d’améliorer l’expérience des voyageurs.", "siren": "834554982"}, {"name": "AGILCARE CONSTRUCTION", "description": "Agilcare conçoit et réalise une nouvelle génération de bâtiments bois performants, évolutifs et dont les éléments et matériaux sont totalement réemployables.\nPour tout type de projets (logement, équipement, tertiaire), ce principe constructif permet de transformer les bâtiments et les déplacer sans générer de déchet ni impacter les sols.", "siren": "831318670"}, {"name": "AKTID", "description": "AKTID conçoit, développe et installe des solutions de tri et de valorisation de déchets clé en main sur tous les segments du marché : déchets ménagers, industriels et du BTP. Ces solutions intègrent des équipements et des systèmes d’exploitation d’un haut niveau pour les exploitants.", "siren": "483647566"}, {"name": "VALAME", "description": "VALAME développe pour ses clients (BTP, Industrie) une solution innovante pour leurs déchets amiantés : un recyclage intégral du déchet, permettant l’élimination de l’amiante et le dégagement de la responsabilité légale qui y est attachée, dans un modèle opérationnel local et d’économie circulaire permettant la valorisation des produits de sortie.", "siren": "849407648"}, {"name": "PIXSTART", "description": "La start-up Pixstart rend des services de suivi des ressources urbaines, agricoles et forestières et d’aide à la décision, développés à partir d’algorithmes d’intelligence artificielle reliant les vérités terrain et les données d’imagerie satellitaires. Les nouveaux paradigmes big data et cloud permettent d’offrir ces services sur de très grands territoires.", "siren": "823514393"}, {"name": "OXXIUS SA", "description": "Oxxius développe, fabrique et commercialise des lasers continus (couvrant le visible, le proche infrarouge et l’UV) pour l’instrumentation optique. Le marché principal est celui des biotechnologies (microscopie, super- résolution, cytométrie en flux, séquençage de l’ADN, excitation de fluorescence).", "siren": "444437362"}, {"name": "LMP SAS", "description": "EXPLAIN développe des applications d’analyse et de veille automatiques des besoins des territoires et de l’opinion publique locale. Ces applications sont destinées aux campagnes électorales et entreprises B2B dont le client ou décideur sont les collectivités et populations locales, et qui ont donc besoin de tout connaître sur eux.", "siren": "789126208"}, {"name": "VOGO", "description": "VOGO développe, commercialise  et  distribue  une  solution  de  diffusion live de contenus audiovisuels basée sur une technologie de traitement de flux vidéo. Cette technologie de rupture vise à améliorer l’expérience des spectateurs au travers de contenus multi-caméras à la demande en live ou en replay tout en offrant des outils audio et vidéo d’analyse à destination des professionnels.", "siren": "793342866"}, {"name": "M4D TREEGRAM", "description": "Spécialisée dans le BIM depuis 10 ans, M4D a réalisé le BIM Management et les modélisations 3D ultra-complexes des chantiers Gehry (Fondation Louis VUITTON, Fondation LUMA).\nBureau d’études, M4D est internationalement reconnu en AMO BIM, en BIM Management, en modélisations avancées avec automations et en gestion de données.", "siren": "518560289"}, {"name": "CONSTRUCTIONS COMPOSITES BOIS", "description": "L’expérience de la société CCB sur le principe constructif LIGNOROC a démontré l’intérêt de sa mise en oeuvre pour le logement individuel. Avec le projet LIGNOROC V2, la société souhaite mettre au point une nouvelle version du matériau et du procédé constructif en cherchant à l’optimiser pour un process de préfabrication lourde et robotisée. Cette évolution\npermettra de répondre à la prochaine RT 2020 avec un produit amélioré économiquement, aux performances techniques uniques mais également validé pour la construction à étages (R+3). L’exploitation des résultats de ce projet favorisera l’exploitation forestière locale et un bilan carbone réduit pour les bâtiments en bénéficiant.", "siren": "490714383"}, {"name": "MATERR'UP SAS", "description": "Materr’UP est une start-up industrielle qui développe des bétons bas carbone d’une nouvelle génération à partir d’un ciment d’argile (Technologie 3C). A iso-performance, ces bétons permettent de réaliser une économie carbone par rapport à des bétons conventionnels. Ces solutions répondent aux exigences de la réglementation RE2020.", "siren": "842959249"}, {"name": "TECHNIWOOD", "description": "Techniwood est un industriel français pionnier, spécialisé depuis 10 ans dans la conception, la fabrication et la vente de systèmes constructifs bois innovants (CTLi Panobloc®, Ossatures bois, Charpente) destinés à la construction et la réhabilitation de bâtiments durables bas carbone très performants.", "siren": "494817430"}, {"name": "GECKO BIOMEDICAL SA", "description": "TISSIUM développe des implants chirurgicaux innovants dans le domaine de la reconstruction des tissus. Sa technologie repose sur une plateforme de polymères propriétaires, adhésifs et biorésorbables issus du MIT, associé à un outil de production, qui lui a permis de développer deux produits dont un ayant obtenu les autorisations européennes.", "siren": "793166299"}, {"name": "PIXEE MEDICAL", "description": "Pixee Médical développe et commercialise des solutions de chirurgie orthopédique assistée par ordinateur utilisant la réalité augmentée. Notre équipe expérimentée regroupe des compétences en ingénierie mécanique, logiciel 3D et vision par ordinateur, réglementaire et gestion de projet.", "siren": "832674816"}, {"name": "KLAXIT", "description": "Klaxit est le leader européen du covoiturage courte distance. Grâce à une application mobile gratuite et accessible  au  grand  public,  Klaxit créé des réseaux de covoiturage sur la base des flux domicile-travail en accompagnant les entreprises et les collectivités. Klaxit compte plus d’un million de membres en France.", "siren": "753153238"}, {"name": "LA COMPAGNIE DES MOBILITÉS Geovelo", "description": "Geovelo développe une application gratuite destinée  à  aider  les cyclistes dans leurs besoins du quotidien. Geovelo peut ensuite, grâce à la communauté d’utilisateurs de l’application, proposer des services aux villes, notamment le partage des signalements effectués dans l’application.", "siren": "521563742"}, {"name": "GATEWATCHER", "description": "Gatewatcher est l’éditeur du système de détection d’intrusions et de menaces avancées Trackwatch®. Cette solution a obtenu le Visa de Sécurité pour la Qualification Elémentaire délivré par l’ANSSI (Agence Nationale des Systèmes d’Information) en avril 2019.", "siren": "810505248"}, {"name": "SEKOIA", "description": "SEKOIA est spécialiste en Cybersécurité et propose des services professionnels ainsi que la solution SEKOIA.IO, solution de cyberdéfense intégrant des capacités de détection modernes combinées à une threat intelligence hyper contextualisée.", "siren": "502067705"}, {"name": "BeFC", "description": "BeFC offre une solution énergétique durable et écologique pour l’alimentation d’objets électroniques de faible puissance. En moyenne, 97 % des piles miniatures finissent à la décharge. Cette technologie réduit l’impact environnemental et les coûts d’élimination. L’écoconception permettra le remplacement de piles polluantes et l’émergence de produits innovants respectueux de l’environnement.", "siren": "883544009"}, {"name": "Actility", "description": "Actility est la première entreprise mondiale dans le domaine du déploiement, de la mise à l'échelle et de l'enrichissement des réseaux IoT. L’entreprise exploite les technologies LoRaWAN ou de l’IoT cellulaire. Actility adresse les opérateurs publics et privés.", "siren": "522305473"}, {"name": "CENTILOC", "description": "Centiloc est spécialisée dans le domaine de l’Internet des Objets. Elle développe deux concepts autour d’un PCB innovant industrialisable pour des applications électroniques simples et une innovation de connectivité des surfaces.", "siren": "852082882"}, {"name": "ELA Innovation", "description": "ELA Innovation est spécialisée dans la recherche, le développement, la fabrication et la commercialisation d’objets communicants basés sur les technologies RFID Active, Bluetooth Low Energy et LoRa. ELA Innovation commercialise une large gamme de Tags, capteurs sans fil et lecteurs à durée de vie élevée pour de nombreuses applications industrielles.", "siren": "432799278"}, {"name": "JPB SYSTEME", "description": "JPB Système est l’un des leaders de la fabrication de solutions technologiques de serrage pour l’aérospatiale, l’aéronautique et d’autres secteurs industriels. Véritable natif digitale, l'entreprise est considérée comme l'un des pionniers de l’industrie 4.0 en France. Fort de cette expérience nous souhaitons accélérer pour aller plus loin dans ce sens", "siren": "402213441"}, {"name": "BIOINSPIR", "description": "BIOINSPIR valorise une partie des travaux de recherche du laboratoire ChimEco (UMR 5021 CNRS/UM) : les capacités d’absorption hors norme de métaux d’intérêt par certaines plantes (la « Biosoprtion ») et des catalyseurs innovants obtenus à partir de cette biomasse chargée en métaux (les\n« Ecocatalyseurs »).", "siren": "880557236"}, {"name": "Deepomatic", "description": "La plateforme Deepomatic permet la conception, l’implémentation à l’échelle et la gestion d’applications de vision par ordinateur. Ces applications sont appelées automates visuels. Ils permettent de guider ou même d’exécuter des tâches répétitives sur le terrain.", "siren": "803489236"}, {"name": "DEFACTO TECHNOLOGIES", "description": "DEFACTO Technologies offre désormais une solution d’EDA (Electronic Design Automation) complète basée sur plusieurs outils EDA génériques couvrant les besoins avancés d’intégration et de vérification de SoCs complexes notamment au niveau RTL. Le produit actuel de DEFACTO TECHNOLOGIES est la suite logicielle dite STAR.", "siren": "449565241"}, {"name": "VMPS CORPORATION", "description": "Notre mission est de rendre l’apprentissage personnalisé, ludique et engageant en tirant le meilleur des intelligences humaine et artificielle basées sur l'interaction à l’écrit ou à l’oral. Nos clients sont des milliers de familles et des collectivités ou des partenaires souhaitant être utiles pour leur territoire.", "siren": "809744907"}, {"name": "MILVUE", "description": "Milvue est un éditeur de logiciel médical, spécialiste de l’urgence hospitalière et de l’imagerie médicale, de son workflow et de l’intelligence artificielle. Par le développement des solutions innovantes utilisant le Deep Learning sur des données médicales, notre mission est d’offrir aux acteurs de la santé les outils pour accélérer, sécuriser et optimiser le workflow et la prise en charge des patients en services d’urgence, et ainsi désengorger les urgences.", "siren": "841005432"}, {"name": "DAM Group", "description": "Depuis plus de 30 ans notre groupe offre des solutions clés en main de tests, de mesures et d’assemblages dans les domaines Automobile, et Aérospatiale.\nNous offrons à nos clients un large champ de compétences (Electronique, Logiciel, Mécanique, Automatisme, Robotique, Hydraulique, Vision) pour réaliser des systèmes complexes dans leur intégralité", "siren": "388676439"}, {"name": "RETROFLEET", "description": "Transformation de flottes de véhicules thermiques en véhicules électriques (retrofit), en impliquant les collectivités dans un projet d’économie circulaire au plus proche de leurs besoins, créateur d’emplois locaux (industriels, formation, maintenance), de nouveaux services numériques et de gestion énergétique du territoire.", "siren": "883589707"}, {"name": "AXIONABLE", "description": "AXIONABLE, jeune société innovante créée fin 2016 par trois ingénieurs, accompagne des entreprises dans leurs projets  à  impact  positif  grâce  à une utilisation responsable de l’Intelligence Artificielle. La société propose à ses clients des solutions d’IA clé en main grâce à son infrastructure logicielle (framework) « Responsible Machine Learning» en garantissant une industrialisation responsable de la technologie de machine learning (ML)", "siren": "823890546"}, {"name": "Telaqua", "description": "Telaqua a pour ambition de devenir un des acteurs incontournables du smart grid (réseau intelligent) de l’eau afin d’aider les différents acteurs à mieux la consommer et mieux la distribuer. L’entreprise répond ainsi à la problématique sur la réduction de la consommation d’eau des agriculteurs, plus gros consommateurs dans le monde, dans un contexte de raréfaction de la ressource et de changement climatique.", "siren": "839198066"}, {"name": "wever", "description": "wever propose une plateforme de mobilité innovante et unique permettant la co-construction avec les salariés du Plan de Mobilité d’Entreprise ou des Plans de Déplacement InterEntreprises. Elle accompagne les acteurs économiques (entreprises, zones d’activités, opérateurs de mobilité, collectivités territoriales, etc.) en leur proposant de réinventer une mobilité performante, inclusive et durable.", "siren": "812989002"}, {"name": "HEWEL SAS", "description": "Start-up issue des Hôpitaux universitaires de la Pitié-Salpêtrière, Hewel propose des solutions dédiées à l’examen et à l’analyse de lames histopathologiques numérisées, notamment à des fins d’enseignement, de recherche ou d’aide au diagnostic en routine.", "siren": "830690764"}, {"name": "PROOV STATION", "description": "Proov Station révolutionne le monde de l’automobile avec ses nouvelles technologies de détection de défauts des véhicules. La spécialité de l’entreprise : l’Intelligence Artificielle. L’entreprise se positionne comme pionnière dans le domaine de l’inspection automobile intelligente et automatisée grâce à son système de portique de détection.", "siren": "842788069"}, {"name": "PROPHESEE", "description": "Prophesee est une start-up fondée en 2014 par une équipe internationale composée de scientifiques, entrepreneurs et investisseurs dont l’objectif est de développer, industrialiser et commercialiser des produits exploitant la technologie disruptive de la vision dite évènementielle, une technologie de capture d’information inspirée du fonctionnement du cerveau et de l’œil humain.", "siren": "800681892"}, {"name": "QUANDELA", "description": "A partir d’une technologie pour fabriquer des générateurs de qubits photoniques uniques au monde, Quandela développe et commercialise les futurs ordinateurs quantiques ainsi que les réseaux de communications optiques qui nous permettront de s’y connecter. Quandela est un acteur central aux infrastructures numériques des décennies futures.", "siren": "830721098"}, {"name": "Batiprint3D", "description": "Batiprint3D développe et commercialise de nouvelles solutions numériques et matérielles pour la robotisation et la modernisation du BTP en s’appuyant sur une expertise en impression 3D XXL de matériaux isolants.", "siren": "880209416"}, {"name": "Vesta Construction Technologies", "description": "Vesta Construction Technologies conçoit  et  construit  des  bâtiments plus respectueux de l’environnement grâce à des procédés novateurs d’industrialisation et de digitalisation. L’entreprise développe des solu- tions de construction modulaire bois et matériaux biosourcés, clef en main, pour les maîtres d’ouvrages leur permettant d’optimiser les phases de conception et de construction.", "siren": "878798115"}, {"name": "G-LYTE", "description": "G-Lyte développe une nouvelle génération d’électrolytes ultrastables à haut rendement permettant d’augmenter très sensiblement la durée de vie des modules photovoltaïques, basés sur la technologie des cellules à colorant. Les panneaux photovoltaïques intégrant la technologie G-Lyte atteignent des durées de vie supérieures à 20 ans. G-lyte développe ainsi une technologie prometteuse pour le développement du smart grid, de l’électronique nomade et de la mobilité électrique en Europe.", "siren": "879295277"}, {"name": "Kimialys", "description": "Grâce à son traitement de surface innovant des biocapteurs, Kimialys se donne pour mission d’apporter des solutions novatrices et bénéfiques en santé publique, ouvrant de nouvelles perspectives à l’analyse in vitro en santé humaine, et particulièrement dans les tests de diagnostic rapide.", "siren": "889602793"}, {"name": "OCEAN Dx", "description": "OCEAN Dx a vocation à mettre sur le marché des tests de diagnostic in vitro innovants ultra-sensibles pour les maladies infectieuses.", "siren": "849349642"}, {"name": "Audensiel healthcare", "description": "AIDRUG mène des activités de Conseil, d’ingénierie et de développement de nouveaux produits pour les différents segments du marché de la santé, entre autres les secteurs de l’industrie pharmaceutique, des biotechnologies et des dispositifs médicaux.", "siren": "818919995"}, {"name": "Bioprox healthcare", "description": "BIOPROX HEALTHCARE propose une gamme complète de probiotiques en vrac ainsi que des services à façon (fermentation et lyophilisation de souches propriétaires, études de développement, optimisation du rendement et amélioration de la stabilité) à ses clients du marché mondial des compléments alimentaires et des aliments fonctionnels.", "siren": "622024180"}, {"name": "DEMBoost", "description": "DEMBOOST est une jeune société innovante créée sous l’impulsion d’anciens salariés du Commissariat à l’énergie atomique (CEA) avec l’ambition de revisiter le concept « safer, cheaper, faster, flexible » dans le domaine du démantèlement d’installations nucléaires en développant des solutions innovantes dans la mesure, la sûreté et la logistique.", "siren": "845055938"}, {"name": "Gene&Green TK", "description": "Gene&GreenTK est une société de biotechnologie issue de l’Université d’Aix-Marseille développant des enzymes très résistantes découvertes dans le Vésuve. Elle a développé deux approches enzymatiques novatrices, dont la technologie VesuBACT, qui permet de lutter contre les infections bactériennes sans générer de résistance microbienne, avec des débouchés prometteurs notamment pour le biocontrôle.", "siren": "793845314"}, {"name": "GREENOV-ITES", "description": "GREENOV-ITES, SAS à mission et JEI, développe et porte des solutions innovantes pour le maritime, notamment sur des projets de CleanTech pour l’environnement marin, en lien avec les évolutions réglementaires, sociétales et citoyennes. La première solution développée est un système de réduction du bruit sous-marin émis par les travaux maritimes.", "siren": "892947847"}, {"name": "INIT ML", "description": "ClipDrop fournit une solution de détourage d’images unique, basée sur deux avancées techniques majeures dans la segmentation d’images par Deep Learning et la réalité augmentée. Elles permettent à tout utilisateur de photographier un objet, de le détourer automatiquement puis de le coller dans une image, en seulement deux clics.", "siren": "885384289"}, {"name": "INNOVAFEED", "description": "InnovaFeed génère de la protéine d’insecte à partir de coproduits agricoles abondamment disponibles en France. Ses produits sont commercialisés sous forme d’ingrédients afin de soutenir des filières alimentaires locales, résilientes et durables. InnovaFeed déploie actuellement son empreinte industrielle, ce qui permettra la création de centaines d’emplois locaux à horizon 2023.", "siren": "819671843"}, {"name": "O2D Environnement", "description": "O2D ENVIRONNEMENT fournit des systèmes de sols perméables minéraux et végétalisés pour l’aménagement de parkings et voies d’accès durables. Elle accompagne les projets de la conception à la phase chantier, en France et en Belgique. L’entreprise mène une démarche engagée de recherche et développement dans le domaine des technosols perméables.", "siren": "478934011"}, {"name": "Purecontrol", "description": "Purecontrol est spécialisée dans l’utilisation de l’intelligence artificielle pour le pilotage des systèmes à variables multiples dans le but d’améliorer la performance énergétique et environnementale des équipements industriels des entreprises et des collectivités. La société commercialise un premier produit PurePOOL qui permet de réduire considérablement la consommation énergétique des piscines.", "siren": "827813585"}, {"name": "SIKIWIS", "description": "SIKIWIS est une entreprise de deep tech française fondée en 2009 axée depuis son origine sur la production logicielle « low et no code ». Afin de répondre aux difficultés de mise en place d’ERP et aux besoins constant en digitalisation sur mesure des grands groupes, SIKIWIS a créé la plateforme no-code DIGITALIZR. Cet outil avec architecture technique permet la création de logiciels inspirée des méthodes les plus modernes de production industrielle.", "siren": "511492472"}, {"name": "Vianova", "description": "VIANOVA développe une plateforme digitale entre les villes et les opérateurs de mobilité connectée, électrique, partagée et bientôt autonome. Cette suite d’outils, par l’analyse des données de mobilité issues de ces moyens de transports, permet aux villes d’améliorer leur compréhension de l’ensemble des flottes de véhicules présentes sur leur territoire.", "siren": "831679733"}, {"name": "WiZama", "description": "Wizama a créé SquareOne, la console de jeux de société interactifs dotée d’un écosystème d’objets connectés.\nCette console est composée d’un écran tactile et d’éléments de jeux connectés (cartes, dés et pions) permettant des interactions entre les objets physiques et le monde numérique.", "siren": "828404426"}, {"name": "Cap 2020", "description": "Cap 2020 propose des services innovants basés sur les dernières avancées technologiques afin d’évaluer les risques agroclimatiques (gamme metIS®) et ceux liés aux bioagresseurs (gamme CapTrap®). Ainsi, les acteurs agricoles peuvent prendre la bonne décision, au bon moment et au bon endroit.", "siren": "494993090"}, {"name": "CMDL", "description": "La société CMDL se positionne généralement comme expert / « Commissioneur » en tant qu’Assistant à Maîtrise d’Ouvrage (AMO) énergétique pour accompagner des projets bâtiments ayant des objectifs énergétiques ambitieux avec un engagement sur les charges ou les consommations énergétiques.", "siren": "510687304"}, {"name": "HINLAB", "description": "HinLab transforme la surveillance médicale des patients en développant des appareils intelligents. Son premier produit, Copernic, est la nouvelle génération de moniteurs de signes vitaux des patients à l’hôpital. Cette solution connectée est regroupée dans un seul appareil innovant petit, portable et puissant.", "siren": "849574926"}, {"name": "Hirondelle médicale", "description": "L’activité de la société Hirondelle Medical réside dans la conception et la production d’instruments chirurgicaux innovants, les guides-broche, ainsi que dans la création de modes opératoires spécifiques mi-invasifs sécurisés permettant de visualiser avec précision le placement des broches et des vis lors d’opérations minutieuses de la colonne vertébrale.", "siren": "824908123"}, {"name": "Laclarée", "description": "Laclarée développe des lunettes à verres adaptatifs pour la correction de la presbytie. Laclarée a breveté une technologie de lentilles optiques basée sur la microfluidique qui apporte une solution à une proportion significative de presbytes aujourd’hui très gênés avec les solutions actuelles.", "siren": "820569218"}, {"name": "Arkhn", "description": "Arkhn développe et déploie des architectures de données dans les établissements de santé en intégrant et standardisant les informations collectées dans les logiciels du système d’information hospitalier.\nPour cela Arkhn utilise le standard FHIR (Hl7, ouvert et neutre), adopté par une vaste communauté d'utilisateurs. Les données sont alors stockées, standardisées dans l’architecture data, accessibles pour la recherche et interopérables avec l’API FHIR ouverte sur laquelle il est possible de connecter différents outils (logiciel de recherche clinique...etc).", "siren": "853328201"}, {"name": "EYELIGHTS", "description": "Inspirée des technologies utilisées sur les avions de chasse, Eyelights a créé une première technologie révolutionnaire en réponse à ce besoin des motards : l’EyeRide qui est un dispositif futuriste propulsant la réalité augmentée grâce à la technologie d’affichage tête haute (HUD).", "siren": "819514118"}, {"name": "TWICE.AI", "description": "Twice.ai est éditeur de solutions IA en réponse à des problématiques industrielles.", "siren": "877576090"}, {"name": "GAIAR", "description": "GAIAR est une plateforme d’hébergement internationale permettant à l’ensemble des professionnels de la culture de protéger, gérer et diffuser des contenus culturels numériques, et bientôt physiques. Grâce à la technologie blockchain, GAIAR simplifie, sécurise et modifie fondamentalement les processus de contractualisation des droits d’auteurs, de diffusion et monétisation des contenus.\nL’ambition de GAIAR est de développer des fonctionnalités simples, transparentes et sécurisées couvrant tous les aspects de la gestion de contenus, d’oeuvres et d’événements culturels quels qu’ils soient, en différé ou en live, de sa conception à sa vente en passant par sa diffusion : encapsulation des actifs culturels dans un token ERC721 pour conférer à l’oeuvre une identité infalsifiable, unique, non fongible, encodage, stockage et diffusion à partir d’un réseau décentralisé, création d’une « Market Room » pour le financement des projets (prise de participation de partenaires financiers, gestion de droits d’exploitations complexes).", "siren": "820961589"}, {"name": "Tech’4’Team", "description": "Tech’4’Team développe une solution logicielle complète nommée Arenametrix - incluant CRM, business intelligence et Yield management - spécialisée pour les billetteries sportives, culturelles et de loisirs. La société souhaite aujourd’hui diversifier sa proposition avec un développement « vertical ».", "siren": "794062497"}, {"name": "ECLORE ACTUATORS", "description": "Eclore Actuators développe une solution de soufflet bio-inspiré à haute efficacité énergétique, 100% recyclable avec une empreinte écologique drastiquement réduite, basée sur des procédés industriels de pliage uniques détenus en interne. Eclore Actuators se positionne comme un fabricant de produits issus de cette technologie.", "siren": "879182533"}, {"name": "Epigene Labs", "description": "Epigene Labs est une startup de biotechnologies qui développe une solution d’oncologie de précision. Grâce à de l’intelligence artificielle, Epigene Labs veut exploiter de grands volumes de données cliniques et omiques pour améliorer les processus de découverte de nouveaux médicaments et de repositionnement de médicaments existants.", "siren": "845367713"}, {"name": "DIGITICA SAS", "description": "Digitica SAS est une startup française florissante lancée en 2017 dans l’optique de simplifier la gestion d’entreprise des indépendants, des TPE et des PME. Créée par des entrepreneurs, pour des entrepreneurs, elle répond à une demande grandissante : gagner du temps au quotidien sur les tâches administratives chronophages.", "siren": "809022643"}, {"name": "Vaonis", "description": "Nous créons des stations d'exploration, combinaison parfaite entre un télescope et un appareil photo. Nos deux premiers instruments, Stellina et Vespera, sont dotés d’un design unique. Ils permettent de capturer des images de l'Univers et de les partager facilement depuis une tablette ou un mobile.", "siren": "823710447"}, {"name": "GAYA", "description": "Gaya commercialise à ses clients une offre clé en main intégrant la transformation des équipements de manutention de diesel vers l’Hybride/Hydrogène et la fourniture d’hydrogène renouvelable produite sur le site du client. Pour ceci GAYA a 2 métiers, le rétrofit de matériel et le développement de site de production d’hydrogène.", "siren": "893538512"}, {"name": "OKEENEA DIGITAL", "description": "Okeenea Digital développe des applications smartphones pour permettre le repérage, l’orientation et le guidage des personnes dans le cadre urbain, les transports et les lieux de destination avec des interfaces conçues de manière inclusive et contextuelle.", "siren": "848981809"}, {"name": "Wefight", "description": "La société montpellieraine est spécialisée dans le développement d’assistants virtuels à destination de patient(e)s atteints de cancers ou de maladies chroniques et de leurs proches : Vik. Vik simplifie l’accès à une information de qualité validée médicalement pour soutenir le patient tout au long de son parcours de soin.", "siren": "827791880"}, {"name": "ORTHOPUS", "description": "La start-up nantaise ORTHOPUS développe des assistants robotiques dédiés à la mobilité du bras. Engagée dans l'Économie Sociale et Solidaire, l’entreprise met son expertise technique au service des personnes en situation de handicap moteur. Son objectif est de démocratiser l'accès aux dispositifs médicaux en proposant des solutions innovantes à prix équitable.", "siren": "843788811"}, {"name": "VitaDX International", "description": "VitaDX développe des logiciels pour détecter précocement le cancer. VitaDX a structuré une équipe de 25 personnes, combinant une expérience scientifique (traitement d’image, IA, biologie) ainsi que dans le domaine des logiciels médicaux et de l’entreprenariat. VitaDX a levé 8 M€ pour développer et commercialiser sa première solution VisioCyt® Diag.", "siren": "811141977"}, {"name": "Micr’Eau", "description": "Depuis plus de 20 ans, Micr’Eau est spécialisée dans le traitement de l'eau potable, des eaux usées, de l’élimination d'arsenic. La société est également leader sur le marché français du stockage et torchage de biogaz urbain et industriel. Elle exporte également ses savoir-faire techniques au Chili et en Amérique Latine.", "siren": "422599779"}, {"name": "Seaturns", "description": "Startup bordelaise, Seaturns développe une solution intelligente et nouvelle qui produit de l’électricité à partir de l’énergie des vagues. Cette innovation concilie contraintes techniques et économiques pour réduire le coût de production et la rendre compétitive sur différents marchés tels que réseaux et sites isolés, dans le monde entier.", "siren": "815307764"}, {"name": "BiOceanOr", "description": "Grâce à ses innovations technologiques de pointe mêlant biologie et intelligence artificielle, BiOceanOr a développé des services pour la prédiction des paramètres critiques de la qualité de l’eau de nos océans. La solution AquaREAL permet d’anticiper ces risques pour les acteurs de l’aquaculture et de la surveillance environnementale", "siren": "834336570"}, {"name": "MURMURATION", "description": "Murmuration se base sur une approche combinant données satellite d’observation de la Terre, en particulier des données issues du programme européen Copernicus, avec des données in-situ et des statistiques socio-économiques, afin d’évaluer l’impact de l’activité humaine sur l’état d’un écosystème indépendamment de sa localisation dans le monde.", "siren": "848934972"}, {"name": "Cyblex Technologies", "description": "Spécialisée dans l'édition de logiciels de cybersécurité, CYBLEX Technologies est experte en sécurité des systèmes d’information et de protection des réseaux qui allie de l’Intelligence Artificielle, de l’Analyse Comportementale, de la Threat Intelligence et d’hypervision, pour aider les entreprises à mieux détecter les attaques informatiques.", "siren": "844786525"}, {"name": "ESCAPE TECHNOLOGIES", "description": "Escape est une plateforme qui réinvente le test dynamique de la sécurité des applications (DAST), avec un focus sur la gestion de la surface d’attaque (ASM), grâce à une technologie innovante d’Intelligence Artificielle.\nEscape réalise un projet en quatre volets. L'objectif est d'affiner l'exploration de son logiciel pour comprendre l'API et personnaliser les tests de pénétration. L'entreprise souhaite également étendre sa technologie aux API REST, prédominantes sur le marché. Par ailleurs, Escape optimise sa plateforme SaaS pour réduire la durée d'un scan et la consommation de puissance de calcul, préparant ainsi une croissance à grande échelle. Enfin, Escape s'emploie à automatiser la correction des failles de sécurité pour simplifier le travail des développeurs et minimiser les erreurs humaines.", "siren": "888699584"}, {"name": "UNITED MOTION IDEAS (UMI)", "description": "UMI développe une technologie unique pour collecter des feedbacks des acteurs du marché afin d’éclairer / sécuriser les décisions d’investissement sur un projet. Cette technologie éprouvée est à la fois puissante pour cibler les acteurs les plus concernés par une innovation et intelligente pour engager le plus efficacement chaque acteur.", "siren": "798755914"}, {"name": "Zorba Group", "description": "Fondé en 2003, ZORBA est un groupe indépendant de création et de production audiovisuelle implanté à Paris, Shanghai, Singapour et Toronto. Pionnier dans la réalisation d’expériences visuelles et sonores, ZORBA collabore avec l’ensemble de la filière musicale française et s’attache particulièrement à son rayonnement international.", "siren": "449830314"}, {"name": "WIREMIND SAS", "description": "WIREMIND SAS est une start-up fondée en 2014 qui développe des outils d'aide à la décision en matière de gestion des revenus et de tarification pour le secteur du transport et de l’évènementiel. Les solutions développées par WIREMIND ont pour objectif d’éliminer toute complexité inutile pour les utilisateurs, afin de mobiliser ces derniers sur des actions à forte valeur ajoutée.", "siren": "805145828"}, {"name": "RollingFunds", "description": "RollingFunds est une FinTech française qui développe et exploite une plateforme électronique innovante permettant aux entreprises de digitaliser leurs relations d’affaires BtoB et d’y intégrer des solutions de financement accessibles en un clic.", "siren": "844752717"}, {"name": "ALPHAIOTA", "description": "Grâce à son système de vidéosurveillance innovant, Vizzia permet aux collectivités territoriales qui en sont équipées de lutter contre les dépôts sauvages. La solution complète développée par Vizzia à destination des collectivités leur permet d’identifier les dépôts sauvages ainsi que leurs auteurs, et de dissuader ces derniers durablement.\nVizzia entend devenir la première entreprise proposant aux territoires des technologies innovantes d'analyse d'images et de détection de déchets intégrées à un système de caméras autonomes afin d’aider les villes à lutter contre les dépôts sauvages. Ainsi, ce projet vise à accompagner les acteurs locaux dans la mise en place d’une politique de réduction des dépôts sauvages et donc dans le financement de la dépollution. Cela est rendu possible grâce aux développements d’une IA d’analyse couplée à une caméra nomade et une plateforme Saas.", "siren": "899832901"}, {"name": "Keymaging", "description": "Keymaging conçoit, développe et commercialise la solution Keydiag d’aide au raisonnement diagnostic et d’automatisation de l’édition de compte rendu diagnostique.", "siren": "844169458"}, {"name": "ATHENA RECHERCHE ET INNOVATION", "description": "ATHENA R&D&I a développé un procédé qui produit de l’hydrogène par fermentation bactérienne à partir d’effluents organiques, générant une énergie décarbonée, locale et renouvelable. ATHENA RECHERCHE ET INNOVATION développe un procédé de production d’hydrogène par voie biologique à partir des eaux usées et des déchets organiques des industries agroalimentaires. L’objectif est de créer des écosystèmes hydrogène au plus près des industriels en vue de décarboner leurs activités et de baisser leurs consommations d’énergies.", "siren": "823166020"}, {"name": "WATURA", "description": "TIA est un agent pédagogique basé sur un modèle d’intelligence artificielle spécialisé dans les métiers de l’eau pour aider à résoudre des problèmes techniques en instantané \nWatura est une PME spécialisée dans la formation technique aux métiers de l’eau. Depuis 2018, elle a développé sa propre plateforme de formation digitale permettant à plus de 6 000 apprenants de se former sur des thématiques techniques liées à l’eau et l’assainissement, en France et à l’international.", "siren": "522427038"}, {"name": "Loop Logistics (LIZEE)", "description": "RMS développe un outil logiciel qui va rendre rentable le traitement des retours clients et amener l’économie circulaire à un niveau industriel. \nAfin d’aider les entreprises à repenser leur modèle économique et à établir une stratégie d’économie circulaire, Lizee propose une technologie clé en main pour permettre aux marques et grandes enseignes de facilement proposer leurs produits à la location éphémère ou par abonnement, et à la vente en seconde main ou reconditionné.", "siren": "849117957"}, {"name": "APMONIA THERAPEUTICS", "description": "Le projet INOTAX d’Apmonia Therapeutics vise à évaluer le potentiel clinique d’un nouveau candidat médicament, le peptide TAX2, dans divers cancers à tumeurs solides. \nApmonia Therapeutics est une société de biotechnologie développant des stratégies thérapeutiques innovantes ciblant la matrice extracellulaire. S’appuyant sur les avancées récentes en bioinformatique, ainsi que sur des technologies de screening et de validation de pointe, Apmonia Therapeutics a pour vocation de développer de nouvelles thérapies pour les patients atteints de cancers.", "siren": "849959390"}, {"name": "JALON THERAPEUTICS", "description": "Afin de soumettre en 2025 une demande d’autorisation d’essai clinique de Phase I, le projet vise à réunir l’ensemble des éléments entrant dans la constitution du dossier réglementaire. \nJalon Therapeutics développe de nouvelles approches thérapeutiques en oncologie basées sur l’inactivation de la voie de signalisation AAC11. Cette voie, jusqu’à présent peu explorée, est essentielle à la survie des cellules cancéreuses. Jalon Tx a mis au point une plateforme de peptides capables de bloquer cette voie.", "siren": "893497859"}, {"name": "HRV Simulation", "description": "OPTEAM a pour objectif de créer une plateforme dédiée à l’analyse, à la gestion et à l’organisation des postes de travail en considérant les facteurs de risques liés aux TMS \nFondée en 2013 à Changé, HRV Simulation se distingue en tant que société innovante spécialisée dans la réalité virtuelle et la simulation. Elle se concentre sur trois domaines d’expertise : l’analyse ergonomique des facteurs de risque de TMS, la simulation médicale et les solutions pour favoriser le bien-vieillir.", "siren": "793796806"}, {"name": "ACCWING SAS", "description": "Le projet ACC vise à soutenir la phase d’industrialisation de la jeune société ACCWing, développant des ailes très performantes à destination de navires de plaisance et de commerce. \nACCWing est un concept innovant d’ailes à destination de tous types de voiliers, y compris les plus grands. Simples d’utilisation, très performantes et automatisées, ces ailes apportent aux navires de plaisance des performances accrues, et permettent aux navires de transport de réduire leur impact environnemental.", "siren": "898198411"}, {"name": "KARDINAL", "description": "Kardinal souhaite exploiter à la fois les données issues de l’historique des livraisons réalisées sur les territoires (selon le découpage en cellules géographiques), mais également combiner ces données avec des données futures. \nKardinal est une société spécialisée dans le secteur du transport proposant une solution SaaS d’optimisation des tournées en temps réel.", "siren": "809234586"}, {"name": "AEROFORCE", "description": "WoC développe un gréement innovant adapté à la propulsion par le vent des navires de marine marchande : ailes gonflables, étanches, rétractables et automatisées pour la décarbonation du transport maritime. \nAEROFORCE est en activité depuis avril 2022 sur la base de Lorient (56) et a pour vocation de concevoir, développer, assembler et commercialiser des systèmes d’ailes gonflables rétractables autoportées à destination du nautisme (ailes de 125 m²) et du maritime (ailes de 250 m² pour vraquiers de 100 à 200m).", "siren": "913415931"}, {"name": "ASTRAN", "description": "Astran permet aux entreprises de poursuivre leurs activités pendant une attaque par ransomware en fournissant un stockage indépendant, multi-cloud et sécurisé pour leurs données critiques.", "siren": "897590592"}, {"name": "PATHWAY (NAVALGO)", "description": "Pathway est le moteur de traitement de données le plus rapide du marché. Le premier data product Pathway Logistics App permet l’analytique opérationnelle en temps réel, y compris prédictive (anomalies, ETA’s, etc.) pour les actifs en mouvement.", "siren": "882417314"}, {"name": "NOMAD EDUCATION", "description": "Nomad Education, entreprise à mission, accompagne la réussite des jeunes francophones, quel que soit leur niveau scolaire ou social. À travers son application mobile, elle propose des contenus de révision, rédigés par 350 enseignants, couvrant 450 diplômes du primaire au supérieur, dans toutes les matières.", "siren": "533327128"}, {"name": "LYS THERAPEUTICS", "description": "Lys Therapeutics est une société de biotechnologie pionnière d’une approche révolutionnaire pour soigner les patients souffrant de maladies neurodégénératives ou neurovasculaires en ciblant les disfonctionnements de la barrière hémato-encéphalique.", "siren": "895069904"}, {"name": "Avatar Mobilité", "description": "Avatar Mobilité développe, assemble et commercialise des véhicules pratiques et sobres puis facilite leur diffusion internationale grâce à une plateforme ouverte et aux services associés. Notre premier véhicule, ULIVE, est une voiture électrique ultra légère (catégorie L7) et solaire, capable de transporter quatre personnes à 90 km/h sur 150 km.", "siren": "901981456"}, {"name": "Animaj", "description": "Animaj développe un modèle d’entreprise et des solutions technologiques de pointe basées sur la data et l’IA pour l’ensemble du cycle de vie des contenus d’Animation 3D – de la détection et acquisition d’IPs à fort potentiel à la conception, développement, production et enfin diffusion multi-plateformes de contenus d’animation.", "siren": "912214673"}, {"name": "Learn&Go", "description": "Depuis 2017, Learn&Go développe et distribue des solutions d’apprentissage pour l’éducation et la compensation des troubles du langage. \nSa plateforme Kaligo accompagne aujourd’hui les enseignants dans l’apprentissage de l’écriture et des fondamentaux. Basée sur l’IA et la recherche, cette application inclusive et innovante, permet à chaque élève de progresser.", "siren": "824814982"}, {"name": "BOTdesign", "description": "BOTdesign, entreprise ISO13485, a lancé son dispositif médical HEKO de gestion des parcours de e-santé en 2020 (150K+ utilisateurs et 20+ clients nationaux). BOTdesign propose une technologie disruptive de GenAI grâce à ORIGA, 1ère plateforme web européenne d’augmentation des données artificielles pour les laboratoires pharmaceutiques, biotechs et les industriels du dispositif médical.", "siren": "828737676"}, {"name": "Healshape", "description": "Healshape est une entreprise de médecine régénérative dont la vocation est de réparer l’humain en lui donnant la possibilité de se régénérer grâce à ses propres cellules. Nous développons des produits naturels et résorbables pour la reconstruction.", "siren": "881023683"}, {"name": "Anod", "description": "Anod a développé le premier vélo hybride qui introduit un nouveau paradigme : la gestion de l’énergie intelligente lors de l’utilisation du vélo, qui repose sur l’optimisation des phases de consommation du vélo en alternance avec des phases de récupération d’énergie. Ces technologies combinant supercondensateurs, batterie lithium-ion et moteur à récupération d’énergie permettent l’utilisation d’une batterie amovible utilisant 6x moins de lithium que les standards du marché. \nCette batterie 5x plus légère et compacte se recharge en USB-C, résolvant pour l’utilisateur urbain et périurbain le problème des batteries lourdes, encombrantes et complexes à charger. Son approche repose sur l’innovation et des solutions respectueuses de l’environnement, fabriquées localement, faisant de lui un acteur clé du vélo moderne.", "siren": "921454450"}, {"name": "Etablissement Jules N'Haux et fils", "description": "Fondé dans les Pyrénées- Atlantiques, N’Haux est un acteur majeur dans le secteur des semences et des céréales, spécialisé dans la conception et la fabrication d’équipements industriels et reconnu mondialement pour leurs effeuilleuses à maïs. Grâce à leur savoir-faire, l’entreprise a étendu son offre à la construction d’usines de recyclage clés en main.", "siren": "096180328"}, {"name": "ONIMA (YEASTY)", "description": "Start-up deeptech biotech-nologique et industrielle fondée en 2021, Onima revalorise la levure de brasserie pour générer un super-ingrédient naturellement riche en protéines et nutriments essentiels. En éliminant l’amertume de ce co-produit grâce à une technologie innovante et brevetée, Onima permet l’exploitation de son potentiel hautement nutritif et gustatif pour de nombreuses applications agroalimentaires, dans les productions du quotidien mais aussi en nutrition sportive ou encore en petfood.", "siren": "908759053"}, {"name": "4D VIEW SOLUTIONS", "description": "Depuis 2007, 4DViews conçoit des systèmes de capture volumétriques dynamiques: une innovation capable de filmer les personnes comme des séquences d’objets virtuels, utilisables dans n’importe quel environnement virtuel. \nSon produit phare le HOLOSYS+ est disponible dans le monde entier pour les studios professionnels. En tant que système de capture volumétrique industrialisé et standardisé, il est compatible avec toutes les principales technologies AR, VR et MR.", "siren": "500704879"}, {"name": "ULTIMETAS", "description": "Aujourd’hui, l’évolution des communications nécessite des antennes de plus en plus performantes, compactes et configurables dans des applications où la sécurité et la sureté sont toujours plus critiques. \nFace à des solutions complexes et coûteuses à mettre en oeuvre et opérer, ULTIMETAS exploite trois ruptures technologiques brevetées et ambitionne d’être le premier acteur européen et international à réaliser une antenne à métasurface digitale, très large bande et à balayage spatial reconfigurable optiquement.", "siren": "843480963"}, {"name": "Starkage Therapeutics", "description": "Starkage Therapeutics est une société de biotechnologie spécialisée dans le développement de thérapies ciblées capable d’éliminer les cellules sénescentes dans les maladies liées à l’âge. Nos programmes de recherche se concentrent sur le cancer, les fibroses ou les maladies auto-immunes.", "siren": "841065923"}, {"name": "DIIMOTION", "description": "Diimotion est une Start-up développant le PiiX, une technologie d’injection directe des produits phytosanitaires pour la pulvérisation agricole et viticole. Le PiiX permet de réguler les doses et/ou les produits en quasi temps réel pour des économies de 30 à 80 % de produits (modulation, application localisée).", "siren": "817433220"}, {"name": "LyophiTech", "description": "Le projet LYOAC a pour objectif de concevoir un lyophilisateur dynamique continu d’une capacité de 100 L à destination de l’industrie agroalimentaire. Cet appareil pourra ensuite être décliné dans une gamme de 100 à 2 000L.\nCe nouveau procédé industriel permettra de réduire efficacement les coûts opératoires et les investissements chez les industriels. En effet la lyophilisation dynamique permet une réduction d’utilisation d’énergie électrique de 20 à 40% par rapport à un procédé statique.", "siren": "834116162"}, {"name": "IXSANE", "description": "Ixsane est une société d’études et d’ingénieurs conseils dans le domaine de l’Ingénierie Urbaine et Environnementale impliquée depuis sa création dans des projets d’innovation pour contribuer à l’avancée des connaissances et à la mise au point de solutions pour répondre aux enjeux environnementaux et sociaux de notre temps.", "siren": "509580973"}, {"name": "KLEARIA", "description": "KLEARIA intervient dans le domaine de la microfluidique. L’activité de l’entreprise comporte trois composantes : la vente d’études scientifiques et techniques, la vente d’instruments, la vente de consommables. Ces dispositifs sont transportables, autonomes, en temps réel et simples à mettre en oeuvre. Ils permettent de réduire les coûts de traitement en améliorant la sécurité sanitaire et environnementale.", "siren": "789701653"}, {"name": "FLUDIA", "description": "Fludia conçoit des technologies numériques, Smart Sensors et Smart Data, dédiées à la mesure et l’analyse des consommations énergétiques, ciblées sur les petits et moyens bâtiments. Elles permettent de comprendre et réduire les consommations grâce à la collecte de données précises et leur analyse via des modules algorithmiques spécialisés.", "siren": "442854147"}, {"name": "PERCIPIO ROBOTICS", "description": "Percipio Robotics, une deep tech fondée par des chercheurs en 2011 qui construit les outils robotiques nécessaires à la réalisation de machines industrielles de micro-assemblage. Ces machines de haute technologie construiront demain les produits ultra-miniaturisés qui feront partie de notre quotidien (électronique, médical, aéronautique et spatial, énergie...).", "siren": "529990301"}, {"name": "FORSETI SAS", "description": "Notre ambition est de libérer le droit en rendant accessibles des millions de jugements.\nEn Europe, seulement 1% des décisions de justice sont accessibles au citoyen. L’obligation européenne d’anonymisation, renforcée par la RGPD, freine l’ouverture du droit.\nDoctrine a donc développé une solution d’anonymisation utilisant le machine learning. Nos algorithmes apprennent les structures du langage pour anonymiser de manière automatique.\nDoctrine offre aussi un logiciel de recherche multilingue et multi système juridique pour permettre à chacun d’interpréter le droit des autres pays comme du sien.", "siren": "820867877"}, {"name": "Infolegale", "description": "Infolegale est spécialisée dans le renseignement BtoB et plus particulièrement dans la production et la diffusion d’informations légales, capitalistiques et financières sur les entreprises et leurs dirigeants. En 10 ans, Infolegale a su s’imposer comme la référence agile et innovante à forte valeur ajoutée du marché.", "siren": "503207896"}, {"name": "UPTIME", "description": "UPTIME développe une technologie englobante de maintenance, qui permet un nouveau mode opératoire préventif puis prédictif. Les interventions de techniciens sont optimisées pour maximiser l’exploitation de leur expertise grâce à la technologie, tandis que le modèle contractuel bascule des visites d’inspection à un engagement sur la disponibilité de l’appareil.", "siren": "822006839"}, {"name": "MagIA Diagnostics SAS", "description": "Sur la base d’une technologie micro-magnétique issue du CNRS et de l’université Grenoble-INP, MagIA Diagnostics développe un dispositif d’analyse qui réalise des ELISA pratiqués en laboratoire en une dizaine d’étapes sur un dispositif portable en une seule étape de 15 minutes.", "siren": "831351796"}, {"name": "MultiX S.A.", "description": "MultiX fournit aux fabricants de scanners de bagages des détecteurs spectrométriques de rayons-x qui permettent l’identification des explosifs lors du contrôle des bagages, la limitation des coûts opérationnels et l’amélioration du confort des passagers, en leur permettant de conserver les liquides, ordinateurs portables et tablettes pendant leurs voyages aériens.", "siren": "527665913"}, {"name": "gulplug", "description": "GULPLUG s’est constituée en 2014 autour de l’idée d’une nouvelle façon de connecter les machines électriques : simple, rapide et sûre, à l’univers des données (Internet of Things) autant qu’à l’énergie (réseau électrique 230V de manière automatique), à partir de technologies issues de Schneider Electric", "siren": "802352187"}, {"name": "SEAir", "description": "SEAir conçoit et fabrique des foils, ainsi que l’équipement nécessaire pour les piloter. L’offre consiste à modifier des bateaux déjà existants par l’adjonction de systèmes brevetés SEAir. L’enjeu est de fournir des « kit foil » à intégrer directement sur les chaînes de montage des nouveaux bateaux.", "siren": "819778838"}, {"name": "STIRAL", "description": "STIRAL fabrique des échangeurs de chaleur à micro-canaux (1/10 de millimètre) en acier inoxydable. Ces échangeurs baptisés COMHEX sont 5 fois plus petits et 4 fois plus légers que les produits actuels. Ils permettent de limiter les quantités de liquides frigorigènes présents dans les condenseurs des pompes à chaleur", "siren": "521142323"}, {"name": "Tictactrip", "description": "Créée en 2016, Tictactrip est une start-up technologique, proposant un concept nouveau de MaaS (Mobility as a Service) lié aux usages innovants de mobilité des personnes aux niveaux local, régional, national et européen.", "siren": "822961652"}, {"name": "ECO-ADAPT", "description": "Eco-Adapt développe des solutions hardware et software de monitoring énergétique innovantes pour les marchés tertiaires et industriels.", "siren": "539339432"}, {"name": "SAS INVERS", "description": "L’objectif d’INFARM est de développer un atelier innovant de production d’insectes à la ferme. INFARM permettra de produire de manière durable, économique et socialement responsable des insectes à destination des marchés locaux d’alimentation animale, et de fournir un substitut durable aux farines importées de poissons et de soja. INFARM intègrera l’expérience des agriculteurs actuellement en test de production, pour permettre de produire plusieurs tonnes d’insectes/mois tout en respectant la capacité maximale d’investissement, de rentabilité économique, de temps disponible pour l’agriculteur et la durabilité (circuits courts, autosuffisance énergétique, transition agroécologique). INFARM pourra être dupliqué rapidement vers d’autres régions françaises et européennes.", "siren": "837934462"}, {"name": "AlgoSource", "description": "Premier producteur de Spiruline en Europe en 1995, la SAS AlgoSource est spécialisée dans la valorisation des microalgues.", "siren": "507757128"}, {"name": "Lactips", "description": "Développer un matériau fonctionnalisé et comestible innovant", "siren": "801500018"}, {"name": "E-ODYN", "description": "E-Odyn développe un procédé innovant pour mesurer les dynamiques océaniques (vent, vagues et courants) en analysant les trajectoires de navires en temps réel et sur toutes les mers du globe. Ces paramètres nécessaires à la compréhension du climat, au sauvetage en mer et à la prévention des pollutions marines sont mesurés en réutilisant une donnée déjà disponible", "siren": "814984860"}, {"name": "IEXEC", "description": "La société iExec a été fondée en 2016 à Lyon. iExec fournit une place de marché décentralisée fondée sur la technologie blockchain. La société développe des briques technologiques permettant aux développeurs de mettre en œuvre un cloud computing décentralisé facilitant l’accès à de grandes capacités de calcul.\niExec développe des solutions de Cloud décentralisé en lien avec la blockchain publique Ethereum. Elle cherche aujourd’hui à diversifier ses activités pour répondre aux besoins des entreprises en matière de blockchain.", "siren": "823070925"}, {"name": "NEXTFLOW Software", "description": "NEXTFLOW Software est spécialisée dans l’édition de logiciels de simulation numérique innovants dans le domaine de la mécanique des fluides et de l’hydrodynamique. Elle est actuellement dans une phase de développement d’un logiciel innovant. Son objectif est d’offrir à ses clients des logiciels innovants intégrant des solveurs différenciants.", "siren": "812220788"}, {"name": "Payfit", "description": "PayFit est une société innovante qui a développé une solution SaaS de gestion automatisée de la paie reposant sur un langage propriétaire, le JetLang. Il permet de prendre en compte la totalité des dispositions prévues par la loi et peut évoluer avec la réglementation", "siren": "813487899"}, {"name": "Tinyclues", "description": "Tinyclues est le leader français de l’IA pour le Marketing-CRM Automation, un nouveau segment de marché en amont et pilotage des outils de gestion de campagnes traditionnels.", "siren": "522265602"}, {"name": "I.T.Control Expert", "description": null, "siren": "530890599"}, {"name": "Incepto Medical", "description": "Au cœur de la rupture technologique de l’intelligence artificielle, Incepto construit la radiologie du futur, plus fiable, plus rapide, pour plus de patients. Incepto Medical offre un environnement collaboratif pour inventer, développer et diffuser des applications révolutionnaires de diagnostic et de traitement des pathologies.", "siren": "834926131"}, {"name": "MEDIMPRINT", "description": "MEDIMPRINT développe et commercialise des dispositifs médicaux innovants dit dispositifs d’empreintes tissulaires. Reposant sur un nouveau concept, l’empreinte tissulaire cérébrale, ces dispositifs sont moins lésionnels pour le tissu que les outils de biopsie. Ils permettent ainsi d’accéder à des régions aujourd’hui inexplorées afin d’identifier les cibles thérapeutiques dans les tumeurs cérébrales.", "siren": "819010539"}, {"name": "CT2MC", "description": "Société indépendante d’ingénierie, CT2MC a pour vocation, depuis sa création en 2012, le développement et la fabrication de produits industriels alliant l’innovation, les matériaux composites, l’automatisme et la robotique. Elle a mis au point sa propre gamme de drones aquatiques pour la réalisation de prélèvements et d’inspections environnementales.", "siren": "841218118"}, {"name": "AUTONOMOUS CLEAN WATER APPLIANCE  ROBOTICS", "description": "La société développe des robots autonomes qui parcourent et analysent les réseaux d’eau en opération à contrecourant. Elle offre aux exploitants une cartographie et une analyse du réseau : ces données permettent de prévenir les fuites et optimiser le fonctionnement du réseau.", "siren": "539201244"}, {"name": "INALVE", "description": "La société de biotechnologie, Inalve, industrialise un système de production de microalgues à faible empreinte environnementale et développe des ingrédients sains et renouvelables pour l’alimentation animale.", "siren": "830590659"}, {"name": "DIOTASOFT S.A.S.", "description": "La société DIOTA est un éditeur de solutions hautement technologiques destinées à l’Industrie 4.0. Ses solutions orientées métier permettent, aux grands acteurs auxquels elles se destinent, d’augmenter sensiblement leur compétitivité par l’optimisation des processus industriels de prototypage, de production, de contrôle et de maintenance.", "siren": "511778532"}, {"name": "SKIPPER NDT", "description": "Depuis 2016, Skipper NDT développe des systèmes liés à la Sécurité des pipelines de pétrole et de gaz. Suite à la subvention du concours i-Lab 2017, Skipper NDT a réussi à développer un système d’inspection des canalisations basé sur un principe magnétique passif, sans injection de courant sur la paroi du pipeline.\nCette technologie brevetée, a donné naissance à un prototype qui est actuellement commercialisé en France et à l’étranger, notamment auprès de Total, Teréga, Air Liquide, Trapil et d’autres majors du secteur de l’énergie. Les performances de ce système sont encourageantes avec une probabilité de détection de défauts (PDD) de l’ordre de 50%, alors que celle des systèmes concurrents ne dépasse pas le seuil des 10%.", "siren": "822080206"}, {"name": "UTTI", "description": "UTTI (Union Textile de Tourcoing Industries), est depuis 1959, une teinturerie, qui propose des produits teints à la demande pour le secteur du textile habillement et ameublement. L’entreprise a pour mission de dynamiser la création, en proposant une gamme de fils variée, pouvant être teint dans n’importe quel coloris.", "siren": "885980144"}, {"name": "Foodvisor", "description": "Foodvisor offre une solution d’intelligence artificielle unique au monde permettant d’analyser instantanément le contenu d’une assiette à partir d’une seule photographie.", "siren": "812516847"}, {"name": "Mipsology", "description": "Mipsology conçoit des solutions de calcul pour les réseaux de neurones (Deep Learning). Zebra, permet des calculs à très haute vitesse applicable à l’intelligence artificielle notamment pour l’image et la vidéo.", "siren": "813450731"}, {"name": "VATES", "description": "Vates édite des solutions de virtualisation open-sources clé en main et commercialise des offres de services autour de ces solutions", "siren": "752155259"}, {"name": "Atawey", "description": "Atawey est spécialisée dans la conception et la production de stations de production et de distribution d’hydrogène vert, grâce à une technologie brevetée d’électrolyse de l’eau à haute performance environnementale. D’ici la fin de l’année 2020, 25 stations Atawey seront déployées en France.", "siren": "753970490"}, {"name": "GEOCORAIL", "description": "GEOCORAIL SAS travaille sur la durabilité des ouvrages côtiers. Après 5 ans de R&D, la société commercialise un procédé électrochimique permettant la création de roches sédimentaires en milieu marin, décliné en diverses applications.\nEn 2019, GEOCORAIL a étendu son activité aux travaux sous-marins, en internalisant des compétences de plongeurs professionnels.", "siren": "539529669"}, {"name": "CAMPOSPHERE", "description": "CampoSPHERE est le promoteur du réemploi des bâtiments modulaires. La société propose des services d’intermédiation pour favoriser le démontage, le transport, la rénovation et le remontage d’installations temporaires. Elle accompagne les propriétaires dans la gestion de leur parc de bâtiments démontables et les acheteurs responsables dans leur acquisition de bâtiments reconditionnés.", "siren": "522659986"}, {"name": "ADAGOS", "description": "ADAGOS développe une technologie de rupture dans le domaine de l’intelligence artificielle. Basée sur la théorie du gradient topologique, elle permet la construction automatique de réseaux de neurones parcimonieux et réduit de plusieurs ordres de grandeurs les ressources (y compris énergétiques) nécessaires pour mettre en œuvre ces méthodes d’apprentissage automatique.", "siren": "537679524"}, {"name": "Earthcube", "description": "Earthcube propose un service de surveillance d’activités de sites sensibles et de renseignement économique. Ses clients sont des acteurs privés ou gouvernementaux ayant besoin de suivre l’activité sur des sites complexes d’accès (très étendus ou très éloignés) et à forts enjeux pour la sécurité des personnes et de l’Environnement.", "siren": "818503146"}, {"name": "Lili.ai", "description": "Lili.ai met en place un système basé sur les récents progrès en traitement automatique des langues pour extraire et analyser des grandes masses de données textuelles hétérogènes (compte rendu de réunion, emails, analyse de risques, etc.) pour sécuriser les grands projets. Nos clients sont des leaders de l’énergie et de la construction.\n9 projets sur 10 de plus de 10M€ sont contestés d’après le Chaos report. Ainsi commence l’exercice très chronophage de reconstitution archéologique des responsabilités de chaque partie dans la création du retard et donc le paiement des pénalités attachés.", "siren": "820982627"}, {"name": "QC WARE FRANCE SAS", "description": "QC Ware France a pour mission de donner aux entreprises les moyens de résoudre leurs problèmes les plus complexes en développant une plate- forme en tant que service (PaaS) pour l’informatique quantique et en concevant une suite d’applications quantiques puissantes. En outre, la société propose des services de conseil aux clients pour les aider à découvrir les problèmes pertinents pouvant être résolus à l’aide d’algorithmes quantiques.", "siren": "854036357"}, {"name": "SANCARE", "description": "Sancare est un éditeur de logiciels spécialisé dans la conception d’Intelligences Artificielles dédiées au monde hospitalier. Sancare est positionnée à ce stade sur le codage automatique des actes hospitaliers : son IA de codage automatisé est actuellement signée ou en signature dans plus de 30 centres hospitaliers français.", "siren": "822501078"}, {"name": "COLLIN", "description": "COLLIN a une activité focalisée sur des travaux de R&D dédiée à la sphère ORL en tant que fabricant (Système RobOtol®, Système de navigation chirurgicale DigiPointeur®, Rocher d’entraînement TEMP’OS®). Elle a également une activité de distribution historique avec des marques mondialement connues : LEICA, KARL STORZ, ELLMAN, MECTRON, MEDIPLAST, BONALIVE.", "siren": "428955520"}, {"name": "SIM&CURE", "description": "La startup Sim&Cure a pour mission d’améliorer la prise en charge du patient atteint d‘un anévrisme cérébral en personnalisant le planning thérapeutique. Pour atteindre cet objectif, notre logiciel Sim&Size réalise des simulations pré-opératoires de la pose des dispositifs médicaux implantables (DMI).", "siren": "803695402"}, {"name": "INTEGRATIVE PHENOMICS", "description": "Grâce à des modèles scientifiques de pointe qui combinent microbiote intestinal, biologie, style de vie et environnement et à partir de la compréhension de la réponse individuelle aux aliments, Intégrative Phenomics a pour objectif, d’apporter des solutions de nutrition personnalisée pour lutter contre les maladies chroniques et encourager une alimentation durable.", "siren": "853913846"}, {"name": "GITGUARDIAN", "description": "GitGuardian aide les développeurs informatiques à sécuriser leur code source en détectant automatiquement les Secrets qu’ils y oublient. Les Secrets peuvent être des clés API, des codes de bases de données, des certificats etc. qui donnent accès à différents systèmes informatiques.", "siren": "833611742"}, {"name": "Harfanglab", "description": "Face à des menaces informatiques de plus en plus sophistiquées et ciblées, les défenses traditionnelles (antivirus, pare-feu) ne sont plus suffisantes. Il est indispensable de disposer désormais d'un outil EDR\n– Endpoint Detection & Response – permettant de détecter les comportements suspects sur les terminaux informatiques et les signaux précurseurs d’une attaque ciblée. HarfangLab est la seule solution EDR française qui garantit la souveraineté des données de ses utilisateurs.", "siren": "839045697"}, {"name": "REDBERRY SAS", "description": "Redberry développe et commercialise des solutions de contrôles microbiologiques rapides, sans phase de culture, simples et quantitatifs à destination des industriels.\nSes solutions applicables sur le terrain permettent une meilleure réactivité en cas de contamination pour les industries pharmaceutiques, agro-alimentaires, cosmétiques et les professionnels des eaux. Des développements sont en cours pour le diagnostic médical", "siren": "829480318"}, {"name": "Hevatech", "description": "Hevatech est une PME spécialisée dans le développement et la commercialisation de solutions de valorisation de chaleurs fatales. Son procédé TURBOSOL convertit les chaleurs perdues en électricité.\nCe procédé propriétaire est robuste, simple à mettre en œuvre, respectueux de l’environnement et présente un temps de retour sur investissement réduit", "siren": "523040020"}, {"name": "AKEO PLUS", "description": "AKEO PLUS : spécialisée dans l’accompagnement de bout en bout des entreprises manufacturières dans leurs enjeux industriels sur 3 piliers : DIGITAL (IoT, Cloud, Edge computing, IA), AUTOMATION (Automatisme, Robotique, maintenance), SAFETY (biens et personnes, Cybersécurité), notamment dans l’aéronautique, l’aérospatiale, la manufacture, la mobilité, l’énergie, santé et pharmaceutique, et l’alimentation.", "siren": "491538716"}, {"name": "ISYBOT", "description": "La société ISYBOT, créée en 2016, conçoit, fabrique industriellement et commercialise des cobots sous la forme de bras robotiques interactifs, flexibles, sans cage, destinés à évoluer au contact des hommes, dans un espace de travail collaboratif et en toute sécurité pour tout type de procédé.", "siren": "823521505"}, {"name": "Scortex", "description": "Le système Scortex automatise le contrôle visuel sur ligne de production. Grâce aux technologies d’apprentissage profond, les inspections les plus complexes sont rendues possibles. Les stations d’inspection Scortex produisent et mettent à disposition la donnée qualité en temps réel, ce qui permet aux industriels d’optimiser leur outil de production.", "siren": "820535102"}, {"name": "Crocosgodigital", "description": "CrocosgoDigital développe des ateliers ludo-éducatifs basés sur la programmation de robots et de drones.", "siren": "840016208"}, {"name": "FITTINGBOX", "description": "Fondée en Aout 2006, FittingBox est le leader Mondial des solutions de réalité augmentée et de la digitalisation pour l’industrie Optique. Elle est la société française qui a inventé le premier miroir virtuel permettant d’essayer des lunettes. FittingBox crée et gère également la plus grande base de données au monde de photos et de modèles 3D de montures.", "siren": "491452991"}, {"name": "MyMedicalAssistant", "description": "iAudiogram,  plateforme  de  télé-audiométrie,  offre  aux  O.R.L.  et Médecins Généralistes une solution permettant de déléguer leurs bilans audiométriques à des Experts Audiométristes.  Cette  réalisation  s’appuie sur l’Audiopod, 1er  audiomètre informatisé développé spécifiquement pour la télémédecine.", "siren": "883064982"}, {"name": "QUCIT SAS", "description": "Qucit (Quantified Cities) est une entreprise française spécialisée dans l’édition de solutions logicielles pour une gestion intelligente des problématiques urbaines. Qucit développe une plateforme d’intelligence artificielle contextuelle permettant de modéliser les comportements et les perceptions humaines. Sa mission est de contribuer à rendre les villes plus agréables, efficaces et durables.", "siren": "802524512"}, {"name": "Smartesting Solutions & Services", "description": "Smartesting développe des solutions cognitives d’automatisation de test qui améliorent l’efficience des équipes QA des Systèmes d’Information. Nos produits mêlent représentations visuelles et technologies d’IA pour faciliter la conception en mode agile des tests les plus pertinents et accélérer leur automatisation.", "siren": "809068943"}, {"name": "SpotLight", "description": "SpotLight aide les acteurs du sous-sol à détecter les changements avec une solution de surveillance sismique non-invasive, peu coûteuse, fiable, écologique et permanente tout en donnant une information en temps réel pour alerter sur les changements et diminuer les risques associés.", "siren": "824695423"}, {"name": "Acticor Biotech", "description": "Spin-Off de l’Inserm, ACTICOR BIOTECH est une société biopharmaceutique créée fin 2013 développant un nouveau médicament, pour le traitement de la phase aiguë d'un AVC ischémique, nommé glenzocimab. D’origine biotechnologique, il s’agit d’un fragment d’anticorps monoclonal, dirigé contre une nouvelle cible thérapeutique d'intérêt majeur : la glycoprotéine VI plaquettaire (GPVI).", "siren": "798483285"}, {"name": "E-Scopics", "description": "E-Scopics développe des systèmes d’échographie ultraportable fonctionnant sur App(s) pour les marchés de spécialités cliniques. La société termine le développement de son premier produit utilisant un lien filaire entre la sonde et son hôte, et dédié à l’évaluation des hépatopathies chroniques. L’endocrinologie et de la gastroentérologie sont ses premiers marchés.", "siren": "841467293"}, {"name": "ORIXHA", "description": "L’ambition du projet est d’améliorer la survie et diminuer les séquelles de l’arrêt cardiaque en commercialisant, dès 2024, la solution Vent2Cool d’hypothermie ultra-rapide par ventilation liquidienne. Ce dispositif médical aura un double impact :\n- Augmenter de 30-35% à plus de 50% le taux de survie des patients réanimés après un Arrêt Cardiaque Extra-Hospitalier, ce qui permettra de sauver plus de 5,000 vies par an en Europe ;\n- Améliorer l’efficacité et potentialiser les efforts de la chaine de survie mobilisée au niveau du SAMU et des Urgences pour la prise en charge de l’Arrêt Cardiaque Extra-Hospitalier.", "siren": "838982858"}, {"name": "ADV PROPULSE", "description": "ADV TECH développe et commercialise une technologie de rotor innovante, appliquée aux domaines des énergies renouvelables et de la propulsion à haut rendement", "siren": "884470600"}, {"name": "ECOV", "description": "Ecov développe, déploie et exploite des lignes de covoiturage à haut niveau de service. Ces lignes transforment la voiture en transport collectif dans les territoires peu denses. Elles permettent aux passagers de prendre un covoiturage comme on prend un bus à haute fréquence", "siren": "808203467"}, {"name": "GREENMOT", "description": "La société GREENMOT a deux activités principales :\n• La prestation d’essai avec exploitation de cellules d’essai climatiques et bancs d’organes pour tests de performances énergétiques ;\n• La construction et la commercialisation de moyens d’essais tels que des bancs d’essai climatiques pour véhicules, des machines de tests et des capteurs spéciaux.", "siren": "527591499"}, {"name": "Stockage Plus", "description": "URBANHUB est un opérateur de logistique urbaine décarbonée, pour la métropole du Grand Paris. Deux lignes d’activité :\n• e-commerce : logistique pour un site e-commerce, jusqu’à la livraison finale et la gestion des retours (France et étranger) ;\n• cross-docking (réception, tri, préparation gestion transport) des clients : marques et distributeurs.", "siren": "817446248"}, {"name": "NEOVYA Mobilité", "description": "La société NEOVYA Mobilité by Technology édite des solutions à destination des gestionnaires de réseaux de transports et de bureaux d’études. Elle développe HUBSIM, une application web intégrant des outils d’analyse de données et de modélisation issus de la recherche pour permettre à ses clients de concevoir les projets de mobilité du futur", "siren": "852789155"}, {"name": "Sublime Energie", "description": "L’ingénierie, la recherche, l’innovation, le développement et l’exploitation de technologies pour développer, produire et commercialiser toutes technologies, études techniques ou commerciales, tous équipements et tous services destinés aux traitements des gaz, à leurs applications ou à leurs utilisations et plus spécialement le biogaz, le biométhane et le bioCO2", "siren": "852793223"}, {"name": "Data Science Experts SES", "description": "Avec le projet AIperion, DSE vise à mettre en œuvre une série d’instruments pour assister les compagnies  d’assurance  de  biens  dans  le  processus de gestion des sinistres liés aux dommages causés par des événements météorologiques extrêmes ou des catastrophes naturelles.", "siren": "881104699"}, {"name": "INGESPACE", "description": "Conception, réalisation et maintien en condition opérationnelle de système numériques ou radiofréquences complexes pour le spatial et la défense", "siren": "488251794"}, {"name": "BrightLoop Converters", "description": "BrightLoop Converters est un acteur français spécialisé dans la conception, l’industrialisation et la fabrication de convertisseurs d’énergie (AC et DC) de quelques watts (W) à plusieurs kilowatts (kW), répondant à des besoins spécifiques (contraintes électriques, de volume, thermiques, efficacité énergétique, etc.) et offrant des performances et des niveaux de fiabilité élevés.", "siren": "805140712"}, {"name": "GEN-HY", "description": "GEN-HY conçoit, fabrique et commercialise des solutions énergétiques intégrant des technologies exclusives, capables d’exploiter l’énergie de l’hydrogène en toute fiabilité, sécurité et performance. GEN-HY propose des solutions de production d’hydrogène de mobilité, de stockage, d’approvisionnement énergétique et de nettoyage de moteurs grandes capacité.", "siren": "850072356"}, {"name": "MillionRoads", "description": "MILLIONROADS conçoit, développe et commercialise des solutions numériques capables de collecter, d’analyser et de restituer automatiquement des parcours scolaires et professionnels réels. MILLIONROADS propose ainsi aux parties prenantes de l’orientation : des informations constamment actualisées sur les filières, formations, métiers et compétences et l’exploration des évolutions scolaires ou professionnelles", "siren": "817446800"}, {"name": "SESTERCE", "description": "SESTERCE développe et commercialise du matériel de minage de crypto- monnaies sur blockchain. Basé sur des cartes GPU ou des cartes ASIC, ces serveurs sont capables de s’adapter à de nombreuses blockchains. Cet avantage scientifique a permis à l’entreprise de se différencier de la concurrence et devenir acteur incontournable su secteur.", "siren": "842753436"}, {"name": "THE AI INSTITUTE", "description": "The_AI_Institute (TAI) améliore enseignement, formation professionnelle et accès à la connaissance, grâce à l’IA et Traitement Automatisé du Langage Naturel (NLP). TAI propose Bob, Assistant Virtuel NLP accompagnant les apprenants ou pour accéder instantanément 24/7 à une connaissance. TAI organise également une formation IA, laboratoire innovant du téléprésentiel.", "siren": "838225316"}, {"name": "Corner", "description": "Corner est une start-up qui réunit dans une même équipe des experts de la construction bois et des technologies numériques. Corner conçoit une méthode constructive bas carbone et 100% hors-site et développe actuellement la plateforme numérique pour pouvoir implémenter cette méthode universellement avec des écosystèmes locaux.", "siren": "843973363"}, {"name": "WOODOO", "description": "WOODOO est spécialisée dans la fabrication d’un nouveau matériau composite bois aux propriétés optiques et physiques pionnières pour l’industrie de la mobilité et du bâtiment", "siren": "822373551"}, {"name": "Sêmeia", "description": "Sêmeia propose des solutions Saas de télésurveillance des patients appuyés sur l’intelligence artificielle afin d’anticiper les évènements indésirables dans les parcours des patients.\nSêmeia bénéficie d’un remboursement de l’Assurance Maladie et commercialise les produits NephroWise (pour les maladies rénales), OncoWise (pour les cancers), ImmunoWise (pour les maladies inflammatoires) et MentalWise (pour les maladies mentales).", "siren": "829055854"}, {"name": "C4Diagnostics", "description": "C4Diagnostics est une biotech spécialisée dans le développement de tests de diagnostic pour les maladies infectieuses humaines. Pour améliorer leur prise en charge et lutter contre l’antibiorésistance, C4Diagnostics offre des tests innovants qui concilient rapidité et fiabilité. Les technologies mises en oeuvre sont protégées par huit familles de brevets.", "siren": "829680503"}, {"name": "Advanced Aerodynamic Vessels", "description": "A2V conçoit et construit des navires à sustentation aérodynamique caractérisés par une efficacité énergétique exceptionnelle. Une géométrie innovante permet à ces navires de bénéficier de motorisations zéro émission en utilisation tout en gardant un rayon d’action à grande vitesse utile.", "siren": "793570243"}, {"name": "SESTERCE France LABS", "description": "SESTERCE développe et commercialise du matériel de minage de crypto-monnaies sur blockchain. Basé sur des cartes GPU ou des cartes ASIC, ces serveurs sont capables de s’adapter à de nombreuses blockchains. Cet avantage scientifique a permis à l’entreprise de se différencier de la concurrence et devenir acteur incontournable su secteur.", "siren": "842753436"}, {"name": "Apix analytics", "description": "La mission d’APIX ANALYTICS est de développer des chromatographes gazeux miniaturisés basés sur l’intégration sur silicium de la chaîne d’analyse : échantillonnage, injection des gaz, séparation de mélanges complexes pour améliorer la spécification puis la détection, l’identification et la quantification de chaque composé du mélange.", "siren": "803133933"}, {"name": "farm3", "description": "Farm3 a pour mission de diminuer l'empreinte carbone de la production agricole et forestière. Farm3 fournit des chambres de culture modulaire à haut rendement, robotisées et ultraBIOponiques, ainsi qu'une bibliothèque de logiciels, destinée aux producteurs, pépiniéristes et aux instituts de recherche.", "siren": "849123401"}, {"name": "Finx", "description": "FinX veut révolutionner le monde nautique en développant des moteurs à membrane ondulante inspirée de la nage des poissons. Eco-conçu, écologique et performant, ce propulseur représente l’avenir de la mobilité. Visant aujourd’hui le marché des bateaux de plaisance, FinX souhaite généraliser sa technologie à des moteurs jusqu’à 1000 CV.", "siren": "851734236"}, {"name": "ME Concept SAS", "description": "ME Concept est un bureau d’études et de R&D qui conçoit et développe des solutions techniques innovantes de suspensions pour les cycles. Son expertise repose sur la modélisation et l’étude du comportement statique et dynamique des architectures de cycles.", "siren": "811109834"}, {"name": "MovieChainer", "description": "La maison-mère de MovieChainer intervient à plusieurs étapes de la chaîne de valeur du film (financement, production, distribution, exploitation). MovieChainer est un outil de gestion des droits initialement développé pour les besoins internes de la société-mère avant d’être commercialisée comme un SaaS depuis 2016.", "siren": "790309835"}, {"name": "SYLVABOT", "description": "NeoFarm conçoit et opère des fermes maraîchères clés en main pour les acteurs du territoire, produisant des légumes bio et locaux. La solution développée est un maillage de fermes associant les bénéfices de l’agroécologie et ceux de la technologie, installées sur de petites surfaces en périphérie des villes.\nL’agriculture fait face à des enjeux historiques, liés au changement climatique et à la souveraineté alimentaire, qui nécessitent de revoir profondément notre modèle de production. NeoFarm saisit l’opportunité de faire émerger un modèle de production maraîchère à grande échelle, à la fois écologique, rentable économiquement et implantée localement. Une micro-ferme NeoFarm permettra de nourrir quotidiennement plus de 1 000 personnes.", "siren": "834754384"}, {"name": "Synapse Développement", "description": "Synapse Développement édite des logiciels amenant le meilleur de l’ingénierie des langues aux organisations, pour aider l’humain à transmettre ses connaissances.", "siren": "393498324"}, {"name": "Umiami", "description": "Chez Umiami, nous développons des alternatives végétales à la viande à l’aide d’une technologie propriétaire de texturation, l’umisation. Nous parvenons à imiter des textures fibreuses de poissons et viandes que la technologie d’extrusion ne permet pas. Nous distribuons nos produits en marque blanche aux acteurs du marché de la simili-viande.", "siren": "883899478"}, {"name": "Vetophage", "description": "Dans le cadre de la lutte mondiale contre l’antibiorésistance et dans un contexte « One health », VETOPHAGE développe des outils de diagnostic et de traitement des bactéries pathogènes grâce aux technologies des phages.", "siren": "825352024"}, {"name": "Wise-integration", "description": "WISE-INTEGRATION développe des technologies d’électronique de puissance à base de GaN en rupture permettant la réduction de la taille et des pertes énergétiques des alimentations d’appareils électroniques par 3.\nStart-up deeptech française, WISE-INTEGRATION est issue d’un essaimage du CEA et cumule près de 8 ans de R&D, à l’origine de 5 brevets déposés.", "siren": "881644900"}, {"name": "World Game", "description": "World Game transforme des problèmes du monde réel en jeux mobile pour solliciter la capacité de l’intelligence collective à mieux les résoudre. Nous créons ainsi des solutions pour engager de larges communautés autour de problèmes définis, analyser de larges quantités de données, et optimiser des systèmes au sein de simulations.", "siren": "892207242"}, {"name": "Yole Developpement", "description": "Yole Développement publie des analyses marketing, techniques et industrielles, dans le domaine des micro- et nanotechnologies. Reconnu dans le monde entier, Yole travaille avec les acteurs clés de l’industrie afin de les aider à mieux comprendre les enjeux de leurs marchés et à développer leurs activités.", "siren": "421162785"}, {"name": "Zaion", "description": "Zaion propose une solution unique et complète de relation client multicanal, misant sur le vocal avec sa solution de callbot, convaincue que la voix sera demain, un axe clé de service des marques. Zaion révolutionne l’expérience client tout au long de son parcours d’usager de centre de contact.", "siren": "832291256"}, {"name": "SAS SPINALCOM", "description": "SpinalCom aide les propriétaires et exploitants à libérer la valeur des quantités massives de données générées par leurs bâtiments pour prendre des décisions basées sur des données de qualité et pour piloter leurs systèmes en temps réel afin de générer des économies, de nouveaux revenus et transformer véritablement l'expérience des occupants.", "siren": "514972306"}, {"name": "FLUOPTICS", "description": "Fluoptics développe et commercialise à l’international de nouveaux systèmes d’imagerie de fluorescence pour guider le chirurgien en temps réel pendant l’intervention, permettant de diminuer les risques de complications post-opératoires et garantissant une meilleure prise en charge du patient ainsi qu’une diminution drastique des coûts de santé.\nFLUOPTICS© aborde le problème n°1 de la chirurgie de la thyroïde : l’hypocalcémie postopératoire due à la lésion accidentelle des glandes parathyroïdes. Sur la base du produit actuel pour cette indication leader sur son marché, FLUOCARE permet le développement d’un produit hautement innovant miniature et quantitatif.\nFLUOPTICS© vise à réduire le taux d’hypocalcémie transitoire de plus de 20 % à moins de 5 %, entraînant une meilleure qualité de vie pour les patients, une réduction des risques de décès, en plus d’économies de l’ordre de 12,2 % sur le coût total de la chirurgie.", "siren": "510508716"}, {"name": "GREENMETRICS", "description": "Greenmetrics est une start-up française existant depuis 2020, dont la mission principale est de mesurer puis réduire l’empreinte environnementale numérique des entreprises. Greenmetrics a développé une plateforme SAAS et des technologies permettant aux entreprises et administrations d’automatiser l’accès aux données et réduire leurs impacts environnementaux liés à leur activité numérique.", "siren": "887598605"}, {"name": "PANDASCORE", "description": "Créé en 2015, PandaScore est un pure player IA - esport, francilien, encore pionnier à ce jour dans son objectif d’appliquer l’Intelligence Artificielle et la Vision par Ordinateur à l’esport pour fournir les statistiques et les cotes les plus précises et temps réel à l’écosystème.", "siren": "813145745"}, {"name": "INTENSCITY", "description": "INTENSCITY développe la 1ère plateforme de gestion d’éclairage architectural par la vidéo", "siren": "853677672"}, {"name": "La Vingt-Cinquième Heure Distribution", "description": "La 25e Heure est une place de marché et une plateforme permettant aux lieux culturels de diffuser leur programmation dans leurs salles virtuelles géolocalisées ou de les multiplexer entre plusieurs lieux, en présentiel et/ou en virtuel. Chaque événement peut être interactif via un dispositif de chat intégré.\nLa 25e Heure permet aux lieux culturels de proposer une meilleure accessibilité à leur programmation, notamment pour les publics empêchés et d'accroître leurs recettes.\nLa plateforme est inclusive et compense en carbone chaque visionnage de contenu en ligne.\nLa 25e Heure a l’ambition de se développer à l’échelle mondiale et d’évoluer en un véritable outil et réseau social professionnel engageant une nouvelle dynamique collaborative entre les lieux culturels et les communautés culturelles et sociales locales (en particulier les Digital Native).\nLa 25e Heure crée un continuum entre l'expérience de la salle physique et la consommation digitale de programmes culturels.\nElle propose ainsi aux lieux culturels un business model complémentaire et innovant permettant d’accroître l’audience et la circulation des oeuvres, favorise la diversité de ces productions en optimisant l’usage et la collecte de datas, tout en favorisant une démarche inclusive.", "siren": "841204050"}, {"name": "PIXPOLE", "description": "Wakatoon développe des technologies et contenus qui allient création sur papier et numérique dans le but de modérer le temps d’exposition des enfants aux écrans tout en favorisant leur imagination. Notre produit phare : des albums de coloriage dont les pages se transforment en dessin animé, à partir d’une simple photographie.", "siren": "809210081"}, {"name": "Spare Parts 3D", "description": "Fondée en 2018, Spare Parts 3D est une entreprise innovante spécialisée dans la numérisation d’inventaires et la production de pièces par fabrication additive. Nous développons, en partenariat avec des leaders du secteur, des solutions d’impression plastiques hautes performances spécifiques à destination de nos clients du semi-conducteur.", "siren": "841469265"}, {"name": "Stirweld", "description": "STIRWELD commercialise des systèmes de soudage FSW (Soudage par friction malaxage). Son produit historique est une tête FSW pour machines-outils à commande numérique qui permet de baisser drastiquement le coût d’investissement pour accéder à cette technologie. De nouveaux produits comme la broche FSW pour robot sont en cours de développement.", "siren": "832024350"}, {"name": "APHELIOR", "description": "La société Aphelior conçoit une solution de logiciels applicatifs autour de la musique et du bien-être, pour adapter la musique aux émotions de l’utilisateur grâce à de l’intelligence artificielle, sous forme de hardware as a service.", "siren": "900062480"}, {"name": "Perspective[S]", "description": "Créée en février 2013, Perspective(S) à Aix-en-Provence, la société Perspective(S) se positionne comme experte en réalité virtuelle, augmentée et mixte. A la fois techniciens et créatifs, nous avons développé une expertise technique des environnements 3D temps réel : capture de mouvement, immersion 3D, réalité virtuelle/augmentée, vidéo interactive, web3D, reconnaissance d’objets…", "siren": "791156268"}, {"name": "VU Log", "description": "VULOG propose une solution SaaS de bout en bout (Back Office, technologie embarquée et Front-End) permettant à toutes entités d’initier un service d’autopartage. Cette solution s’adresse aux opérateurs de flottes et se compose d’une plateforme, d’un ordinateur de bord, d’une gestion administrative et d’applications mobiles pour les utilisateurs.", "siren": "490533528"}, {"name": "LDL TECHNOLOGY", "description": "Equipementier automobile de premier rang spécialisé dans le développement, LDL Technology\nindustrialise et commercialise des systèmes électroniques embarqués intelligents et connectés sans fil.", "siren": "477592794"}, {"name": "SynapCell", "description": "La société SynapCell est un CRO expert leader mondial du marché des études précliniques de candidats- médicaments visant le système nerveux central en se basant sur l’usage des biomarqueurs EEG. Les travaux de SynapCell permettent d’étudier l’effet thérapeutique de nouvelles molécules contre les pathologies touchant le cerveau comme l’épilepsie, la maladie de Parkinson ou la schizophrénie.", "siren": "481563526"}, {"name": "ADLIN Science", "description": "ADLIN est une digital health-tech qui accompagne les chercheurs, cliniciens, biotech et entreprises pharmaceutiques dans la gestion, l’analyse et la valorisation de leurs données multi-omiques à travers un logiciel qui vise à favoriser l’interopérabilité des données et à promouvoir la collaboration entre les acteurs de la santé via des solutions innovantes.", "siren": "890791692"}, {"name": "ExactCure", "description": "ExactCure développe une solution de santé pour un bon usage du médicament. Notre Jumeau Numérique simule la concentration des médicaments dans le sang d'un patient en fonction de ses caractéristiques personnelles (âge, poids, sexe, statut rénal et hépatique, génotype…) pour éviter sous-doses, surdoses et interactions médicamenteuses.", "siren": "834329088"}, {"name": "Mablink Bioscience", "description": "Mablink Bioscience est une société de biotechnologie spécialisée dans le développement d'une nouvelle classe de médicaments anticancéreux, appelés conjugués anticorps-médicaments (ADC). Elle licencie également sa plateforme de développement d’ADC, PSARlinkTM.", "siren": "845257930"}, {"name": "Ubiplug", "description": "Ubiplug conçoit des dispositifs médicaux faciles d’utilisation, destinés à améliorer la prise en charge des patients pour lesquels un accès au système circulation central est nécessaire. Ainsi, elle réalise des travaux avec l’objectif de développer un nouvel abord vasculaire pour l’hémodialyse.", "siren": "830525549"}, {"name": "Weenat", "description": "Le projet Meteoria vise à développer un outil de pilotage d’irrigation simple et déployable pour tous les agriculteurs afin de réduire leurs coûts opérationnels et préserver la ressource en eau", "siren": "803450287"}, {"name": "FRENCH TOUCH FACTORY", "description": "French Touch Factory est spécialisée dans les technologies immersives. La startup propose des services aux entreprises dans les domaines de la 3D, de la programmation, de l’audiovisuel, des VFX, de la capture volumétrique, de la Réalité Virtuelle et Augmentée. Elle crée également des expériences à destination du grand public.", "siren": "843717943"}, {"name": "Newsbridge", "description": "Newsbridge développe et commercialise une plateforme SaaS permettant à ses clients d’archiver et de monétiser ses contenus d’archives vidéo et photo.\nSes clients sont des groupes de médias et de presse (TF1, AFP, Brut, Sky… ) des ayants droits sportifs (FFF, Bayer Leverkusen, Olympique de Marseille… ).", "siren": "817784317"}, {"name": "Pianity", "description": "Pianity est la première marketplace française de musique NFT où les artistes et leur communauté se réunissent pour écouter et collectionner des morceaux en éditions limitées. L’approche pionnière de Pianity, qui inclut l’écoute gratuite et la possibilité de transformer les morceaux en NFT offre aux artistes une nouvelle source de revenus leur permettant d’être plus indépendants et de se connecter plus en profondeur avec leurs fans.", "siren": "898551502"}, {"name": "ADD TECHNOLOGIES", "description": "ADD Technologies produit et commercialise son système d’Aile de propulsion gonflable dans le but d’équiper les navires de la marine industrielle et de réduire leur empreinte carbone. Son bureau d’études basé à Lorient travaille en étroite collaboration avec les chantiers navals et les armateurs pour intégrer le système.", "siren": "849902838"}, {"name": "EPEIRE3D", "description": "Née d’une R&D à haute valeur ajoutée, EPEIRE3D apporte des avancées technologiques majeures avec sa gamme d’imprimantes 3D à granulés, alliant performance, technicité, économies et modularité. Ainsi, l’entreprise conçoit, développe, fabrique et commercialise 3 gammes de machines d’impression 3D. L’entreprise propose également des services de maintenance et de conseil pour l’installation de ses machines.", "siren": "841066947"}, {"name": "echOpen Factory", "description": "echOpen développe une sonde d’imagerie échographique ultra-portable et abordable, connectée à un smartphone ou tablette et dédiée à l’orientation diagnostique. Annoncé comme le « stéthoscope » du XXI° siècle. Cet outil incontournable dans la prise en charge des patients, sera augmenté de services numériques et d’intelligence artificielle.", "siren": "882017346"}, {"name": "RDS SAS", "description": "RDS est une startup basée à Strasbourg qui propose aux hôpitaux la solution MultiSense® pour une télésurveillance continue et précise destinée à permettre un suivi physiologique du patient jusqu’à son domicile.\nIl s'agit d'un dispositif médical miniaturisé et connecté, fabriqué en France, qui permet une télésurveillance de très haute qualité (en continu et pendant plusieurs jours) des paramètres cardiaques et respiratoires clés : rythme cardiaque, ECG, saturation d'oxygène, événements de pression artérielle, fréquence respiratoire, température cutanée, activité et posture.\nCette solution permet aux équipes cliniques de laisser les patients rentrer chez eux plus tôt, en toute sécurité, et de les surveiller à distance comme s'ils étaient encore à l'hôpital, en particulier lors d’un suivi post-chirurgical.", "siren": "882347958"}, {"name": "POXEL", "description": "Poxel est une société biopharmaceutique au stade clinique qui développe des traitements innovants pour les maladies chroniques graves d’origine métabolique, notamment la stéatohépatite non alcoolique (NASH) et les maladies rares (ALD).", "siren": "510970817"}, {"name": "WAINVAM-E", "description": "WAINVAM-E est aujourd’hui la plus grande start-up au monde développant et commercialisant des solutions basées sur l’exploitation des propriétés quantiques de diamants à centres NV, pour différentes applications commerciales (industrie, recherche, cosmétique, agroalimentaire…). Son objectif long terme est de développer de nouvelles solutions biomédicales.", "siren": "882937659"}, {"name": "IDEE Services", "description": "IDEE Services développe un prototypage et un test en bassin d’essai d’un cluster de 3 machines houlomotrices de production électrique à l’échelle 1/10e. \nIDEE Services est un bureau d’étude et de prototypage avec une expérience de plus de 30 ans en conception et industrialisation d’ensemble et sous-ensemble technologiques destinés notamment au véhicules spéciaux, véhicules électriques, nouvelles mobilités et énergies renouvelables. Parallèlement, IDEE Services agit comme porteur indépendant de projets technologiques de rupture.", "siren": "850703562"}, {"name": "AZUVIA", "description": "AZUVIA vise à accélérer l’industrialisation et la mise sur le marché de ses systèmes de traitement des effluents liquides fortement chargés en pollution organiques et azotées. \nAZUVIA est une start-up technologique innovante qui développe des systèmes écologiques de traitement des effluents liquides. Ses technologies sont conçues pour répondre aux besoins en traitement des rejets issus des exploitations vinicoles, des plateformes de compostage et des industries agro-alimentaires. Ces innovations reposent sur la phyto-épuration, l’hydroponie et l’environnement contrôlé.", "siren": "848104840"}, {"name": "ENGINN TECHNOLOGIES", "description": "Enginn concoit et implémente une architecture temps réel pour un modèle de synthèse vocale émotionnelle multilingue. \nEnginn Technologies développe des applications de synthèse vocale. Ces applications sont destinées aux créateurs de contenus nécessitant de la voix.", "siren": "888384252"}, {"name": "IRIDER", "description": "IRAS™ est le premier Système Intelligent d’Assistance à la conduite de Véhicules Légers Électriques (VLE) à base d’IA, de caméras intelligentes et de connectivité dédié à la sécurité des conducteurs, des piétons et des véhicules. \niRider est une société d’Intelligence Artificielle et de logiciel Mancelle dont la mission est de permettre l’adoption en masse des Véhicules Légers Électriques en développant un système intelligent d’assistance à la conduite qui protège les utilisateurs des autres véhicules, les piétons des mauvais comportements et les véhicules des vandales.", "siren": "827864950"}, {"name": "IMEDIAPP", "description": "OMNIBATCH apportera une solution de communication client (CRM) souveraine permettant aux grandes entreprises et administrations de relever les défis d’un monde numérique mobile. \nDepuis 2015, iMediapp fournit à ses 400 clients européens une plateforme de communication client via notifications push. Cette technologie s’appuie sur des flux de données et non des bases de données statiques permettant une orchestration agile et réactive des campagnes de communication pour engager et fidéliser les utilisateurs finaux.", "siren": "525279600"}, {"name": "BLOOM", "description": "Le Projet R0-N propose une offre inédite de collecte de données, de détection et d’évaluation de la propagation des risques, d’alerting en temps réel pour tous les réseaux sociaux. Il s’agit de créer premier indicateur mondial de viralité sociale, le R0 numérique \nBloom est une plateforme d’anticipation stratégique qui permet aux marques et institutions de détecter tendances et signaux faibles, d’anticiper les crises et de décrypter les communautés sur les réseaux sociaux. Ses fondateurs sont Bruno Breton, expert des médias et réseaux sociaux, et Alexander Polonsky, docteur en mathématiques appliquées et neurosciences.", "siren": "511646226"}, {"name": "Embodme", "description": "SuperIRIS est le premier écran interactif fonctionnant au contact et sans contact. Permettant une interaction plus naturelle, accessible et hygiénique, cet écran interactif est conçu pour remplacer les écrans tactiles traditionnels dans les lieux publics et les industries du numérique. \nEmbodme développe des capteurs de vision en champ proche pour les interfaces homme-machine. La startup parisienne sort son premier produit en 2020: un contrôleur musical innovant utilisé par des artistes de renoms tels que Jean-Michel Jarre et le groupe Coldplay avant de se lancer sur le marché de l’affichage interactif.", "siren": "843725714"}, {"name": "Whispeak", "description": "Je parle donc je suis ! Whispeak VIP permettra de généraliser l’usage de la voix comme élément biométrique simple et omnicanal pour sécuriser nos authentifications dans le respect de notre vie privée. \nWhispeak propose une solution pour fluidifier les processus d’authentification avec un facteur biométrique simple à déployer et à utiliser : la voix. \nSaaS, onPremise ou embarquée, la solution se déploie naturellement sur tous les points de contacts en bénéficiant de la présence généralisée des micros. Elle est 100% RGPD compatible.", "siren": "883563728"}, {"name": "Deemea", "description": "Le projet ASTRID 2 vise à homologuer et mettre à disposition des médecins, une application digitale pour le dépistage et le suivi des patients atteints de spondyloarthrites axiales. \nDeemea est une startup en santé numérique experte en analyse de données de vie réelle guidées par l’intelligence artificielle. Spécialisée dans le traitement des données d’imagerie, elle développe une plateforme coopérative d’assistance au diagnostic et au suivi des patients atteints de pathologies inflammatoires ou de maladies rares.", "siren": "882328057"}, {"name": "RIBONEXUS", "description": "Ribonexus est une société bio-pharmaceutique spécialisée dans la R&D de petites molécules innovantes ciblant la résistance aux médicaments des cellules cancéreuses. \nEn se concentrant sur les inhibiteurs de la traduction de l’ARNm, la société possède une licence exclusive pour une bibliothèque de composés thérapeutiques de Pierre Fabre Médicament, qui ont été identifiés comme ayant un potentiel thérapeutique contre la cible eIF4A. Ribonexus concentre ses travaux sur le traitement du mélanome.", "siren": "898280250"}, {"name": "ALTAROAD", "description": "BETTER crée la « boîte à outils de réduction de l’impact environnemental du chantier» avec des recommandations actionnables, contextualisées et multicritères pour tous les acteurs. \nCréé en 2017, ALTAROAD est lauréat i-Nov pour sa solution innovante de traçabilité des matériaux et déchets du BTP pour répondre au besoin des entreprises de BTP et du traitement des déchets dans la réduction de leur impact environnemental.", "siren": "833737653"}, {"name": "oghji", "description": "Oghji fabrique le premier tableau électrique intelligent « tout en un » pour les économies d’énergie Smart Building et l’optimisation des flux électriques Smart City \nL’entreprise OGHJI a pour mission de fabriquer un tableau électrique éco-responsable, nativement digital et connecté, destiné au résidentiel et petit tertiaire, pour l’efficacité énergétique du bâtiment et du territoire.", "siren": "841719545"}, {"name": "ONSEN", "description": "Onsen développe une matrice numérique unique et révolutionnaire du bâtiment avec un service centralisé de monitoring précis et efficace permettant une parfaite maitrise des piscines publiques. \nL’activité d’ONSEN est basée sur la récupération d’énergie, le renouvellement de l’eau et l’automatisation grâce à ses nombreuses références en France. Onsen assure un accompagnement complet, la mise en service est faite par leurs soins et ils forment leurs personnels aux différents outils.", "siren": "518714332"}, {"name": "smartway", "description": "Smartway offre depuis 2012 des solutions d’aide à la réduction du gaspillage alimentaire aux acteurs de la grande distribution. Présente dans plusieurs milliers de magasin dans 11 pays différents, Smartway prouve au quotidien que l’on peut réconcilier impact écologique et impact économique: Sustainable is Profitable.", "siren": "750444697"}, {"name": "YellowScan", "description": "YellowScan conçoit, fabrique et commercialise des solutions LiDAR qui garantissent des données de haute qualité pour les applications de cartographie en 3D. Les solutions développées par l’entreprise matérielles et logicielles sont des outils de collecte de données faciles à utiliser qui s’accompagnent d’une formation et d’une assistance de la part de nos experts.", "siren": "813091543"}, {"name": "IRCAM AMPLIFY", "description": "Ircam amplify est la société d’innovation audio qui met le meilleur de la recherche française au service des nouveaux usages et des industries. La société opère un modèle hybride en proposant de la prestation de service et des produits technologiques à forte valeur ajoutée, ciblant les Industries culturelles et créatives, l’Automobile, le Luxe-Retail, la Robotique et l’IoT.", "siren": "852085257"}, {"name": "GEOMATYS", "description": "Geomatys est une PME spécialisée dans le traitement de données géospatiales et le développement de Systèmes d’Information Géographiques. Cette activité se décline également en la production de solutions métiers innovantes intégrant l’exploitation de données géospatiales combinée à des algorithmes d’Intelligence Artificielle.", "siren": "484766308"}, {"name": "Yseop", "description": "Yseop, leader en intelligence artificielle générative pour les sciences de la vie et l’industrie b i o p h a r m a c e u t i q u e , révolutionne l’automatisation des contenus dans les secteurs régulés grâce à sa plateforme centrée sur l’humain. S’appuyant sur des technologies de pointe en traitement du langage naturel (NLP), Yseop accélère la mise sur le marché de nouveaux médicaments en optimisant la rédaction de rapports et d’analyses, réduisant ainsi significativement les délais critiques de \nl’industrie.", "siren": "433429065"}, {"name": "KAPSDATA", "description": "KAPSDATA développe des solutions d’aide au pilotage à destination des infrastructures industrielles complexes grandes consommatrices d’énergie. Le projet KAPSCENTER aborde les datacenters, leurs exploitants et leurs gestionnaires, en vue de réduire la consommation énergétique et l’empreinte environnementale. De nouveaux composants de pilotage de ces bâtiments seront créés. Basés sur des intelligences artificielles interprétables, ils permettront de caractériser les nombreuses causes de déséquilibre ou d’anomalies et de recommander les actions à réaliser pour se rapprocher des objectifs de performances de ces bâtiments.", "siren": "809582570"}, {"name": "Navee", "description": "Navee est un prestataire de service dans le secteur de la protection de marque contre la contrefaçon en ligne et y met en oeuvre de nombreuse technologies basées sur l’image, le texte et le contexte pour automatiser la recherche et la prise de décisions sur le contenue contrefaisant.", "siren": "844840728"}, {"name": "Evolutive Agronomy", "description": "Evolutive Agronomy produit et vend des agents de biocontrôle pour lutter efficacement et naturellement contre les ravageurs du sol.", "siren": "952317576"}, {"name": "Broadpeak", "description": "Broadpeak conçoit des logiciels et des services de diffusion vidéo pour les fournisseurs de contenus et opérateurs réseau, permettant la diffusion de films, programmes en direct et autres contenus sur des réseaux à haut débit, avec une qualité optimale sur tous les appareils.", "siren": "524473063"}, {"name": "CARBON BEE AGTECH", "description": "Le projet ILS (Intelligent Localized Spraying) a pour objectif la mise sur le marché d’une solution de capteurs hyperspectraux et d’analyse par Intelligence Artificielle, installés sur la rampe de pulvérisateur, permettant d’identifier et discriminer les espèces végétales nuisibles (adventices), afin de piloter en temps réel une pulvérisation localisée.\nLes objectifs économiques pour Carbon Bee AgTech sont de pouvoir équiper le marché européen avec un modèle d’affaire reposant sur une logique de service.\nLes objectifs sociétaux et environnementaux sont d’accompagner avec une solution pragmatique la réduction de solution désherbante sur les cultures les plus répandues en Europe.", "siren": "834072407"}, {"name": "ETS DUBRULLE", "description": "La société conçoit et fabrique des solutions de manutention, de déterrage, de calibrage et de stockage pour les pommes de terre, oignons et autres productions légumineuses.", "siren": "447350018"}, {"name": "SPECTRALYS innovation", "description": "Le projet OPTI MILL a pour objectif de développer une plateforme analytique unique permettant de mesurer en temps réel l’ensemble des critères pertinents de qualité des blés et farines. De plus un outil d’aide à la décision sera mis en place à destination des meuniers afin de proposer le mélange optimal pour assurer la qualité du pain baguette chez l’industriel ou l’artisan en fonction du cahier des charges.\nLe projet est porté par SPECTRALYS Innovation, spécialisée dans le développement de solutions analytiques optiques de rupture, non- destructives, sensibles et en temps réel. Cette technologie est basée sur l’utilisation innovante des signaux de fluorescence naturelle émis par les produits biologiques et alimentaires.", "siren": "508491883"}, {"name": "C4Hydro", "description": "C4Hydro est spécialisée dans la détection de microorganismes pathogènes dans l’eau. Sur la base d’une technologie brevetée, elle propose actuellement des solutions permettant de contrôler efficacement dans tous types d’eaux chaudes le risque sanitaire dû à Légionella pneumophila (bactérie pathogène à déclaration obligatoire et à l’origine de la légionellose).", "siren": "821975844"}, {"name": "ACCENTA", "description": "ACCENTA développe un système énergétique comprenant une solution de stockage des énergies thermiques du bâtiment et un système de pilotage intelligent et auto-apprenant, qui permet d’atteindre des niveaux de performance inégalés tant en efficacité énergétique qu’en décarbonation, à un coût compétitif par rapport aux énergies traditionnelles.", "siren": "823555495"}, {"name": "ENERGIES DEMAIN", "description": "Energies Demain est un bureau d’études spécialisé dans la mise en œuvre opérationnelle des politiques publiques de transition énergétique. Depuis plus de 10 ans, la société développe de nombreux modèles et solutions numériques adapté aux défis et contraintes de l’énergie", "siren": "480478502"}, {"name": "HAWK", "description": "HAWK porte la vision du Drone-As-A-Service.\nLes drones permettent de capter de la donnée à moindre coût. Ils s’inscrivent dans la digitalisation de processus et d’assets et concourent à l’industrie 4.0. La place de marché de HAWK rassemble des milliers de prestataires de services professionnels de drones, mobilisables à la demande", "siren": "805358090"}, {"name": "STEADYSUN", "description": "STEADYSUN développe des outils qui proposent des services de prévision de production solaire à haute précision, pour des horizons allant de quelques minutes à plusieurs jours. Les prévisions de production sont obtenues en couplant l’analyse des données des centrales solaires, les prévisions météorologiques, les données satellites et les images prises sur site.", "siren": "792522492"}, {"name": "SurfactGreen", "description": "SurfactGreen développe, formule et commercialise des tensioactifs verts pour des applications dans des domaines variés tels que la détergence, la cosmétique, les émulsions bitumeuses ou encore l’agriculture. Sa technologie est issue des travaux de recherche des professeurs Plusquellec et Benvegnu depuis 1984 sur le développement de tensioactifs verts issus de matières premières naturelles.", "siren": "823347133"}, {"name": "SHIPPEO", "description": "Shippeo a créé le premier outil collaboratif de tracking et de visibilité en temps réel pour le transport routier de marchandises. Elle travaille avec plus de 30 grands comptes, fait appel à la plateforme SaaS pour maîtriser leurs flux en interaction avec les chargeurs, transporteurs, conducteurs.", "siren": "801689415"}, {"name": "AB Tasty", "description": "AB Tasty est le leader français et européen du marché de l’A/B Testing. L’A/B Testing consiste à tester plusieurs variantes d’un site internet, chaque version étant présentée à une partie des internautes tandis que les données de navigation des différents panels sont analysées pour mesurer l’impact de chaque version.", "siren": "518685540"}, {"name": "EUVEKA", "description": "Spécialisés dans les technologies robotiques liées à la morphologie et au biomimétisme, nous avons mis au point la nouvelle génération des mannequins de bois. Ce mannequin-robot évolutif et connecté, piloté par un logiciel dédié, aidera les professionnels du textile à créer, produire et vendre des vêtements à la taille exacte.", "siren": "534166038"}, {"name": "Therapixel SA", "description": "Therapixel est une société éditeur de logiciel spécialisée dans l’imagerie médicale. Elle développe des algorithmes d’aide à la décision pour l’interprétation d’images. Notre objectif : positionner un radiologue digital du meilleur niveau dans chaque cabinet de radiologie.", "siren": "793920521"}, {"name": "Aenitis Technologies", "description": "Aenitis Technologies développe des solutions innovantes de manipulation et de filtration de cellules basées sur les technologies d’acoustophorèse.\nLa Société se concentre sur le développement de solutions technologiques qui vont permettre de révolutionner les pratiques actuelles des procédés de préparation en thérapie cellulaire relevant d’enjeux de santé publique majeurs.", "siren": "803512458"}, {"name": "Vaxinano", "description": "Vaxinano est spécialisée dans le développement de vaccins prophylactiques et thérapeutiques contre les maladies infectieuses, sur les marchés de la santé humaine et animale. Nous développons des vaccins sûrs, plus stables, plus efficaces et sans adjuvant. Notre technologie brevetée est centrée sur l’utilisation de nanoparticules biodisponibles et bioéliminables.", "siren": "821549755"}, {"name": "SENTRYO", "description": "Éditeur de solution de Cyber sécurité pour l’Internet Industriel, Sentryo aide les entreprises, à assurer la disponibilité, la résilience et la sécurité de leurs systèmes de contrôle industriels en profitant de la transformation numérique et en luttant contre les cyberattaques.", "siren": "802913160"}, {"name": "DIBOTICS", "description": "DIBOTICS est spécialisée dans le traitement en temps-réel des données issues de capteurs de type LiDAR, permettant à tout robot mobile, dont la voiture autonome, de comprendre son environnement", "siren": "810319764"}, {"name": "EBIKELABS", "description": "eBikeLabs conçoit, développe et commercialise des systèmes de propulsion pour vélo à assistance électrique innovants et interactifs. La solution développée est un cerveau électronique pour les vélos électriques. Le système moteur n’est plus seulement un simple organe de propulsion mais se transforme en un véritable système moteur interactif", "siren": "810993857"}, {"name": "VITIBOT", "description": "VitiBot est une start-up innovante rémoise spécialisée en robotique viticole. L’entreprise conçoit et produit des robots viticoles autonomes qui révolutionnent le travail de la vigne. Elle possède une technologie innovante conjointement pensée avec des grandes maisons de Champagne", "siren": "824267389"}, {"name": "CYCL-ADD", "description": "Les plastiques recyclés présentent des propriétés dégradées : les transformateurs du plastique utilisent des additifs pour les renforcer, mais ils ne sont pas issus du recyclage. Cycl-add développe des additifs issus du recyclage, fabriqués à partir de déchets industriels. Le procédé Cycl-add permet alors l’obtention de plastiques 100 % recyclés.", "siren": "821242898"}, {"name": "Les Alchimistes", "description": "Les Alchimistes ont deux activités principales :\n• collecte et compostage électromécanique des biodéchets en circuit-court, sur un maillage de sites d’une capacité de 600 tonnes par an (actuellement sur des sites pilotes pour faire la preuve du concept) ;\n• R&D sur le traitement de déchets non valorisés : couches-culottes, bioplastiques.", "siren": "824298343"}, {"name": "ROSI", "description": "ROSI propose une solution innovante de recyclage de silicium ultra pur provenant de la filière photovoltaïque, et actuellement considéré comme déchets. ROSI valorise ce silicium de haute qualité contenu dans ces déchets industriels afin de le réinjecter dans la chaine de production photovoltaïque initiale.", "siren": "833310204"}, {"name": "ThrustMe", "description": "Fondée en 2017, ThrustMe est une société de « deep-tech », qui développe et commercialise des systèmes de propulsion spatiale entièrement intégrés et optimisés pour les satellites de nouvelle génération. Sa technologie s’appuie sur plus de dix ans de recherche fondamentale et appliquée au sein du laboratoire de physique des plasmas, Unité mixte de recherche entre le CNRS et l’Ecole Polytechnique.", "siren": "827453614"}, {"name": "AMPLISIM", "description": "AmpliSIM offre un service web de modélisation environnementale, principalement dans le domaine de la qualité de l’air. Ses clients sont des industriels, des gestionnaires d’infrastructure et des sociétés d’engineering. AmpliSIM aide ses clients à évaluer, suivre et prévoir l’impact de leurs installations sur l’environnement et les populations.", "siren": "810488114"}, {"name": "OROSOUND", "description": "Orosound est une entreprise française, créée en 2015, experte en acoustique et en prévention des risques professionnels. Orosound propose des solutions brevetées aux entreprises pour la réduction et la gestion des nuisances sonores. Orosound est lauréate du Ministère de la Recherche et du Trophée d’Or de l’Innovation au salon Expoprotection.", "siren": "811315829"}, {"name": "FairyTool", "description": "FairyTool est une startup créée en Juillet 2017. Sa mission est de développer des solutions technologiques innovantes pour la création de contenus numériques (animation 3D) pour les médias traditionnels (cinéma, télévision) et les nouveaux médias (réalité virtuelle et augmentée, internet). Le projet PocketStudio a été sélectionné parmi les 10 finalistes du concours Real-Time Live! de SIGGRAPH (Vancouver 2019).", "siren": "831275904"}, {"name": "POLLEN Metrology", "description": "Pollen Metrology est spécialisée dans l’édition de logiciels d’intelligence artificielle (IA) destinés à la production de matériaux innovants. Notre technologie permet d’accélérer à la fois la phase de développement et d’optimiser la phase de production de ces matériaux innovants en augmentant les rendements.", "siren": "804862043"}, {"name": "Skopai", "description": "La plateforme Skopai permet d’observer et d’analyser les startups et les PME innovantes au niveau mondial. Grâce à ses technologies propriétaires d’intelligence artificielle, Skopai collecte massivement sur le web des données sur les startups et livre à l’utilisateur les informations qu’il recherche sur une startup ou sur un secteur.", "siren": "831050489"}, {"name": "Toucan Toco", "description": "Notre mission : faire acte de pédagogie pour transformer des données brutes complexes en des Dataviz et Histoires interactives. Les Small Apps de Toucan sont mobiles, simples d’utilisation, facilement paramétrables, intégrées dans les SI existants et au service de l’excellence opérationnelle des métiers RH, Marketing, Financière, Commerciaux et Directions Générales.", "siren": "801300526"}, {"name": "BOOSTHEAT", "description": "BOOSTHEAT est concepteur, fabricant, installateur et mainteneur de chaudières thermodynamiques très performantes. BOOSTHEAT est une nouvelle technologie de compression thermique permettant d’atteindre des rendements de 200 % sur énergie primaire, divisant par 2 les consommations d’énergie et les émissions de gaz à effet de serre (GES) liées au chauffage.", "siren": "531404275"}, {"name": "METAFORA biosystems", "description": "METAFORA est le seul acteur industriel au monde à pouvoir caractériser les besoins de cellules en nutriments pour alimenter leur métabolisme énergétique. La société développe une plateforme unique permettant de détecter et de caractériser les besoins énergétiques de cellules individuellement, pour diagnostiquer des maladies précocement et efficacement.", "siren": "530932672"}, {"name": "NovaGray", "description": "NovaGray développe les premiers tests de tolérance à la radiothérapie pour les cancers du sein, de la prostate et du poumon. Basés sur un prélèvement sanguin, ces tests permettent d’identifier, avant traitement, les patients à risque de développer des complications lourdes. NovaGray s’inscrit dans la voie de la médecine personnalisée.", "siren": "814412672"}, {"name": "GREEN SHIELD", "description": "Développer un appareil de désherbage laser de précision", "siren": "820173292"}, {"name": "SABI AGRI", "description": "SABI AGRI est une entreprise d’ingénierie agricole qui conçoit, fabrique et commercialise des agroéquipements innovants en lien avec l’agro- écologie.", "siren": "831190806"}, {"name": "Watchfrog", "description": "Le laboratoire Watchfrog est une PME innovante spécialisée dans l’évaluation des effets des perturbateurs endocriniens et des micropolluants sur le vivant.\nIl propose des tests éthiques grâce à des modèles aquatiques, larves d’amphibiens et de poissons, associant des marqueurs fluorescents qui permettent de révéler le potentiel perturbateur des échantillons testés.", "siren": "811684190"}, {"name": "SPIREC", "description": "Conception, fabrication et vente en France, Europe et Etats-Unis d’échangeurs thermiques, de terminaux de climatisation pour les hébergements d’hôpitaux, et de sous-stations pour le chauffage et la production d’eau chaude sanitaire des établissements de santé et des logements.", "siren": "484872551"}, {"name": "DCbrain SAS", "description": "MarvinZero est un logiciel permettant l’optimisation des processus de fabrication des industries, depuis les flux fournisseurs amont jusqu’aux produits finaux micro-personnalisés.", "siren": "805052735"}, {"name": "E-COBOT", "description": "E-COBOT est une société industrielle spécialisée en conseil, conception et intégration de solutions en cobotique et en intelligence artificielle pour les secteurs de l’industrie manufacturière. Ces trois activités sont le conseil en cobotique et en performance industrielle, la conception de cobots sur- mesure et l’intégration de solution collaboratives ou coopératives.", "siren": "819577230"}, {"name": "AIVE", "description": "La technologie Aive se présente sous la forme d’une plateforme vidéo alimentée par une intelligence artificielle créative permettant d’automatiser la création des vidéos, et d’en optimiser la distribution.\nCette technologie s’adressera dans un premier temps au marché publicitaire pour les marques (projet « deep tech » présenté ici) puis via notre API aux marchés de l’e-commerce et des plateformes sociales.", "siren": "848706800"}, {"name": "NOVITOM", "description": "Novitom, société de service B2B indépendante est spécialisée dans les techniques avancées de caractérisation et de contrôle non destructif. Pionnière dans la prestation de services sur-mesure autour de l’imagerie industrielle, Novitom conçoit et développe les outils numériques requis pour implanter la numérisation 3D au coeur des procédés industriels.", "siren": "535196836"}, {"name": "MAbSilico SAS", "description": "MAbSilico est une jeune société de biotechnologie issue d’un laboratoire de recherche dont l’activité principale consiste à  combiner  des approches d’intelligence artificielle, de  deep-learning  et  de  big  data afin de développer des algorithmes permettant de modéliser certaines étapes du développement précoce (phases précliniques) des anticorps thérapeutiques.", "siren": "832200224"}, {"name": "PATHOQUEST", "description": "PathoQuest, société experte en génomique appliquée aux tests microbiologiques, a choisi 2 applications au niveau mondial : une application industrielle de biosafety pour l’industrie pharmaceutique et les biotech, et une application en diagnostic clinique pour les laboratoires de microbiologie hospitaliers. Nous vendons nos services en France comme à l’international.", "siren": "524876059"}, {"name": "Stem Genomics", "description": "Stem Genomics est une nouvelle start-up qui propose des tests innovants pour mesurer l’intégrité génétique des cellules souches. Le premier test commercialisé en service a l’avantage d’utiliser l’ADN libre du surnageant de culture. Ces tests permettent de contrôler les cellules à chaque stade de leur production pour la thérapie cellulaire.", "siren": "841152077"}, {"name": "Hackuity", "description": "Hackuity développe et commercialise une plateforme SaaS à destination des commanditaires et des prestataires de tests d’intrusions informatiques. L’ambition d’Hackuity est de révolutionner le marché - en créant l’unique place de marché mondiale dédiée - et les pratiques, grâce à sa technologie de rupture.", "siren": "841324577"}, {"name": "BuyCo", "description": "Le projet porte sur le développement de nouvelles fonctionnalités de la plateforme digitale collaborative BuyCo sur laquelle importateurs/ exportateurs, transitaires et transporteurs maritimes peuvent déjà collaborer sur un même dossier de transport de conteneurs, afin de simplifier, optimiser et sécuriser leurs échanges.", "siren": "800532822"}, {"name": "CWS MOREL", "description": "CWS développe une voile aile innovante à destination du transport maritime. Le système développé vient fournir une poussée additionnelle aux navires afin de permettre aux armateurs de réduire la puissance moteur, et donc la consommation et les pollutions associées.", "siren": "811732700"}, {"name": "SEVA Technologies", "description": "Société d’ingénierie spécialisée dans la conception et la réalisation de systèmes de protection passifs en sécurité automobile.", "siren": "794167593"}, {"name": "SQUADRONE SYSTEM", "description": "SQUADRONE SYSTEM est une entreprise spécialisée dans la conception de drones autonomes et intelligents. Squadrone System propose des solutions drones visant à résoudre des problématiques industrielles. Ces drones permettent de simplifier et d’harmoniser les systèmes de commande robotique et ainsi de décupler l’efficacité de ses clients B2B.", "siren": "803183771"}, {"name": "VEL'CO", "description": "Velco est une entreprise innovante qui a développé le premier guidon connecté pour vélo capable de guider de manière intuitive et sécurisée le cycliste grâce à des signaux lumineux et de sécuriser le moyen de transport ainsi que l’utilisateur.", "siren": "818024234"}, {"name": "AXIOMA", "description": "AXIOMA est une entreprise spécialisée dans la conception et la fabrication de biostimulants pour l’agriculture et les espaces verts, de compléments alimentaires pour l’élevage, et d’additif de compostages pour les agriculteurs. Les produits AXIOMA sont composés d’agencement complexes d’extraits hydroalcooliques de plantes fraîches, et sont utilisables en agriculture biologique.", "siren": "789737095"}, {"name": "CESIGMA SIGNALS & SYSTEMS", "description": "CeSigma est une PME experte en électronique et traitement de données temps-réel. Le savoir-faire de CeSigma est concentré sur 4 métiers : les systèmes d’acquisition et de traitement de données, les  systèmes  de mesure des Hautes Énergies, les systèmes de Sécurité & de Défense et les systèmes de surveillance environnementale.", "siren": "413591215"}, {"name": "ANTOFENOL SAS", "description": "Développer un produit de biocontrôle pour les agrumes", "siren": "802796698"}, {"name": "Pellenc ST", "description": "Pellenc ST conçoit, fabrique et commercialise des équipements de tri et leurs services associés auprès de professionnels spécialisés dans la réception, la séparation et la préparation des matériaux recyclables pour la commercialisation de matière première secondaire. Par son expertise, elle accompagne les exploitants dans la gestion de leur performance.", "siren": "435267885"}, {"name": "SYRLINKS", "description": "Développement et fabrication de produits de radio communication destinés aux marchés du spatial, de la défense, de la sécurité et du temps- fréquence. Syrlinks affiche deux credo : la fiabilité et la performance… avec deux enjeux : la miniaturisation et la faible consommation.", "siren": "532462256"}, {"name": "Separative", "description": "Sur la base d’une découverte scientifique, SEPARATIVE développe une gamme de colonnes disruptives de chromatographie pour la purification de produits pharmaceutiques.", "siren": "801697426"}, {"name": "BIOSENCY", "description": "BiOSENCY apporte une solution de télésuivi personnalisée, innovante, cliniquement validée pour le patient insuffisant respiratoire chronique, afin d’améliorer son parcours de soin et sa qualité de vie. Nous commercialisons un dispositif médical (bracelet BORA Band connecté à une plateforme web BORA connect), et différentes interfaces pour les professionnels de santé.", "siren": "830861860"}, {"name": "GEOTWIN", "description": "GeoTwin développe des modèles de simulation multi-agent de la petite à la grande échelle afin d’aider les collectivités, les opérateurs de mobilité et les industriels à planifier et à optimiser des offres de transports traditionnelles et innovantes suivant des critères tels que les coûts, les bénéfices environnementaux et sociétaux.", "siren": "843549809"}, {"name": "HOMEYS", "description": "Homeys propose un logiciel (Software as a Service –Saas) d’analyse de données permettant d’améliorer la performance énergétique des bâtiments grâce à un réglage optimisé des systèmes de chauffage collectif. Les clients de Homeys sont les bailleurs sociaux et les exploitants chauffagistes", "siren": "839582335"}, {"name": "MICRODB", "description": "MicrodB innove et transfère des technologies du monde académique à l’industrie pour l’identification des sources de bruit. Ses ingénieurs en acoustique et techniciens développent des produits à base de réseau de capteur et d’algorithme en traitement du signal. Elle revend sa technologie par réseau de distribution.", "siren": "398873778"}, {"name": "Biodis", "description": "BIODIS est spécialisée dans le développement, la production et la commercialisation de probiotiques destinés à la nutrition Humaine. Son offre s’appuie sur des capacités à la fois d’innovation et de fermentation industrielle.", "siren": "348966029"}, {"name": "LA FABRIQUE A POPOTTE (ACDO)", "description": "ACDO développe des modèles algorithmiques complexes pour supprimer les contraintes de la cuisine du quotidien. Notre assistant culinaire Popotte Duck simplifie l’organisation et optimise l’alimentation du foyer en fonction de ses préférences et de son environnement. Personnalisation de l’alimentation et diminution du gaspillage alimentaire sont les maitres mots de notre assistant.", "siren": "829476878"}, {"name": "Né d'une seule ferme", "description": "Né d’une seule ferme crée plus de valeur à la ferme, en rendant simple la transformation, via des modules (containers) équipés et mobiles transformant l’industrie en Industry as a Service. Les containers sont prévus pour être déployés par centaines sur tout le territoire, et rendront accessibles les produits fermiers.", "siren": "853545127"}, {"name": "PROCSEA", "description": "ProcSea est la place de marché en ligne spécialisée dans les produits de la mer et exclusivement dédiée aux professionnels. Depuis 2016, nous connectons en temps réel les mareyeurs et producteurs avec les restaurateurs, poissonniers et grandes surfaces.", "siren": "820559110"}, {"name": "VALOREX", "description": "VALOREX est une entreprise qui développe des produits et des services, historiquement pour le marché de l’alimentation animale et plus récemment pour le marché de l’alimentation humaine. Le cœur de métier de VALOREX repose sur son savoir-faire dans la technologie de cuisson des graines oléo-protéagineuses (lin, féverole, pois, et lupin).", "siren": "389863986"}, {"name": "SESAME IT", "description": "Pure Player Cybersécurité, Sesame IT est dédiée à la détection d’attaques réseau. La mission de Sesame IT est d’accompagner les Organisations d’Intérêt Vital pour sécuriser efficacement leurs réseaux. Aujourd'hui la société démarre la commercialisation de sa sonde Jizo, et travaille continuellement sur sa nouvelle solution de deceptive technologie, Loki.", "siren": "832787477"}, {"name": "AX SYSTEM", "description": "AX SYSTEM conçoit et fabrique des solutions robotisées visant à optimiser le rendement énergétique des centrales électriques thermiques et solaires. Le AX Cleaner® est un robot nettoyant par haute-pression les tubes  à ailettes des aéro-échangeurs des centrales thermiques, maximisant ainsi la production électrique.", "siren": "502349590"}, {"name": "E-Mersiv", "description": "E-Mersiv a pour objet de concevoir et vendre des batteries Li-ion hautes performances pour le marché de la voiture électrique. E-Mersiv utilise et maitrise une technologie de refroidissement par immersion et de gestion électronique des batteries qui permet une rupture technologique des caractéristiques des batteries.", "siren": "852745660"}, {"name": "HYCCO", "description": "HYCCO®   développe un élément clef destiné aux prochaines générations de piles à combustibles, les plaques bipolaires. HYCCO® propose un service d’expertise sur l’intégration de sa technologie sur des systèmes industriels existant, et est en mesure d’accompagner ses clients, du prototypage jusqu’à la phase d’industrialisation.", "siren": "850621848"}, {"name": "Waga Energy", "description": "Waga Energy valorise le biogaz des sites d’enfouissement sous forme de biométhane. Les unités d’épuration, WAGABOX®, garantissent un biométhane de haute qualité, quelle que soit la qualité du biogaz brut. Celui-ci peut être injecté directement dans les réseaux de distribution de gaz ou utilisé comme carburant pour les véhicules", "siren": "809233471"}, {"name": "Agriconnect", "description": "Agriconnect se positionne dans le secteur de l’arboriculture, plus précisément dans l’optimisation de la production (tonnage, calibre et qualité) des vergers de pommier, à travers son service de cartographie d’intensité de floraison et l’intégration des cartes de traitement pour consoles de modulation guidées par GPS pour piloter la pulvérisation automatiquement.", "siren": "822127700"}, {"name": "Energiency", "description": "Energiency est une société spécialisée en intelligence énergétique industrielle qui mène un projet de recherche ambitieux visant à développer des technologies et un produit logiciel innovant au service des nouveaux enjeux de la Transformation Digitale de l’Industrie et de la réduction de l’impact énergétique et climatique.", "siren": "792639098"}, {"name": "TerraNIS", "description": "TerraNIS est une société toulousaine spécialisée dans la conception, le développement et la commercialisation de services de géoinformation utilisant l’imagerie satellitaire dans les domaines de l’agriculture, l’environnement et l’aménagement du territoire. TerraNIS développe et commercialise ses services en France et à l’export (Europe et Amérique du Sud).", "siren": "800815367"}, {"name": "TOOPI-Organics SAS", "description": "TOOPI Organics est une start-up spécialisée dans le recyclage, la transformation et la valorisation de l’urine humaine en produits pour l’agriculture et l’industrie. TOOPI Organics a été fondée en février 2019 à Langon (33) et dispose aujourd’hui d’une équipe de 8 salariés.", "siren": "848016093"}, {"name": "Hera-MI", "description": "Hera-MI est une entreprise française spécialisée dans l'imagerie médicale appliquée au diagnostic radiologique du cancer du sein. La société a développé et commercialise Breast-SlimView V1.0, un logiciel breveté d'aide au diagnostic du cancer du sein basé sur l'Intelligence Artificielle pour la mammographie 2D et 3D.", "siren": "828871699"}, {"name": "Oasis Smart Sim Europe", "description": "Oasis Smart SIM Europe (Oasis) fournit des technologies de pointe et des services personnalisés permettant le déploiement d'eSIM (carte SIM intégrée). À la pointe de l’innovation dans l’industrie des logiciels embarqués sécurisés, Oasis est membre de la GSMA depuis 2011 et a été la 1ere PME mondiale à avoir obtenu un très large portefeuille de certifications de la part des autorités de régulations.", "siren": "522418516"}, {"name": "SPACEABLE", "description": "SpaceAble crée la première plateforme SAAS et multi-face de données spatiales permettant à ses utilisateurs d'accéder à toutes les données critiques pour surveiller avec précision et simuler les risques associés aux actifs en orbite terrestres, notamment les risques de météo spatiale.", "siren": "842107070"}, {"name": "Avicenna.ai", "description": "Le métier principal de la société Avicenna.AI est la conception, le développement et la mise sur le marché de solutions d’aide au diagnostic et de prise en charge du patient dans le domaine de l’imagerie médicale et particulièrement du scanner. Avicenna.AI a développé une solution pour la radiologie d’urgence en scanner.", "siren": "840424287"}, {"name": "Eurevia", "description": "La société EUREVIA conçoit et fabrique des unités terminales de chauffage vecteur air dédiés aux navires de croisière, hôtels, habitations, résidences et bureaux. La stratégie d’innovation permet à EUREVIA de se différentier sur ce marché très concurrentiel", "siren": "502266562"}, {"name": "TELMA", "description": "Depuis plus de 60 ans, Telma est le leader mondial du freinage sans friction basé sur le principe physique de l’induction électromagnétique. L’entreprise TELMA est spécialiste dans la conception et la réalisation de ralentisseurs électromagnétiques à destination de véhicules lourds (camions, autobus et autocars).", "siren": "410163125"}, {"name": "Nimesis Technology", "description": "Leader dans le domaine des actionneurs spatiaux intelligents, Nimesis Technology conçoit, développe et produit des actionneurs, sécurités thermiques et dispositifs intelligents pour l’industrie à partir d’alliages à mémoire de forme.", "siren": "508776010"}, {"name": "CIRCOULEUR", "description": "CIRCOULEUR a développé un procédé innovant permettant de créer des peintures acryliques à partir de restes de peintures inutilisés (Minimum 70% de matière recyclée). Leurs performances sont équivalentes à une peinture neuve haut de gamme en termes de pouvoir couvrant, facilité d’application ou praticité.", "siren": "825283039"}, {"name": "LEANSPACE", "description": "La première Plateforme en tant que Service pour l’ingénierie spatiale. Notre technologie permettra aux agences, aux entreprises et à des milliers de startups du NewSpace de gérer leurs programmes spatiaux bout-en-bout avec une facilité et une agilité sans précédent, et d’interopérer. Avec la transformation numérique, nous accélérerons la conquête spatiale.", "siren": "882763220"}, {"name": "ISAHIT", "description": "ISAHIT opère  dans  le  domaine  de  l’innovation  avec  impact  social, à l’international. Isahit développe une plateforme d’externalisation socialement responsable de tâches digitales pour l’intelligence artificielle et le traitement de données.", "siren": "812570604"}, {"name": "MY TRAFFIC", "description": "Mytraffic propose la première plateforme Saas afin d’analyser les flux Piétons, pour accompagner les acteurs de l’immobilier commercial (enseignes, foncières, agents immobiliers et villes) dans leurs décisions d’installation de commerce, de suivi de la performance ou de diagnostic de l’attractivité commerciale d’un quartier ou d’une rue.", "siren": "814849113"}, {"name": "UNEOLE", "description": "UNEOLE s’impose comme le spécialiste de l’énergie éolienne en zone urbaine. L’entreprise développe depuis 2014 des éoliennes répondant aux contraintes des zones urbaines. Aujourd’hui Unéole innove en proposant la première plateforme de production d’énergies renouvelables hybrides, le système le plus productif en qualité et en quantité d’énergie.", "siren": "803310713"}, {"name": "VERDIKT", "description": "Verdikt a pour ambition de (ré)concilier numérique et écologie en entreprises pour valoriser leur performance sociétale, en équipant les directeurs informatique et RSE, d’une plateforme d’évaluation et d’optimisation de la performance écologique de leur numérique.", "siren": "889631123"}, {"name": "Lumedix", "description": "LumediX développe des tests rapides hyper-sensibles pour le diagnostic médical, avec une sensibilité analytique de plusieurs ordres de grandeur plus élevée que l’existant, grâce à une technologie propriétaire de nanoparticules luminescentes. La mission de LumediX est de rendre les meilleures solutions de diagnostic in vitro accessibles à tous, partout.", "siren": "841289119"}, {"name": "Advanced biodesign", "description": "Advanced BioDesign est une société de biotechnologie développant une thérapie innovante contre les cancers résistants. Sa molécule phare, le DIMATE, est un inhibiteur spécifique dirigé contre une nouvelle cible thérapeutique d’intérêt majeur : la famille des enzymes aldéhydes déshydrogénases de classe 1 (ALDH1).", "siren": "523847820"}, {"name": "ADYOULIKE", "description": "Adyoulike est une AdTech française référente. Pionnière en 2012 du Native Advertising, un format publicitaire respectueux de l’utilisateur, devenu le format majoritaire du marché, Adyoulike a également été l’instigateur de la première plateforme programmatique haute fréquence Native en 2016.", "siren": "531651792"}, {"name": "AgenT", "description": "AgenT développe des solutions diagnostiques et thérapeutiques pour cibler la maladie d’Alzheimer dès la phase silencieuse et stopper la progression avant l’apparition des symptômes irréversibles. Son premier produit est un test sanguin pour diagnostiquer Alzheimer dès la phase asymptomatique.", "siren": "838187318"}, {"name": "AItenders", "description": "Grâce à notre technologie autour du NLP, l’OCR et l’apprentissage supervisé, Aitenders aide ses clients à extraire de l’intelligence de leurs documents d’appels d’offre, leurs permettant ainsi d'accélérer le processus de revue de décision, d’augmenter la qualité des réponses et de contribuer à la capitalisation des connaissances.", "siren": "844748251"}, {"name": "Algama", "description": "Pionnière dans la valorisation des microalgues dans le système alimentaire, Algama développe des technologies et ingrédients Clean Label 100% végétaux pour l’industrie alimentaire, remplaçant complètement les produits d’origine animale (oeufs, poissons, produits laitiers…) et rendant accessible au grand public les bénéfices nutritionnels des microalgues sans contraintes de goût, d’odeur et de conservation.", "siren": "798666806"}, {"name": "Cardiorenal", "description": "CardioRenal est une entreprise de thérapies digitales. Nous développons des dispositifs médicaux connectés pour mesurer des biomarqueurs sanguins (e.g. créatinine & K+) à domicile par les patients et des logiciels qui permettent le suivi et l’optimisation de traitement par les médecins à distance.", "siren": "789041027"}, {"name": "Diabeloop", "description": "Diabeloop est une entreprise à forte croissance qui développe et commercialise des solutions personnalisées basées sur l'IA pour améliorer les résultats cliniques des personnes avec un diabète, tout en soulageant leur charge mentale constante.", "siren": "810416438"}, {"name": "ITinSell", "description": "ITinSell est un éditeur de solutions logicielles de pointe pour la e-logistique (ou logistique du e-commerce). Sa philosophie : apporter une excellence opérationnelle aux e-commerçants et 3PL afin de transformer la livraison en véritable outil d’acquisition, de fidélisation et même de réengagement clients.", "siren": "832948962"}, {"name": "K-Ryol", "description": "Permettant de tracter 500 kilos sans effort, sans gâchette, ni bouton grâce à une technologie révolutionnaire, 2 véhicules électriques ultra-intuitifs ont ainsi été développés :\n· des remorques pour vélo pour la logistique urbaine\n· des chariots de manutention pour éliminer la pénibilité sur les chantiers.", "siren": "818670093"}, {"name": "Micropep technologies", "description": "Micropep Technologies développe une technologie deep-tech dans les biotechnologies végétales, reposant sur la découverte d’une famille de peptides (ou petites protéines), baptisées « miPEPs ». Présents naturellement dans les plantes et permettant une régulation fine et transitoire de l’expression de leurs gènes, ils sont la clé vers une agriculture durable.", "siren": "819588427"}, {"name": "MOB ENERGY", "description": "Mob-Energy est une PME française fondée fin 2018 et spécialisée dans les systèmes de recharge innovants pour parkings. Ses solutions robotisées utilisent du stockage d’énergie durable pour ainsi accélérer la transition vers une mobilité plus durable en rendant la recharge accessible pour tous, partout, tout le temps.", "siren": "843868555"}, {"name": "Newheat", "description": "NEWHEAT est le leader français de la fourniture de chaleur solaire et de récupération à destination des grands consommateurs industriels, des réseaux de chaleur urbains et des serres maraîchères. NEWHEAT propose à ses clients des solutions de décarbonation combinant solaire thermique, chaleur fatale et stockage thermique (courte et longue durée).", "siren": "815176128"}, {"name": "OCEAN DEVELOPPEMENT", "description": "Océan Développement est un chantier nautique spécialisé dans la course au large et les projets innovants liés au nautisme. A travers des projets sur mesure, OCEAN DEVELOPPEMENT réalise des bateaux démonstrateurs, qui allient des concepts novateurs high-tech avec des valeurs de performance à un souci constant de la préservation des océans.", "siren": "490476777"}, {"name": "Primaa", "description": "Primaa développe des solutions à base d’intelligence artificielle pour accompagner les médecins anatomo-pathologistes dans le diagnostic des cancers.", "siren": "842567422"}, {"name": "PROTERA", "description": "PROTERA fabrique des ingrédients alimentaires sains et écoresponsables à base de protéines. Notre plateforme d'intelligence artificielle utilise des algorithmes prédictifs pour identifier et révéler les propriétés de protéines présentes dans la nature, dont nous développons ensuite la production par fermentation.", "siren": "881925630"}, {"name": "Qubit Pharmaceuticals", "description": "Quantum Machine Learning pour la découverte de Médicaments", "siren": "883649238"}, {"name": "SOLICAZ", "description": "Solicaz est une société d'ingénierie agroécologique spécialisée dans la préservation et la restauration du capital naturel des sols. Elle propose des produits et services innovants qui s'appuient sur les interactions étroites entre les micro-organismes du sol et les plantes, pour le maintien des services écosystémiques et une production éco-efficiente.", "siren": "517957130"}, {"name": "GEOSYS", "description": "GEOSYS est spécialisé dans le traitement des données satellites pour l’agriculture. Adhérent du pôle de compétitivité Agri Sud-Ouest Innovation, GEOSYS souhaite, grâce à l’expertise de ses data scientists, développeurs et agronomes, devenir leader dans le développement d’outils d’aide à la décision pour le monde agricole.", "siren": "343043790"}, {"name": "KERMAP", "description": "KERMAP est spécialisée dans l’information stratégique à destination des acteurs privés et publics grâce à l’analyse massive et automatisée d’images satellite et aériennes. KERMAP produit ces informations à forte valeur ajoutée et les valorise via ses plateformes cartographiques et outils d’aide à la décision.", "siren": "832361471"}, {"name": "aQuasys", "description": "AQuasys est l'un des principaux fournisseurs français de systèmes de gestion des ressources en eau aidant les différents acteurs face au contexte du dérèglement climatique. Les systèmes développés facilitent le traitement de l’ensemble des données du grand cycle de l’eau, depuis l'acquisition des données jusqu’à leur visualisation.", "siren": "493021125"}, {"name": "Buildrz", "description": "Buildrz modélise la constructibilité des parcelles en numérisant les règles des Plans Locaux d'Urbanisme. L'IA génère des volumes à la surface de plancher maximisée, dont la faisabilité économique est évaluée grâce à des données de marché. Les utilisateurs peuvent visualiser en 3D, modifier et partager leurs projets en ligne.", "siren": "822111795"}, {"name": "Geosophy", "description": "Les outils logiciels développés ont pour objectif de faciliter l’accès à la géo-énergie pour les nonspécialistes, pour un chauffage et un rafraîchissement durable, local et décarboné des bâtiments.", "siren": "843459884"}, {"name": "KOCLIKO", "description": "Kocliko révolutionne l’individualisation des frais de chauffage pour les gestionnaires d’immeubles en chauffage collectif (bailleurs sociaux et copropriétés), grâce à une nouvelle technologie de mesure de la quantité de chaleur consommée par un logement, associant Simulation Thermique Dynamique ultraprécise et algorithmes de machine learning.", "siren": "820508174"}, {"name": "SAS WONDERWOMALT", "description": "La société revalorise les drêches de bières, le malt résiduel, en farine alimentaire riche en apport nutritionnel (Activité de meunerie) pour répondre aux enjeux de revalorisation des drêches et aux demandes de plus gros acteurs de l’agroalimentaire.", "siren": "840571541"}, {"name": "Japet Medical", "description": "Japet combine les technologies médicales et la robotique moderne au service de la santé. Son premier exosquelette, le Japet.W est destiné à la prévention du mal de dos au travail. Il est déjà utilisé par plus de 300 personnes dans plus de 15 pays.", "siren": "820081602"}, {"name": "Golem.ai (IDEQUANET)", "description": "Golem.ai est une Deeptech ayant pour ambition de faciliter le travail grâce au langage. Ainsi, l’entreprise développe une IA unique et à contre-courant des modèles actuels omniprésents sur le marché des solutions d’automatisation. Les technologies développées fonctionnent sans entraînement ni données personnelles et sont 100% française.", "siren": "821352317"}, {"name": "Octopize", "description": "Octopize, startup labellisée Deeptech, développe et commercialise une nouvelle méthode d’anonymisation des données personnelles basée sur l’intelligence artificielle : les avatars. Les avatars sont des données anonymisées garantissant la protection et la conservation de la qualité statistique des données initiales pour en assurer un partage et une exploitation éthique.", "siren": "839370681"}, {"name": "WABEL", "description": "Notre société Wabel, a pour mission depuis ses débuts en 2013 de faciliter la mise en relation et la collaboration entre acheteurs et fournisseurs majoritairement européens des secteurs de l’agroalimentaire, des vins et spiritueux, de la beauté, de l’hygiène, et de l'éco-emballage.", "siren": "521214262"}, {"name": "Sogilis", "description": "Sogilis est une PME grenobloise créée en 2008. Depuis sa création l’entreprise affiche une raison d’être ambitieuse : « amener l’industrie du logiciel vers le zéro défaut ». Elle oeuvre en ce sens au travers sa principale activité : le développement de systèmes logiciels critiques (ESN experte), mais également dans le développement de produits pour améliorer l’efficience des développements logiciels, et ses filiales produit innovantes (Hionos et SquareScale).", "siren": "502012073"}, {"name": "Biodiv-Wind", "description": "Biodiv-Wind SAS est une entreprise française créée en 2011 et basée à Boujan-Sur-Libron (34). L’entreprise développe, installe et exploite un système de détection de la faune volante basé sur l’Intelligence Artificielle (IA) en milieu industriel.", "siren": "538449737"}, {"name": "Earthwake Entreprise", "description": "Earthwake Entreprise a mis au point un équipement de pyrolyse, appelé Chrysalis, capable de valoriser 300 kg de déchets plastiques par jour en énergie (65% de diesel, 15% d’essence, 15% de gaz destiné à alimenter l’équipement en énergie de chauffe et 5% de résidus carbonés).", "siren": "882741390"}, {"name": "Fairme", "description": "Fairme conçoit une machine de transformation laitière multi-produit entièrement autonome. Cette Smart Factory branchée directement à la ferme, transforme le lait en une gamme de produits laitiers à la demande du consommateur via une simple application Web. En automatisant la transformation et la vente à la ferme, Fairme rend possible la consommation locale à la ferme à grande échelle, offrant un bénéfice écologique et social considérable.\nFairme répond à un besoin croissant de la part des consommateurs de se nourrir de produits fermiers sains, locaux et ne répondant pas aux critères de l’industrie agroalimentaire. Les processus usuels sont vecteurs de pollution et d’émissions de gaz à effet de serre conséquentes, détériorent l’aspect qualitatif des produits et ne permettent pas aux éleveurs de valoriser leur travail à un juste tarif. Le modèle du fermier s’occupant de l’élevage, la traite, la transformation et la vente à la ferme nécessite un nombre d’heures de travail et des investissements considérables, principaux freins à son développement à grande échelle. En apportant une solution technologique novatrice, Fairme résout l’équation fermier- consommateur.", "siren": "888970837"}, {"name": "DOCENT", "description": "Docent est une application mobile facilitant la découverte d’oeuvres d’art contemporain. Nos algorithmes identifient et analysent les préférences des collectionneurs et s’affranchissent des biais habituels du marché pour leur proposer les oeuvres d’art les plus proches de leurs goûts.", "siren": "891899148"}, {"name": "Upfluence SAS", "description": "Prédiction de la performance des publications des influenceurs", "siren": "792760548"}, {"name": "UNIFIED SOFTWARE", "description": "UNIFIED SOFTWARE a inventé la SOFTWARE FACTORY qui permet de réaliser les logiciels métiers 25 fois plus rapidement. Grâce à son système totalement novateur de composants métiers standards intégré à la SOFTWARE FACTORY, UNIFIED SOFTWARE propose la première solution no-code métiers. Cette solution permet de réaliser en quelques heures des logiciels métiers complexes automatiquement interfacés entre eux. A terme le projet permettra de couvrir tous les secteurs d’activités de l’économie.", "siren": "892968512"}, {"name": "ABYS MEDICAL", "description": "La société Abys® Medical développe des dispositifs médicaux à destination du marché de la chirurgie traumatologique. Lauréate du concours i-Lab 2020, Abys® Medical est né de l'ambition d'être un nouvel acteur de la chirurgie orthopédique, en combinant médecine personnalisée et outils numériques puissants dans les mains des chirurgiens orthopédistes.", "siren": "841052814"}, {"name": "PHENOCELL", "description": "Phenocell est une société de recherche contractuelle (CRO) fondée en 2013, experte reconnue pour les tests biologiques in vitro humains de nouvelle génération basés sur des modèles dérivés de cellules iPS. Nous développons des outils in vitro et programmes de R&D pour les industries dermocosmétique et pharmaceutique.", "siren": "797465457"}, {"name": "Usense", "description": "Usense développe un dispositif médical de diagnostic in vitro (DMDIV) connecté et réutilisable, de la taille d'un stylo, permettant l'accès à un diagnostic médical précoce et personnalisé pour les praticiens et leurs patients. En quelques secondes, la solution Usense permet de mesurer quantitativement les biomarqueurs habituellement recherchés dans l’urine. Usense est une MedTech proposant des dispositifs médicaux connectés à base d’intelligence artificielle.", "siren": "851832212"}, {"name": "FeetMe", "description": "FeetMe est un fabricant de dispositifs médicaux certifié qui développe et produit des semelles connectées pour améliorer la mobilité. Sa technologie innovante permet d’analyser en temps réel et au quotidien les paramètres de marche et de pression plantaire et de proposer de la rééducation digitale avec biofeedback en temps réel.", "siren": "797586708"}, {"name": "INOVAYA", "description": "InovaYa développe des solutions innovantes pour un traitement efficient des eaux potables et industrielles. Avec une approche novatrice et durable, elle propose une gestion décentralisée et locale de l’eau, en rapprochant le traitement du besoin. Sa mission : préserver la ressource en eau pour la rendre accessible à tous", "siren": "837594027"}, {"name": "CAPACITE", "description": "Gouach révolutionne l’industrie des batteries en fabriquant une nouvelle génération de batteries éco- conçues à partir de cellules de secondes vies et en développant des outils logiciels permettant de connaître rapidement l’état des batteries et les réparations à effectuer.", "siren": "844405274"}, {"name": "Kikléo", "description": "KIKLEO est une startup qui développe un système breveté de caméra intelligente permettant une analyse détaillée du gaspillage alimentaire grâce à un algorithme de reconnaissance visuelle. Les données collectées sont centralisées sur une plateforme pour être exploitées et mettre en place des mesures correctives afin de réduire les pertes.", "siren": "877561365"}, {"name": "ÉHO.LINK", "description": "Ého.Link est une société R&D marseillaise qui développe des solutions de cybersécurité en s’appuyant sur 4 piliers d’expertise : réseaux/télécoms, systèmes, Big Data & IA. Son objectif : démocratiser les technologies les plus novatrices afin de faciliter l'accession des entreprises, collectivités et particuliers à la sécurisation et la protection numérique.", "siren": "818763278"}, {"name": "Droon", "description": "DROON est expert dans le développement et la mise en œuvre de blockchains privées pour la collaboration, la gestion de processus, la sécurité et la gestion des données. Droon utilise la blockchain comme tiers de de confiance sécurisé pour la gestion et l’analyse des données.", "siren": "850183708"}, {"name": "Moovency", "description": "Moovency est une entreprise DeepTech spécialisée dans la vision par ordinateur et les méthodes d’IA permettant d’estimer les mouvements des travailleurs sur leur poste de travail. Ces données posturales permettent de déterminer des indicateurs biomécaniques objectifs et chiffrés du risque de troubles musculosquelettiques (TMS) encouru par le travailleur.", "siren": "843692559"}, {"name": "UPFLOW", "description": "Upflow est une société numérique qui développe une plateforme SaaS permettant de simplifier et d’automatiser les processus de gestion des factures et de recouvrement des créances pour les entreprises B2B.", "siren": "838718328"}, {"name": "CYCLIK", "description": "CYCLIK s’inscrit dans une démarche pionnière qui vise à reconsidérer les modes de production usuels de l’industrie du cycle et proposer aux utilisateurs des solutions alternatives viables, pérennes, et plus vertueuses pour transitionner vers les mobilités douces. L'ambition de l'entreprise est à la fois simple et complexe : proposer les vélos ayant le plus faible impact environnemental possible pour que demain, la production d’un vélo soit aussi verte que sa pratique ! De là découle l'ensemble de notre démarche et de la démarche de l'entreprise, allant de l'éco-conception, à la fabrication locale des cadres à partir de matières végétales, en passant par un cahier des charges qui vise à produire des vélos de qualités, durables, sûrs mais aussi exaltants.", "siren": "834939431"}, {"name": "SAS MINIMUM", "description": "SAS MINIMUM est une jeune stratup industrielle de l’ESS, spécialisée dans la transformation de déchets en matériaux durables pour le bâtiment.", "siren": "837645175"}, {"name": "MIDIPILE Mobility", "description": "MIDIPILE MOBILITY imagine, développe, produit et opère une nouvelle catégorie de véhicule bas carbone adaptée aux ZFE-m : 4 roues, carrossé fermé, durable, simple, léger et peu couteux. Les véhicules roulent à 45km/h et emportent 300 kg de charge utile dans les différentes versions cargos.", "siren": "889863494"}, {"name": "Caranx Medical", "description": "L’ambition de Caranx Medical est de révolutionner le domaine de la chirurgie en proposant les premiers robots intelligents à autonomie partielle, supervisés par le praticien. La valeur apportée par les robots réside dans la réduction de la complexité des procédures, la standardisation et la démocratisation du geste technique, et surtout dans l’amélioration de la qualité des soins par la diminution de la morbi- mortalité des patients.", "siren": "879449965"}, {"name": "LUCINE", "description": "La société Lucine developpe depuis 10 ans des thérapies numériques spécialisées dans les douleurs chroniques. Lucine a fait le choix de créer sa premiére solution brevetée pour soulager efficacement et durablement les douleurs pelvi-périnéales liées à l'endométriose ou aux règles.", "siren": "828117028"}, {"name": "MED’INN’Pharma", "description": "MIP est spécialisée dans la pharmacologie résolutive et développe une gamme de candidats médicaments. Grace à sa plateforme technologique propriétaire unique, MIP produit des candidats médicaments 100% humains et biologiques, fabriqués par des cellules humaines, composés d’un ensemble parfait de molécules dédiées au traitement de maladies chroniques et dégénératives.", "siren": "828460139"}, {"name": "Pasqal SAS", "description": "Le projet 10XQER²A vise à développer et concevoir une architecture pour augmenter drastiquement la fréquence de calcul des processeurs quantiques PASQAL. \nPASQAL construit et vend des ordinateurs quantiques à partir de la technologie des “atomes neutres” ordonnés en réseaux 2D et 3D. Le but étant d’apporter un “avantage quantique” i.e. des performances de calcul supérieures aux processeurs “classiques”.", "siren": "849441522"}, {"name": "RAILwAI", "description": "RAILwAI développe une solution d’analyse globale des données clés de l’infrastructure ferroviaire permettant, grâce à l’IA, de réduire les pannes et les coûts, et donc de favoriser la mobilité durable ! \nRAILwAI est un éditeur de solutions logicielles d’aide à la décision pour la surveillance, la maintenance et le renouvellement des infrastructures ferroviaires. Ses solutions intégrées aux processus métiers sont centrées sur les données et reposent sur le développement de modèles d’intelligence artificielle.", "siren": "904233350"}, {"name": "DESSINTEY", "description": "ACTIVITY LAB développe des solutions de rééducation interactives et intelligentes pour réduire le temps d’inactivité des patients, quel que soit leur stade de récupération. \nDessintey développe et commercialise des technologies de rééducation intensive pour accélérer le retour à l’autonomie des patients. Dessintey s’appuie sur les dernières avancées scientifiques en neurosciences et sur une proximité forte avec les thérapeutes pour proposer des technologies simples et efficientes.", "siren": "831210620"}, {"name": "TRIBUN HEALTH", "description": "Pathomix développe un Outil logiciel pour l’utilisation des données médicales histopathologiques issues du soin (RWD) au profit de la recherche, du développement en IA et du développement pharmaceutique. \nTribun Health est éditeur de solutions logicielles de gestion d’images d’anatomopathologie utilisées par les médecins spécialisés dans le cadre de leur examen diagnostique. Ces dispositifs médicaux, qui remplacent le microscope, permettent de travailler de façon digitale, et d’apporter au médecin des moyens innovants contribuant à optimiser le parcours diagnostique.", "siren": "538927120"}, {"name": "URBANLOOP", "description": "Le projet CROSS, Croisements Opérés par une Supervision Sécuritaire, va permettre de sécuriser les traversée de voies Urbanloop tout en gardant une vitesse commerciale élevée pour l’usager. \nUrbanloop est une entreprise française fondée en 2019 développant un système de transport public urbain à faible impact environnemental. C’est un transport guidé léger, autonome en site propre. Urbanloop répond au besoin des territoires de moyenne densité avec une solution écologique plus efficace que l’automobile sur le temps de trajet.", "siren": "878394956"}, {"name": "France Quadricycle", "description": "Le projet porte sur le développement du Ouicycle, le premier moyen de transport collectif actif et décarboné, destiné aux collectivités territoriales. \nFrance Quadricycle développe des solutions de mobilités actives qui s’inscrivent dans une nouvelle catégorie de véhicules dits intermédiaires. La mise au point de ce type de véhicule repose sur des innovations techniques (pédalier générateurs, toit photovoltaïque) permettant aux passagers de contribuer facilement au déplacement du véhicule.", "siren": "850984097"}, {"name": "Standing Ovation", "description": "Standing Ovation apporte une solution innovante pour réduire l’empreinte environnementale des produits laitiers, avec la production de caséines -les principales protéines du lait- par fermentation de précision: un procédé efficace qui permet la production d’ingrédients avec une moindre consommation des ressources et impact sur la planète. Lauréate FrenchTech 2030, elle a pour objectif de devenir un acteur incontournable de la transition alimentaire, de l’économie circulaire et de la souveraineté alimentaire en accompagnant les industriels dans la voie d’une production plus durable.", "siren": "884522582"}, {"name": "DIAMFAB", "description": "DIAMFAB synthétise du diamant pour l’industrie du semi-conducteur. Nos produits seront au coeur de la transition énergétique grâce à des performances électriques supérieures, une efficacité record et une forte compacité.", "siren": "849450705"}, {"name": "MUODIM", "description": "Muodim a développé une nouvelle technologie de rupture parmi les méthodes de Contrôle Non Destructif : la muographie. Elle permet de cartographier l’intérieur d’une structure pour produire des images. Ces images permettent de prévenir des risques, anticiper des problèmes d’exploitation et optimiser des process industriels. Nous intervenons dans le génie civil, l’industrie et les géosciences.", "siren": "901931105"}, {"name": "LOUISE", "description": "Louise est une start-up de techbio spécialisée dans la fertilité, qui a pour objectif de permettre aux professionnels de soin de la PMA de prendre des décisions diagnostiques et thérapeutiques plus éclairées grâce à l’utilisation de l’IA collaborative et éthique.", "siren": "914943774"}, {"name": "BLUEBACK", "description": "BLUEBACK est une entreprise bretonne spécialisée dans l’analyse des muscles profonds. Elle a développé la technologie Deep EMG®️ qui permet de détecter des muscles profonds à partir de capteurs de surface et de méthodes IA. Ces produits sont vendus principalement aux professionnels de santé mais son développement futur s’oriente vers le grand public pour la prévention et l’éducation thérapeutique.", "siren": "834565327"}, {"name": "ATOPTIMA", "description": "Atoptima est une DeepTech, spin-off d’Inria/CNRS, qui édite des logiciels d’aide à la décision basés sur l’intelligence de l’optimisation mathématique. Déjà lauréate du concours i-Lab, son expertise se traduit en des outils performants à la pointe de l’innovation technologique pour la planification des opérations du transport, de la logistique des entrepôts et des processus industriels.", "siren": "851387225"}, {"name": "MOBA", "description": "Moba est le leader européen du diagnostic et de la certification batterie des voiture électriques. Grâce à une solution logicielle multi-marques et à un boîtier de diagnostic, Moba permet de certifier l’état de santé (SOH) d’une batterie en moins de 2 minutes, quelque soit la marque de la voiture électrique. \nMoba travaille avec plus de 500 clients en Europe, dont une dizaine de leaders du marché automobile comme Stellantis , Toyota, Aramisauto ou Arval (BNP Paribas), qui utilisent la solution Moba Certify Pro au quotidien et sur l’ensemble de leur parc VE d’occasion pour assurer une vente rapide, efficace et totalement transparente pour l’acheteur. La solution Moba Certify Pro a obtenu en 2023 la première labellisation européenne pour le diagnostic batterie des voitures électriques, remise par la Car Association Remarketing Europe, l’association qui regroupe les principaux acteurs du remarketing automobile en Europe.", "siren": "850032491"}, {"name": "FLYING WHALES", "description": "FLYING WHALES est une société française créée en 2012 pour concevoir, produire, commercialiser et opérer des dirigeables charges lourdes (« LCA60T »). La solution développée par l’entreprise de transport contribue au développement économique des territoires enclavés et à la réduction de l’impact environnemental du transport cargo.", "siren": "788658946"}, {"name": "Patrowl", "description": "Patrowl développe une solution de cybersécurité pour les entreprises offrant une évaluation en continu et en permanence de tous leurs composants ou systèmes exposés sur internet.", "siren": "883168403"}, {"name": "Rayon", "description": "Rayon développe un logiciel collaboratif de conception assistée par ordinateur à destination des professionnels de l’architecture, de la construction et de l’immobilier.", "siren": "903538403"}, {"name": "Cintoo", "description": "Cintoo est une scale-up française développant une plateforme SaaS permettant de gérer et distribuer les données de Reality Capture (scanners laser 3D, drones, images panoramiques 360°) en les transformant en surfaces 3D visualisables dans un simple browser Web ou des plateformes de réalité virtuelle. La plateforme permet également la visualisation de modèles 3D BIM et de Jumeaux Numériques pour de nombreux cas d’usage pour les secteurs de la Construction, du Manufacturing et de l’Energie.", "siren": "794581223"}, {"name": "Teem Photonics", "description": "Teem Photonics développe des solutions photoniques intégrées et des lasers pour ses partenaires OEM, alliant fonctionnalité avancée, robustesse, abordabilité et volume. Basée près de Grenoble, la société emploie 50 experts, couvrant la R&D, la fabrication et la fourniture mondiale à l’industrie.", "siren": "399229434"}, {"name": "SPIMED-AI", "description": "Développement et commercialisation de logiciels (imagerie médicale), algorithmes et services informatiques dans le domaine de la santé ainsi que le développement de sites internet ou d’applications mobiles dans le domaine du bien-être et de la santé.", "siren": "853720696"}, {"name": "MORFO", "description": "MORFO restaure à grande échelle les écosystèmes forestiers tropicaux en utilisant des technologies avancées comme les drones et l’IA. Ses innovations permettent d’optimiser la reforestation de précision, tout en intégrant la biodiversité, les communautés locales, et des solutions industrielles durables.", "siren": "899640502"}, {"name": "WaltR", "description": "WaltR est une spin-off de l’Agence spatiale française (CNES) fondée en 2018 à Toulouse et également présente à Nantes et Paris. WaltR accompagne les entreprises et acteurs publics dans leur transition écologique en fournissant des données fiables pour maîtriser les émissions polluantes. En conciliant performance économique et responsabilité environnementale, WaltR transforme les contraintes réglementaires et économiques en leviers d’innovation", "siren": "838887263"}, {"name": "BIODEVAS LABORATOIRES", "description": "La société BIODEVAS Laboratoires a pour cœur de métier la formulation et la fabrication de solutions phytogéniques, composées d’actifs naturels, pour améliorer la rentabilité des exploitations agricoles tout en diminuant l’utilisation d’intrants chimiques.", "siren": "481637726"}, {"name": "Soleo Eco-Solutions", "description": "Start-up issue de la recherche publique, SOLEO ECO-SOLUTIONS développe des solutions écologiques, à base de substances naturelles, contre les fourmis coupeuses de feuille et les termites. Ces insectes constituent les principaux ravageurs des cultures et des exploitations forestières en zone tropicale.\nEn Guadeloupe et en Guyane aucune solution n’est aujourd’hui disponible.", "siren": "823567714"}, {"name": "TENEVIA", "description": "Spécialiste de l’information environnementale numérique, TENEVIA développe et propose des solutions novatrices pour la Mesure, la Surveillance et la Prévision. Ces principaux domaines d’activités sont les Risques Naturels (crues, chute de blocs, …), Energies Renouvelables (Hydroélectricité, Photovoltaïque) et Ressources naturelles (Gestion de l’eau).", "siren": "751982455"}, {"name": "MASCARA NOUVELLES \nTECHNOLOGIES", "description": "Recherche développement, fabrication, installation et opération maintenance d’équipements de dessalement solaire membranaire d’eau salée ou insalubre avec :\n• une gamme d’unités de dessalement solaire d’eau de mer de 1 m³/jr à 300 m³/jr;\n• une gamme d’unités de dessalement solaire d’eau saumâtre de 10 à 50 m³/jr.", "siren": "800480683"}, {"name": "Odit-e", "description": "Odit-e, jeune entreprise innovante créée en juillet 2017, propose aux Gestionnaires de Réseaux de Distribution des solutions innovantes pour mieux prévoir l’impact de productions intermittentes et de nouveaux raccordements sur leurs réseaux et optimiser leurs investissements", "siren": "830800199"}, {"name": "TIAMAT", "description": "TIAMAT conçoit, développe et fabrique des batteries à charge ultra-rapide (quelques minutes) et à longue durée de vie (plusieurs milliers de cycles). La technologie de rupture utilisée pour développer ces batteries de puissance est la technologie sodium-ion, industrialisable rapidement car le sodium-ion est compatible avec les usines existantes et en construction.", "siren": "831726245"}, {"name": "TRISKEM INTERNATIONAL", "description": "TrisKem, entreprise de 15 salariés, recherche, développe et produit des résines hautement sélectives permettant de rendre les procédés de séparation chimique à la fois plus précis et plus efficaces que les méthodes traditionnellement utilisées.\nTrisKem vend ses résines dans une soixantaine de pays dans le monde.", "siren": "493848972"}, {"name": "Botify", "description": "Créée en 2010 et basée à Paris, Botify a profondément modifié les paradigmes et l’état de l’art du SEO (Search Engine Optimisation) depuis le lancement de son offre en 2013.", "siren": "519350813"}, {"name": "Pricemoov", "description": "Pricemoov propose une solution SaaS de tarification dynamique multisectorielle permettant d’aider les entreprises à perfectionner leurs prix en fonction de plusieurs critères dont la demande, la catégorisation des clients et le contexte d’achat. Utilisant de l’IA, la solution de tarification dynamique en temps réel permet aux sociétés de maximiser leurs revenus.", "siren": "818856619"}, {"name": "Sidetrade", "description": "Nos efforts en R&D ces 3 dernières années (développement d’un lab de Data Science, investissement dans 2 start-ups à la pointe de l’Intelligence Artificielle, lancement de Sidetrade Payment Intelligence solution) nous permettent de proposer aujourd’hui de nouvelles solutions qui couvrent l’ensemble du cycle client, depuis le lead jusqu’au paiement des factures. Avec un objectif unique : aider les Directions Marketing, Commerciales et Financières à développer le Chiffre d’Affaires et accélérer la génération de cash.", "siren": "430007252"}, {"name": "TrustBK", "description": "Margo Bank commercialisera, début 2019, un nouvel établissement bancaire au service des petites et moyennes entreprises pour répondre à leurs attentes et leurs besoins. Margo Bank veut proposer une offre de paiement et de dépôt et de crédit conçue sur mesure pour les PME.", "siren": "829226760"}, {"name": "Pherecydes Pharma", "description": "Fondée en décembre 2006, Pherecydes Pharma est la première PME française de biotechnologie qui se soit concentrée sur le développement de la phagothérapie, l’approche aujourd’hui la plus prometteuse et la plus fiable pour faire face à l’antibiorésistance.", "siren": "493252266"}, {"name": "ALSID", "description": "La société ALSID développe une solution novatrice totalement différenciante sur le marché de l’Active Directory visant à protéger les architectures d’annuaire.\nLa solution s’adresse à une population de décideurs : la complexité technique des systèmes sous-jacents est abstraite et synthétisée sous forme de tableaux de bord et de scores clairs.", "siren": "820862340"}, {"name": "Prove & Run", "description": "Prove & Run a pour mission d’aider ses clients à répondre aux problèmes de cybersécurité liés à l’usage à grande échelle des appareils connectés et au déploiement de l’Internet des objets. Avec ses briques logicielles de haute sécurité elle protège les objets connectés contre les cyberattaques à distance.", "siren": "514510783"}, {"name": "EXPLISEAT SAS", "description": "Expliseat a conçu le premier siège d’avion certifié avec une structure en composite. Deux à trois fois plus léger que ses concurrents, son siège permet aux compagnies aériennes d’économiser du carburant, de transporter plus de passager et de réduire leurs émissions de CO2.", "siren": "531208734"}, {"name": "VULOG", "description": "Vulog est actuellement le leader mondial indépendant des solutions technologiques de mobilité partagée.\nVulog fournit une plateforme SaaS (Software-as-a-Service) offrant des services innovants d’autopartage, en free-floating, de station à station ou en boucle, aux opérateurs de mobilité.", "siren": "490533528"}, {"name": "ALPINOV  X", "description": "La société ALPINOV X développe des générateurs de froid à haute performance énergétique destinés aux segments de marché du froid entre -20 et +20°C, et plus particulièrement le refroidissement des Datacenter et les réseaux de froid urbain.", "siren": "828812735"}, {"name": "SAVE INNOVATIONS", "description": "L’objectif de la société SAVE INNOVATIONS est la conception, le développement, la fabrication et la commercialisation de turbines innovantes qui produisent de l’électricité dès de faibles flux d’eau avec un prélèvement minimal de pression. Cette innovation permet d’alimenter en autonomie et en tout point des réseaux d’eau potable l’ensemble des équipements de mesure, de contrôle et de télétransmission.", "siren": "789078870"}, {"name": "DELTALYS", "description": "Deltalys participe à la transition vers une industrie décarbonée en développant des éco-procédés et solutions innovantes basées sur la revalorisation de sous-produits en fin de vie sourcés localement dans une logique d’économie circulaire intégrée. Ces solutions trouvent notamment des applications dans le domaine de la filtration/purification des gaz et biogaz.", "siren": "801564238"}, {"name": "ECODROP", "description": "Ecodrop est une solution simple, économique, et éco-responsable pour les déchets des artisans du bâtiment. Au moyen d’une application digitale, les artisans peuvent soit se rendre dans une déchèterie partenaire à moins de 10 kms de leur chantier, à prix négociés, soit se faire collecter directement sur chantier, dans les 2 heures.", "siren": "822408175"}, {"name": "MODETIC", "description": null, "siren": "498845064"}, {"name": "URBAN ECO SCOP", "description": null, "siren": "538701020"}, {"name": "Exotrail", "description": "Exotrail est une start-up développant des solutions d’opération et de propulsion électrique à destination du marché des petits satellites afin d’améliorer leurs performances.", "siren": "831241179"}, {"name": "Acklio", "description": "Acklio fournit des solutions logicielles pour activer n’importe quel réseau LPWAN avec IP (LoRaWAN, Sigfox, NB-IoT, ...). Elles offrent une interopérabilité native, une intégration simple et universelle et une sécurité de bout en bout. S’appuyant sur 20 ans de recherches protocoles, architecture et sécurité des réseaux, Acklio offre la première implémentation industrielle du nouveau standard de compression pour LPWAN.", "siren": "819345042"}, {"name": "Alkemics", "description": "Alkemics, start-up française créée en 2011, propose le premier réseau de collaboration digitale de la grande consommation. La plateforme Alkemics est la brique collaborative qui aide marques, distributeurs et solutions métier à digitaliser, collecter et partager l’ensemble de leurs données produites, en un seul lieu sécurisé.", "siren": "535078190"}, {"name": "Tempow – Tap Sound System", "description": "Tap Sound System, dit « Tempow », est une société spécialisée dans l’amélioration du protocole Bluetooth. L’ambition de Tempow est de devenir le leader mondial des solutions logicielles pour le Bluetooth, et de fournir toutes les entreprises utilisant un composant Bluetooth.", "siren": "818339566"}, {"name": "SMOME", "description": "• Conception numérique et fabrication industrialisées d’éléments bois massifs et bois lamellé-collé (BLC) constituant des composants (panneaux, planchers, lisses, poteaux) standardisés qui assemblés forment des constructions de type maison, collectif, tertiaire, entrepôt, extension, surélévation, véranda, piscine.\n• Commercialisation par la concession de licences de fabrication et de commercialisation.", "siren": "831287628"}, {"name": "Rheonova", "description": "Rheonova ambitionne de rendre la rhéologie accessible, à travers une activité d’analyses et de conseils scientifiques, et la conception de dispositifs de mesure innovants centrés sur les besoins des utilisateurs. Acteur disruptif en rhéométrie, Rheonova conçoit des rhéomètres dédiés aux fluides biologiques, et s’adressant particulièrement aux maladies respiratoires chroniques", "siren": "803705342"}, {"name": "Unis C", "description": "Unis C est spécialisée depuis 3 ans dans l’accessibilité pour les personnes à mobilité réduite. L’entreprise a mis en place la plateforme Picto Acces, une plateforme collaborative permettant aux utilisateurs de noter l’accessibilité de lieux d’intérêt. En parallèle, la plateforme permet aux entreprises de valoriser et d’améliorer leur accessibilité.", "siren": "813987534"}, {"name": "PLANT ADVANCED TECHNOLOGIES (PAT)", "description": "Développer des substances naturelles végétales capables de se substituer aux herbicides de synthèse", "siren": "483047866"}, {"name": "ZOO TECHNIC Group Elastoteck", "description": "Solution environnementale de gestion du stress bactériologique et thermique de la vache laitière", "siren": "753130921"}, {"name": "LODIAG", "description": "L’activité de LODIAG repose sur le développement d’outils innovants d’intelligence artificielle et de traitement de données dans le domaine de l’environnement et des sciences de la vie. Les nouvelles biotechnologies sont à l’origine de quantités d’informations sous-exploitées. Les progrès dans l’intelligence artificielle rendent possible l’investigation des mégadonnées par des approches non-supervisées.", "siren": "522782481"}, {"name": "GEOLITH", "description": "Le coeur de l’activité de GeoLith est la fourniture de technologies innovantes de production de lithium basées sur un matériau absorbant sélectif constitué de microfibres, développées en partenariat avec des centres de recherche de Paris-Saclay.", "siren": "810876177"}, {"name": "ENWIRES", "description": "ENWIRES est une entreprise industrielle, qui développe, fabrique et commercialise des matériaux à base de nanofils de silicium pour les batteries lithium-ion de prochaine génération afin d’accélérer l’acceptation des véhicules électriques. Ces matériaux fournissent une charge rapide et une autonomie plus importante.", "siren": "793002908"}, {"name": "Solar Cloth System", "description": "SolarCloth développe des textiles photovoltaïques (PV) légers, flexibles, enroulables, facile à transporter et à mettre en oeuvre. Les textiles PV de SolarCloth proposent notamment des solutions face au stress climatique et en particulier pour l’agriculture protégée en zone aride à fort ensoleillement. Ils répondent également aux besoins énergétiques de la mobilité et des structures porteuses légères.", "siren": "809273329"}, {"name": "AKRYVIA", "description": "AKRYVIA est une jeune entreprise innovante industrielle qui développe un procédé de découpe automatique des métaux ayant la précision du laser avec les avantages de productivité et de coûts du plasma. Cette rupture majeure délivre des gains majeurs de performance simultanément sur les critères de qualité, productivité et coût, en s’appuyant sur une innovation brevetée dans l’intensification extrême des jets plasmas fruit de 15 années de recherche académique et industrielle.", "siren": "813819414"}, {"name": "Deep Algo", "description": "Deep Algo est une startup française qui développe un logiciel d’analyse des codes sources des entreprises pour les rendre explicables et auditables par des experts métiers, répondant ainsi à l’accroissement des besoins de transparence et de sécurité des algorithmes informatiques.", "siren": "822060810"}, {"name": "Glose SAS", "description": "Glose est à la fois une librairie de livres numériques, un écosystème pour annoter et surligner ses lectures, un site de partage et d’échanges autour des lectures permettant la lecture de groupe. Nous avons développé un moteur de traitement du langage naturel transformant des formats de document classique en expérience de lecture (annotable, partageable, interactifs, etc.).", "siren": "798135489"}, {"name": "SAS Pikcio Services", "description": "Pikcio propose un écosystème autour des données personnelles, composé à la fois d’une application utilisateurs et d’une plateforme B2B, liées par la PikcioChain et le PikcioPass, en conformité avec GDPR.\nPikcio redonne ainsi contrôle et confiance dans les échanges de données numériques et les valorise.", "siren": "803767375"}, {"name": "BIROTA", "description": "BIROTA est une startup innovante qui développe, commercialise et opère le service de vélos électriques partagés Zoov. Le service Zoov est une offre de mobilité sous le modèle du MaaS (Mobilité as a Service) qui allie rapidité et fiabilité pour les utilisateurs, tout en s’intégrant avec bienveillance dans l’espace public.", "siren": "832111967"}, {"name": "D-ICE Engineering", "description": "D-ICE est une deeptech développant des solutions de rupture pour la digitalisation, la simulation, la conduite, l’optimisation et l’autonomisation des opérations marines et des navires. Grâce à son excellence scientifique et technique, la société fournit des services pour les industries Maritimes, Offshores, des Energies Marines Renouvelables et du Nautisme.", "siren": "814888798"}, {"name": "Green Communications", "description": "Communiquer sans contraintes est la devise principale de Green Communications. La société commercialise sa technologie Green PI qui permet de créer à la demande une infrastructure Internet mobile avec des applications et des services embarqués (voix, vidéo, chat, partage de fichiers, etc.) pour communiquer en toute autonomie.", "siren": "833737653"}, {"name": "GREEN SPOT TECHNOLOGIES", "description": "Développer les procédés permettant de produire des farines alimentaires et des aliments spécifiques à partir des coproduits de raisins et de betteraves", "siren": "842237786"}, {"name": "ZERO GACHIS", "description": "Zéro-Gâchis est une jeune entreprise française spécialisée dans la recherche et le développement d’outils informatiques à destination des grandes surfaces alimentaires.", "siren": "750444697"}, {"name": "COMERSO", "description": "COMERSO fournit des solutions numériques qui permettent de lutter contre le gaspillage en favorisant les synergies et connexions entre les entreprises soumises aux problématiques d’invendus et l’écosystème de récepteurs. Ces solutions permettent d’identifier l’invendu et de le rediriger vers la bonne filière (déstockage interne, filières de valorisation, dons).", "siren": "798075628"}, {"name": "NÉOLITHE", "description": "Néolithe développe un procédé de traitement des déchets non-recyclables en granulats minéraux utilisables dans le BTP, notamment en sous-couche routière. Néolithe cherche à proposer une troisième voie pour le traitement de ces déchets non-recyclables, actuellement enfouis ou incinérés, en proposant une valorisation matière des déchets à 100%.", "siren": "847631207"}, {"name": "POLY TO POLY", "description": "Poly to Poly est spécialiste de la recherche, de l’analyse et de la vente de polymères recyclés. Son laboratoire garantit la qualité de ses produits et assure une progression de la filière dans la recherche sur les polymères recyclés. La société développe une plateforme digitale afin de fluidifier les échanges au sein de la filière.", "siren": "842895559"}, {"name": "SOLZERO", "description": "SolZero développe deux activités : du conseil pour la mise en place de systèmes de réemploi (choix des contenants les plus adaptés, modalités du retour en point de vente, du passage en caisse, communication aux consommateurs) et du service industriel et logistique de nettoyage des contenants (transport et lavage dans des centres de traitement répartis sur le territoire pour une plus grande proximité et pour mutualiser les outils entre plusieurs acteurs).", "siren": "850728239"}, {"name": "Absolut System SAS", "description": "Absolut System définit, conçoit et réalise des systèmes cryogéniques principalement pour les domaines du spatial, de la recherche... La maitrise de la cryogénie (machines cryogéniques, cryostats…) est aujourd’hui nécessaire à de nombreuses technologies en expansion comme la supraconductivité qui nécessite des températures de fonctionnement entre – 250 °C à\n– 200 °C.", "siren": "521646216"}, {"name": "SODITECH", "description": "SODITECH est une entreprise spécialisée dans l’optimisation du rapport coût fiabilité de la conception à la fabrication de sous-ensembles mécaniques, thermiques et électroniques dans les domaines à forte contraintes. Depuis 1990 SODITECH propose aux grands industriels une offre pour prendre en charge les projets à partir des spécifications jusqu’à l’intégration.", "siren": "403798168"}, {"name": "SARL DRACULA Technologies", "description": "DRACULA Technologies est une start-up « Deep Tech » créée en décembre 2011 qui conçoit, développe et fabrique des dispositifs Photovoltaïques Organique par Inkjet. Sa mission est d’assurer l’approvisionnement énergétique des IoT et Tags RFID dans leur situation d’utilisation quotidienne en produisant à façon la technologie LAYER®.", "siren": "538758236"}, {"name": "365Talents", "description": "365Talents est une plateforme qui s’appuie sur l’intelligence artificielle pour révolutionner le Talent Management. Grâce à de puissants algorithmes de Machine Learning et de traitement automatique des langues, la plateforme révèle en temps réel les compétences des collaborateurs et leur suggère automatiquement des opportunités d’évolution professionnelle.", "siren": "812215804"}, {"name": "United Visual Researchers", "description": "Dans le contexte innovant de la Conception de l’Apparence Assistée par Ordinateur (CA2O), United Visual Researchers propose l’ensemble des outils nécessaires à la génération d’images de synthèse « Iso-Photographique », c’est-à-dire indiscernables d’une photographie prise au même moment dans les mêmes conditions.", "siren": "831248380"}, {"name": "ESTHESIX", "description": "PANDA Guide est une start-up francilienne portant un concept de rupture : la réalité augmentée pour les personnes déficientes visuelles. La mission de PANDA Guide est de s’attaquer au manque d’autonomie des personnes déficientes visuelles en considérant ce handicap comme un levier d’innovation pour le développement de nouvelles technologies accessibles.", "siren": "827599226"}, {"name": "BOIS LIGNOROC", "description": "L’entreprise Constructions Composites Bois commercialise la technologie LIGNOROC béton de bois sous la forme de panneaux préfabriqués de murs ou planchers pour la construction. Les bâtiments construits avec LIGNOROC offrent des avantages techniques tels que l’inertie et la régulation hygrométrique et présentent un faible impact carbone.", "siren": "891703654"}, {"name": "HYPNO VR", "description": "HYPNOVR est une MedTech strasbourgeoise créée en 2016, spécialisée dans le développement de dispositifs médicaux dédiés à l’hypnose médicale. L’entreprise s’appuie sur des expertises médicales et informatiques pour développer des solutions non médicamenteuses de contrôle de la douleur et de l’anxiété basées sur l’utilisation de la réalité virtuelle.", "siren": "823512561"}, {"name": "WECO", "description": "WeCo est une entreprise qui conçoit et commercialise les premières toilettes à chasse d’eau écologiques, autonomes et design grâce à un système innovant de sédimentation et de dégradation des effluents, suivi par une électrolyse et un filtrage des eaux usées, donnant une eau traitée claire, inodore et réutilisable pour les chasses d’eau.", "siren": "805375821"}, {"name": "Dry4Good (LGD)", "description": "Grâce à une technologie innovante, Dry4Good déshydrate les aliments en conservant au maximum leurs qualités organoleptiques et fonctionnelles, offrant une qualité inégalée des produits finis. Notre offre s'adresse aux professionnels de l'alimentation, industriels et indépendants, soucieux de remettre la naturalité des ingrédients au coeur de leurs procédés de fabrication.", "siren": "851016329"}, {"name": "IADYS", "description": "IADYS est une jeune entreprise innovante qui conçoit, développe et commercialise des solutions innovantes à la croisée de l’Intelligence Artificielle et de la robotique.\nIADYS révolutionne la réalisation de missions environnementales complexes ou récurrentes en diminuant les ressources nécessaires, les coûts d’exploitation, les risques d’exposition et leur impact écologique.", "siren": "822704532"}, {"name": "TELLUX", "description": "Tellux développe une  gamme  de  produits  adaptés  au  marché  de la dépollution. Aujourd’hui, la technologie HSL permet d’analyser ponctuellement en laboratoire des échantillons de sols. Demain, un modèle miniaturisé et embarqué permettra de suivre en temps réel l’état de la pollution et des déchets reçus en décharge ou dans les rejets des usines Seveso.", "siren": "878185735"}, {"name": "PLENESYS", "description": "PLENESYS est une startup deeptech travaillant sur des technologies plasma haute température innovantes. PLENESYS développe des torches plasma triphasées à fonctionnement continu destinées aux industries des procédés ainsi qu’un nouveau procédé de production d’hydrogène décarboné basé sur sa torche plasma propriétaire.", "siren": "840607279"}, {"name": "PowerUp", "description": "PowerUp conçoit, développe et commercialise des solutions de diagnostic, de gestion et de supervision de parcs de batteries, pour permettre d’exploiter les batteries au maximum de leur potentiel dans différentes conditions d’usage.", "siren": "829235928"}, {"name": "Roseau Technologies", "description": "Roseau Technologies développe pour ses clients, les acteurs du secteur de la distribution d’électricité, des logiciels d’études techniques. Elle dispose d’un double savoir-faire en ingénierie des réseaux électriques et en ingénierie logicielle, couplé à une forte expertise dans le domaine des réseaux électriques intelligents (“smart grids”).", "siren": "843752437"}, {"name": "ENOVASENSE", "description": "Enovasense conçoit et développe une technologie innovante de contrôle de l'épaisseur de tous types de revêtements industriels (peintures, polymères, organiques, céramiques, métalliques, vernis, colles...) sur tous types de substrats. Le procédé par laser, permet une mesure ponctuelle rapide, sans contact avec la pièce à mesurer et non destructive.", "siren": "791516578"}, {"name": "BeeBryte S.A.S.", "description": "BeeBryte est un fournisseur de solutions d’intelligence énergétique pour les bâtiments tertiaires et industriels. La société a développé un logiciel- service (SaaS) avec une infrastructure IoT permettant de réduire les fac- tures d’électricité jusqu’à 40% en contrôlant en temps réel les systèmes de chauffage, climatisation, ventilation et réfrigération.", "siren": "815290333"}, {"name": "Kemica Coatings", "description": "Fabrication et vente de résines d’étanchéité, de revêtement de sols et de protection anti corrosion pour le bâtiment, le génie civil, les industries, le secteur nucléaire et le secteur maritime/offshore", "siren": "513785923"}, {"name": "LINAGORA", "description": "LINAGORA est un éditeur innovant de Logiciels Libres. Notre mission est de permettre aux grandes organisations publiques ou privées de développer leur indépendance technologique. Nos solutions de collaboration, respectueuses de la confidentialité des données, sont aujourd’hui largement adoptées et sont la troisième voie numérique face aux GAFAM et aux BATX.", "siren": "431473669"}, {"name": "VeriQloud", "description": "VeriQloud est une entreprise spécialisée dans les architectures, les logiciels et les applications pour la communication quantique. Nous développons des solutions permettant de déployer des architectures de communication quantique à de petites échelles. Cet « ethernet quantique » permet d’apporter les avantages de la cybersécurité quantique à de petites échelles.", "siren": "829924638"}, {"name": "VSM Sa", "description": "La société VSM, spécialiste depuis plus de 30 ans dans le domaine de la simulation pilotée temps réel et acteur depuis plus de 6 ans sur le secteur de la formation des personnels en soute dispose non seulement des compétences pour réfléchir à un tel sujet dans le cadre d’un projet de Recherche & Développement, mais aussi du soutien opérationnel indispensable de ses partenaires et clients comme la Sécurité Civile via l’ECASC de VALABRE et ses partenaires, la Gendarmerie, les services héliportés du SAMU, ou les services concernés de l’Assistance Publique des Hôpitaux de Marseille (APHM).", "siren": "343698106"}, {"name": "WOMED", "description": "La mission de Womed est d'aider les femmes à améliorer leur fertilité et à se soigner en protégeant et réparant l’utérus. La société développe deux dispositifs médicaux innovants : un pansement qui empêche les fausses couches suite à une intervention chirurgicale, et un autre pour stopper les saignements utérins.", "siren": "837961978"}, {"name": "Openairlines", "description": "La mission d’OpenAirlines est d’accélérer la transition vers un transport aérien durable grâce au numérique.\nOpenAirlines développe des logiciels innovants, basés sur le Big Data et l’IA pour optimiser les opérations des compagnies aériennes et notamment réduire leur consommation de carburant et leur empreinte environnementale.", "siren": "493038707"}, {"name": "FERLAM TECHNOLOGIES", "description": "FERLAM TECHNOLOGIES conçoit, fabrique et commercialise des solutions textiles techniques résistantes aux fortes températures et/ou aux flammes afin de protéger les personnes, les produits et les process. L’expérience métier de l’entreprise lui permet de proposer 600 références (bandes transporteuses, fils, tresses, feutres aiguilletés) particulièrement recherchées dans le monde industriel (12 industries).", "siren": "412160871"}, {"name": "FLODIM", "description": "FLODIM développe des services en cavités souterraines, en géothermie profonde et en abandon de puits. FLODIM articule ses efforts sur la maitrise des techniques opérationnelles, sur de solides compétences R&D et sur une présence commerciale directe ou transférée. FLODIM anticipe, conçoit, développe des suites d’instruments adaptées aux nouvelles configurations industrielles", "siren": "399286020"}, {"name": "Amiral Technologies", "description": "La solution DiagFit pour la prédiction à l’aveugle de pannes d’équipements industriels d’Amiral Technologies a été adoubée par la communauté Deeptech (I-lab 2019, sélection NETVA) et les industriels (Thales, Daher, Valéo, etc.)\nLe projet P2_AI4 vise à augmenter le périmètre d’application par l’augmentation de sa capabilité algorithmique, de ses fonctionnalités et de ses modalités de déploiement. Ceci afin de répondre aux attentes d’un marché plus vaste.", "siren": "839798451"}, {"name": "ARSKAN", "description": "ARSKAN développe des technologies disruptives de compression progressive permettant la visualisation des données 3D massives sur le web, en mobilité et sans contraintes de serveurs externes et de bande passante. ARSKAN permet d’exploiter ces données 3D en jumeau numérique interactif et collaboratif et d’y connecter tous types de données.", "siren": "824251565"}, {"name": "Blockchain Certified Data", "description": "BCDiploma est une application blockchain SaaS B2B commercialisée depuis 2019, permettant d’émettre tout type de document probant sous un format 100% numérique et sécurisé, accessible d’un simple clic : diplômes, attestations de formation et de compétences, certificats ISO.\nSoutenue par Microsoft, l’application compte 71 clients répartis sur 13 pays de 4 continents.", "siren": "833138951"}, {"name": "METAVERSE TECHNOLOGIES France", "description": "METAVERSE TECHNOLOGIES France est une PME française créé en 2017 et spécialisée dans le développement de solutions logicielles innovantes en mode SAS facilitant l’utilisation de la conception assistée par ordinateur (CAO) collaboratives au profit d’utilisateurs de modèles 3D issus de différents outils dans les secteurs des nouvelles technologies et/ou de l’industrie.", "siren": "827545740"}, {"name": "Combo solutions", "description": "Combo solutions ambitionne de devenir le leader européen de la mesure et du pilotage de l’empreinte carbone des bâtiments. Combo développe depuis 2017 Vizcab, sa suite de logiciels Saas qui permet aux acteurs de l’ingénierie de catalyser la transition carbone de leurs projets immobiliers grâce aux data sciences.", "siren": "811426584"}, {"name": "CONSTRUCTION 3D", "description": "Fabrication et ventre d’imprimante 3D pour bâtiment", "siren": "831687009"}, {"name": "Inovadea", "description": "Inovadea est focalisée sur les solutions et services qui sont en cours de tests d’évaluation à partir de d’équipements tiers pour réaliser les cahiers de charges, développer et faire produire les solutions du projet SPEED. Déterminer les expertises techniques et technologiques essentielles liées à la croissance future de l’activité.", "siren": "749891974"}, {"name": "Terria", "description": "Fabricant de produits destinés au chauffage, au refroidissement, à la ventilation et à la production d’eau chaude sanitaire, pour la maison individuelle, en neuf et en rénovation, sur la base d’une énergie 100% renouvelable, le granulé de bois", "siren": "821912359"}, {"name": "AnthroPi", "description": "AnthroPi est une société spécialisée dans la fourniture de solutions technologiques innovantes et d’intelligence artificielle pour l’amélioration de la communication téléphonique dans la gestion des situations d’urgences et de crise.\nCentre de formation reconnu internationalement grâce à son simulateur SimulPhone, AnthroPi développe également des applicatifs d’analyses cognitives et conversationnelles.", "siren": "833685480"}, {"name": "Avatar medical", "description": "AVATAR MEDICAL développe et commercialise des solutions logicielles qui améliorent la préparation chirurgicale à l'aide d'images médicales en réalité virtuelle (VR) qu’elle commercialise en Europe et aux Etats-Unis. Notre technologie crée instantanément des représentations 3D interactives de patients à partir d'images médicales standard (IRM, CT-Scan).", "siren": "885007112"}, {"name": "CryptoNext", "description": "L'ordinateur quantique remet en cause la sécurité des infrastructures informatiques reposant sur les algorithmes de cryptographie à clé publique (https, VPN, paiement, blockchain, signature...). CryptoNext Security apporte une solution à cette menace avec une librairie de cryptographie résistante au quantique, hybride, s’intégrant facilement à des environnements logiciels et matériels variés.", "siren": "851589770"}, {"name": "Dreamquark", "description": "L’IA peut être lente, déroutante et coûteuse. Dreamquark a développé « Brain », qui permet aux banquiers privés de prendre des décisions hyper-personnalisées, simplement et rapidement. « Brain » permet d’accroître la valeur grâce à ses prédictions intelligentes et transparentes et une intégration sans contrainte.", "siren": "801145210"}, {"name": "HY GENERATION", "description": "Hy Generation, conçoit, développe et industrialise les premiers propulseurs électriques pour bateaux, fabriqués en France. De conception totalement innovante, ces propulseurs apportent de nombreux avantages aux utilisateurs tout en permettant de développer une industrie nouvelle en France.", "siren": "750158339"}, {"name": "Keen eye technologies", "description": "Keen Eye Technologies est une jeune société française qui développe des outils d’analyse pour faciliter et accélérer le travail des pathologistes et biologistes. Grâce à l’intelligence artificielle et au Deep Learning, ils améliorent l’analyse de images biomédicales en termes de qualité, de reproductibilité, de standardisation et de gain de temps.", "siren": "793725045"}, {"name": "Mazedia", "description": "Mazedia est une entreprise qui conçoit et réalise des dispositifs digitaux pour la médiation culturelle (musées, sites patrimoniaux). Mazedia est éditeur de la suite logicielle Wezit, qui apporte le socle technique pour la production de différents dispositifs interactifs. Cette solution est commercialisée à l’international.", "siren": "397978560"}, {"name": "MYCOPHYTO", "description": "AgTech est spécialisée dans la production et la formulation de produits à base de champignons mycorhiziens arbusculaires indigènes afin d’augmenter la productivité et la qualité des cultures, réduire leurs impacts environnementaux et les rendre plus résistantes aux stress biotiques et abiotiques afin de permettre une transition agro-environnementale.", "siren": "832815948"}, {"name": "NEOTRUCKS", "description": "Neotrucks développe une nouvelle gamme d’engins spéciaux issus du rétrofit afin de donner une seconde vie à des poids lourds routiers et proposer des solutions connexes innovantes comme des stations de charges utilisant des panneaux photovoltaïques.", "siren": "892458308"}, {"name": "OCCIDEV", "description": "Occidev recherche, étudie, conçoit, développe et commercialise des produits et services dans le domaine de l'ingénierie des systèmes numériques et informatiques. Notre entreprise propose des solutions afférentes à l'économie circulaire permettant de supprimer ou diminuer l’impact environnemental des solutions usuelles.", "siren": "893924977"}, {"name": "Oncodiag", "description": "OncoDiag a pour activité le développement et la commercialisation de tests non invasifs de diagnostic, de surveillance des récidives et de dépistage des cancers. La société s’est focalisée sur le cancer de la vessie, le cancer de la prostate et le cancer colorectal.", "siren": "794025932"}, {"name": "SCIBIDS TECHNOLOGY", "description": "Scibids propose aux acheteurs média (“trading desks”) une intelligence artificielle pour opérer et optimiser en autonomie les campagnes programmatiques. La technologie s’appuie en particulier sur des méthodologies de pricing d’une impression publicitaire à la pointe de l’état de l’art et du machine learning large scale.", "siren": "822771309"}, {"name": "TaxyMatch", "description": "TaxyMatch développe des algorithmes pour que des passagers qui ne se connaissent pas mais qui effectuent un trajet similaire, puissent partager un taxi / vtc. TaxyMatch réalise le transport avec ses chauffeurs et propose aussi via une «de programmation d'application », sa technologie de «-sharing» à des plateformes de taxis, vtc ou MaaS.", "siren": "840599070"}, {"name": "UWINLOC", "description": "UWINLOC conçoit des solutions innovantes de traçabilité d’objets à base d’étiquettes sans pile ni batterie, à destination d’entreprises de tous secteurs. Cette solution leur permet notamment d’augmenter leur efficacité métier tout en réduisant leur empreinte environnementale.", "siren": "814529368"}, {"name": "wAys", "description": "Ways a pour objectif de développer et protéger toutes marques, brevets et process industriels destinés à structurer la filière bois d'oeuvre autour des plus hauts standards de qualité d'un bois sec et/ou quasi sec. Ways conçoit, fabrique, vend ou loue, installe, répare et assure la maintenance de systèmes de séchage de bois.", "siren": "811609916"}, {"name": "Elzeard", "description": "Elzeard développe une application numérique Web & mobile à destination des agriculteurs, en France ou à l’international, pour optimiser la planification des cultures diversifiées et soutenir leur transition vers une agriculture plus résiliente. Ces solutions sont développées avec un ensemble de partenaires académiques et du secteur agricole.", "siren": "847718129"}, {"name": "MUANCE", "description": "MUANCE ambitionne d’industrialiser la construction de l’habitat social grâce à une méthode industrielle de construction modulaire 3D préfabriquée dite « hors site ». Chaque étape de conception est repensée, optimisée et le choix des matériaux axé sur la proximité. Ainsi, par la construction rapide d’habitats durables, abordables et évolutifs, les acteurs du logement social sont accompagnés.", "siren": "889698007"}, {"name": "Cardiawave", "description": "Pour traiter la sténose aortique, Cardiawave a développé un dispositif médical non invasif, guidé par l'image échographique en temps réel et par un robot. Il utilise une technologie ultrasonore de pointe qui consiste à réparer la valve aortique, et non à la remplacer.", "siren": "805240108"}, {"name": "MinMaxMedical", "description": "L’activité de MMM est, depuis sa création en 2008, entièrement dédiée au développement de nouveaux concepts et technologies supportant l’introduction de dispositifs particulièrement innovants, sur les marchés connexes de la robotique chirurgicale et des interventions médicales assistées par ordinateur (CAO).", "siren": "508333101"}, {"name": "Actronika", "description": "Actronika est une société développant et commercialisant avec ses clients des produits basés sur sa technologie haptique vibrotactile, pour amener de l’haptique de haute définition dans les produits d’innovation. Elle collabore avec de grandes entreprises sur les marchés automobile, téléphonie mobile, du jeux-vidéo, de la réalité virtuelle et du bien-être.", "siren": "803040138"}, {"name": "Heex Technologies", "description": "Heex Technologies propose des services de gestion de données pertinentes pour les systèmes autonomes. Avec une approche innovante et une plateforme simple, nous augmentons la productivité des équipes développements en ciblant puis en automatisant l’extraction de données nécessaires à l’amélioration de l’apprentissage et du monitoring de produits et services s’appuyant sur un niveau avancé d’intelligence artificielle.", "siren": "849073812"}, {"name": "LOGIROAD", "description": "LOGIROAD accompagne les collectivités locales dans la gestion patrimoniale de leurs infrastructures routières au moyen d'une gamme de logiciels innovants basés sur l’intelligence artificielle et s’appuyant sur une expertise métier issue d’une collaboration de plus de 2 décennies avec l’UGE (Université Gustave Eiffel), ex IFSTTAR.", "siren": "753050038"}, {"name": "Atelier Daruma", "description": "Atelier Daruma est un studio d’innovation parisien spécialisé dans les narrations immersives. À la frontière du Cinéma, du Théâtre et du Jeu Vidéo, l'Atelier explore le potentiel des formes émergentes d’image à travers la réalisation d'ambitieuses expériences multi-sensorielles.", "siren": "837591742"}, {"name": "Heuritech", "description": "Par les images des réseaux sociaux et des sites e-commerce (neuf et seconde main), Heuritech, quantifie les tendances futures et met à disposition des marques, une plateforme tout-en-un leur permettant d’ajuster leurs collections à la demande future, pour améliorer leur profitabilité et réduire leurs invendus.", "siren": "794196055"}, {"name": "STAGE 11", "description": "Stage 11 rassemble les dernières technologies issues du jeu vidéo, du machine learning, de la capture de mouvement, de la réalité augmentée, de la blockchain et de l’intelligence artificielle pour mettre sur le marché une plateforme intégrée offrant de nouvelles expériences immersives et interactives pour le public et les artistes.\nNous rassemblons les dernières technologies issues du jeu vidéo, du machine learning, de la capture de mouvement, de la réalité augmentée, de la blockchain et de l’IA pour mettre sur le marché une plateforme intégrée offrant de nouvelles expériences immersives et interactives pour le public et les artistes.\nUne partie de nos travaux vise à permettre la production et la diffusion de captations « live » sur de multiples canaux visibles par des millions de spectateurs-acteurs en simultané.", "siren": "890762750"}, {"name": "R&D VISION", "description": "R&D Vision, PME Française créée en 2002 conçoit, fabrique et industrialise des solutions innovantes intégrant technologies optiques et Intelligence Artificielle : systèmes embarqués, machines spéciales et bancs d’essais. Les thématiques abordées concernent toutes les industries et sont variées : 3D, métrologie laser, détection de défauts, temps réel, thermographie IR, …", "siren": "440955300"}, {"name": "Trees-Everywhere", "description": "Trees-Everywhere offre aujourd’hui aux entreprises souhaitant axer leur démarche RSE vers la compensation carbone des solutions de captation de carbone et de restauration de la biodiversité par le biais de projets de reforestation dense sur des terrains en friche ou pollués, par l’intermédiaire des collectivités.", "siren": "883005407"}, {"name": "Genesis", "description": "Première agence de notation des sols agricoles au monde", "siren": "880025051"}, {"name": "NOVAQUARK", "description": "Pépite des scènes technologiques et culturelles françaises, Novaquark est un pionnier du métavers depuis 2014, qui développe les technologies les plus avancées mondialement dans ce domaine. Ces dernières sont les fondements du premier jeu développé par la société, « Dual Universe ».", "siren": "799791926"}, {"name": "Emerwall", "description": "Emerwall fabrique et commercialise un isolant thermique et acoustique à base de bagasse de canne à sucre. Les produits sont développés pour correspondre aux contraintes climatiques locales à partir d’un\n« déchet » issu de l’industrie martiniquaise.", "siren": "897956876"}, {"name": "NRGYBox", "description": "NRGYBOX propose une solution innovante de pilotage de l’éclairage public adaptée à la fréquentation des rues. La solution NRGYBox permet de maintenir une ambiance lumineuse pour faire des économies d’énergie sans sacrifier le sentiment de sécurité des usagers.", "siren": "878782440"}, {"name": "ZIWIG", "description": "ZIWIG ambitionne de révolutionner le diagnostic, la prise en charge et le suivi des pathologies féminines, en alliant deux innovations de rupture : le séquençage nouvelle génération et l’intelligence artificielle. ZIWIG est l’inventeur du premier test salivaire de diagnostic de l’endométriose au monde, dont l’efficacité est cliniquement prouvée.", "siren": "848079075"}, {"name": "PHOST’IN THERAPEUTICS", "description": "Issu de plus de 10 ans de travaux académiques, Phost’in Therapeutics a l’ambition de développer des traitements de rupture pour les patients atteints de cancers agressifs et autres maladies graves. En 2022, nous débutons le premier essai clinique du PhOx430, avec une demande d’autorisation déposée fin 2021.\nPour la 1ère fois, les effets d’un inhibiteur sélectif de N-glycosylation vont être évalués en clinique. Le résultat ouvrira de nouvelles voies pour le traitement des tumeurs solides, notamment pour des cancers sans solutions thérapeutiques. Cette étape doit imposer Phost’in Therapeutics comme leader incontesté des glyco-immuno-thérapies à l’échelle internationale.", "siren": "808490619"}, {"name": "Perha Pharmaceuticals", "description": "Perha Pharmaceuticals optimise et développe des petites molécules inspirées de molécules marines, pour corriger les déficits cognitifs des personnes atteintes de trisomie 21 et de maladie d’Alzheimer, prévenir les pertes auditives et traiter la polykystose rénale. Cette société de biotechnologies est située à Roscoff, dans le Finistère.", "siren": "850455429"}, {"name": "Healthy Mind", "description": "Healthy Mind est une entreprise spécialisée dans le développement de dispositifs médicaux innovants (DTx). Elle commercialise depuis 2018 un logiciel dispositif médical de classe I marqué CE, Healthy Mind VR,qui combine les neurosciences, l'hypnose médicale et l’immersion en réalité virtuelle pour réduire la douleur et l'anxiété des patients à l’hôpital.", "siren": "833226608"}, {"name": "SKAIROS", "description": "L’activité de SKAIROS repose sur l’ambition de porter les premiers jumeaux numériques du rachis vers les industriels, les organismes de régulation et les cliniciens, et apporter un service global d’accompagnement depuis la phase prémarket jusqu’à à l’exploitation en clinique pour l’aide à la planification de chirurgie et à l’évaluation post market.", "siren": "851456392"}, {"name": "Okomera", "description": "Issue de l’Ecole polytechnique et de l’Institut Pasteur, Okomera vise à améliorer le traitement personnalisé du cancer. La technologie d’Okomera permet de tester les cellules d’une biopsie sur place, facilement, en quelques jours seulement, pour prédire la réponse du patient aux différentes options de traitements, et sélectionner la meilleure.", "siren": "884940024"}, {"name": "AKANTHAS", "description": "Akanthas est une startup toulousaine portée par la conviction que 100% des déchets du secteur industriel et de la construction sont valorisables en agissant à la source. Pour cela, la startup développe des outils propulsés par l’IA pour optimiser la gestion des déchets professionnels et permettre aux matières recyclées, remployées et réutilisées de devenir compétitives.", "siren": "898606744"}, {"name": "DIAMSENS", "description": "DIAMSENS développe, fabrique et commercialise des capteurs électrochimiques à base d’électrodes en diamant pour le contrôle in-situ de la qualité de l’eau. Le diamant est le matériau le plus durable et DIAMSENS sait le rendre autonettoyant. Son prix devient enfin abordable, même pour les contrôles non réglementés.", "siren": "911925006"}, {"name": "Nothing2Install", "description": "Nothing2install est une startup créée fin 2018 et basée à Marseille développant et commercialisant des solutions technologiques innovantes permettant d’offrir l’accès à distance instantané et sécurisé à tout type d’applications. Elle mène des activités de R&D structurées par une équipe de spécialistes et soutenue par plusieurs organismes publics et privés", "siren": "843699273"}, {"name": "Velco SAS", "description": "Velco fournit des solutions connectées pour les vélos électriques. Grâce à la connectivité, nous améliorons l’expérience de mobilité de l’utilisateur final et nous augmentons les performances et les marges des professionnels de la mobilité (fabricants de vélos et gestionnaires de flottes). La mission de Velco est de transformer la mobilité urbaine pour un développement durable. Nous favorisons la pratique de modes de transport durables grâce à la connectivité.", "siren": "819556168"}, {"name": "IOT Symphony", "description": "Notre entreprise développe depuis 2019 Octavio, une marque audio souhaitant réconcilier le grand public et le monde de l’audio Haute-Fidélité pour redécouvrir sa musique à la maison, au plus proche des enregistrements studio.\nNous proposons ainsi des systèmes audios reposant sur des technologies de reproduction sans perte, design, accessibles et fabriqués en France.", "siren": "878303403"}, {"name": "Hoffmann Green Cement Technologies", "description": "La raison d’être d’Hoffmann Green est d’agir sur le climat et l’environnement autrement et dès maintenant, en concevant et produisant des ciments décarbonés 0% clinker, à faible consommation énergétique. Grâce à ces solutions innovantes, les acteurs de la construction peuvent réduire significativement leur empreinte carbone afin de créer les villes durables de demain.", "siren": "809705304"}, {"name": "IQSPOT", "description": "En s’appuyant sur la technologie IOT, iQspot développe et commercialise une solution logicielle de relève automatique et d’analyse en temps réel des consommations fluides (énergie et eau) et d’indicateurs de conforts (température, CO2, humidité) des bâtiments tertiaires.", "siren": "809096043"}, {"name": "GANYMED ROBOTICS", "description": "Spécialisé dans le développement d’outils de vision par ordinateur et de mécatronique avancée, GANYMED ROBOTICS développe un robot d’assistance chirurgicale en orthopédie disruptif. La première indication visée est la pose de prothèses totales de genou, une intervention en forte augmentation, soumise à de fortes pressions de fiabilisation et de maîtrise des coûts.", "siren": "840634356"}, {"name": "Swallis Medical", "description": "Swallis Médical est une start-up spécialisée dans les dispositifs médicaux connectés de diagnostic et de prise en charge de la dysphagie (troubles de la déglutition). Son premier produit, le Swallis DSATM (Device for Swallowing Analysis) est un collier qui détecte et mesure les signaux de l’activité pharyngolaryngée (de la gorge).", "siren": "848039004"}, {"name": "SAS Open Stent Solution", "description": "Open Stent Solution développe des solutions de remplacement valvulaires cardiaques peu invasives basées sur un concept révolutionnaire qui est le Ruban Valvé.\nOpen Stent Solution développe une solution thérapeutique universelle de remplacement valvulaire mitral percutané. Cette solution a pour objectif de faire face à l’attente de 2.5 millions de patients, rien qu’en Europe et aux Etats-Unis, qui sont atteints d’insuffisance mitrale et qui voient leur pronostic vital mis en jeu car non-éligibles aux thérapies actuelles.", "siren": "842621096"}, {"name": "Sensome", "description": "Sensome, startup deeptech fondée en 2014 (CNRS/École polytechnique), développe des capteurs d'impédance couplés à des algorithmes d’apprentissage machine pour identifier la nature biologique des tissus en temps réel. Le premier dispositif médical est un guide neurovasculaire connecté qui aidera les médecins lors du traitement d’un accident vasculaire cérébral (AVC) ischémique.", "siren": "801623596"}, {"name": "PILI", "description": "Pili développe des couleurs écologiques issues de biomasse française non-alimentaire pour décarboner l’industrie européenne et réduire la dépendance au pétrole. \nCréée en 2015 avec la volonté d’apporter une alternative écologique aux colorants et pigments fossiles très polluants, PILI a pour mission de décarboner l’industrie de la couleur qui est responsable de l’émission de plus de 200 millions de tonnes de CO2 chaque année, soit l’équivalent de 5% des émissions européennes.", "siren": "811524545"}, {"name": "Tree Water SAS", "description": "Electrotate développe un procédé d’électro-oxydation innovant pour le traitement et le recyclage des effluents industriels. \nDepuis 2017, Treewater développe et fabrique des procédés d’oxydation avancée innovants pour le traitement et de recyclage des effluents industriels. Tous les projets de l’entreprise reposent sur une démarche en trois étapes : Etude/ pilote/installation, qui permet d’optimiser les performances du procédé et d’en limiter les coûts.", "siren": "828379636"}, {"name": "YOUWOL", "description": "YouWol fournit un accélérateur d’innovation en géosciences sous la forme d’un espace de travail en ligne avec outils pour une transition énergétique efficiente. \nYouWol est une entreprise internationale de type SAAS (software as a service) qui développe des solutions numériques en ligne et des services associés pour les ingénieurs, chercheurs, enseignants et étudiants dans le domaine des géosciences.", "siren": "853059376"}, {"name": "DIGDASH", "description": "Digdash permet aux utilisateurs métiers de générer des tableaux de bord depuis une interface conversationnelle (IA) et de tirer profit de l’open data sans la moindre connaissance technique ou informatique. \nDigDash, expert de la Business Intelligence, est un éditeur français d’une solution de tableaux de bord dynamiques ; une plateforme nouvelle génération qui permet à ses utilisateurs d’explorer, visualiser et communiquer facilement sur leurs données. Ce logiciel s’adresse à toutes tailles d’entreprises, tous secteurs et tous métiers.", "siren": "492291455"}, {"name": "SeaBeLife", "description": "SeaBeLife développe une approche thérapeutique unique pour préserver la vue et limiter la perte de vision dans des pathologies oculaires comme l’Atrophie Géographique ; une forme sévère de la DMLA-sèche et la première cause mondiale de cécité. \nSeaBeLife est une société de biotechnologie spécialisée dans le développement de molécules first-in-class basées sur une technologie brevetée et un mécanisme d’action unique qui bloque directement et simultanément deux voies de mort cellulaire régulée. SeaBeLife développe un portefeuille de candidats adressant des pathologies aigues et chroniques et présentant un fort besoin médical.", "siren": "849445192"}, {"name": "O-Kidia", "description": "Combinant une IA biomédicale multimodale, et connaissances cliniques, O-Kidia crée des métriques plus objectives et systématisées d’évaluation des troubles du neurodéveloppement et de santé mentale associés, chez les enfants et les adolescents, facilitant ainsi grâce à la plateforme, Spectrum Mind®, le parcours patient comme la pratique des professionnels de santé. \nO-Kidia ambitionne d’appréhender le neurodéveloppement grâce une IA biomédicale multimodale et les connaissances cliniques.", "siren": "909581340"}, {"name": "WALTERRE", "description": "WaltApp développe une plateforme digitale métier destinée à l’amélioration et au suivi des systèmes de Chauffage, Ventilation, Climatisation (CVC) pour tous les acteurs du bâtiment. \nWalterre est une société spécialisée dans l’efficacité énergétique des systèmes du bâtiment. Walterre expertise les installations CVC (Chauffage Ventilation, Climatisation), dresse des plans de progrès technique et améliore la performance des installations suivies d’au moins 10% (à confort égal).", "siren": "848343927"}, {"name": "Kleep", "description": "Fondée en 2021, Kleep est une société émergente de l’IA générative au service du e-commerce. En développant des solutions technologiques B2B, sa mission est d’accompagner les e-commerçants à réduire le nombre d’articles qui leur sont retournés et ainsi retrouver une activité e-commerce plus rentable et plus durable.", "siren": "904780335"}, {"name": "Braindex", "description": "Braindex développe un dispositif de surveillance cérébrale au bloc opératoire permettant d’administrer la juste dose de produits anesthésiques à chaque patient opéré, en vue de prévenir les complications associées aux sur- et sous-dosages médicamenteux.", "siren": "820676583"}, {"name": "ARCHEON MEDICAL", "description": "Archeon Medical développe des technologies 100% made in France pour aider les équipes soignantes à mieux ventiler les patients en situation d’urgence vitale. Notre mission est de rendre accessible au plus grand nombre de professionnels de santé des technologies de pointe pour améliorer la prise en charge des patients.", "siren": "835009465"}, {"name": "BLUENAV", "description": "Aller vers une navigation plus respectueuse et moins impactante sur la biodiversité par le développement de : \n- Turbines « rim-drive » add-on de 8, 15 et 30kW, entièrement repensées à partir des Rex de la première génération : \n- Whale design (hydrodynamique et biomimétisme) \n- Contrarotatives (optimisation du rendement) \n- Cost of ownership (Maintenance et réparabilité) \n- Utilisation des GNSS HP, de la vision électronique, \n- du partage de données, de l’IA et du machine learning pour accompagner les changements de comportement des utilisateurs : \n- Gestion de l’évitement automatique \n- Ancrage virtuel sans impact sur les fonds marin \n- Docking assisté \n- Eco-pilotage prédictif \n- Pilotage autonome", "siren": "881583850"}, {"name": "DXOMARK Image Labs", "description": "Depuis 15 ans, les scores DXOMARK, reconnu par l’industrie, reflètent les performances des appareils et la qualité de l’expérience utilisateur dans les scenarios du quotidien. Tous nos tests sont réalisés dans des conditions et des environnements variés afin de refléter l’usage réel.", "siren": "821245503"}, {"name": "iDAKTO", "description": "Créée en 2019, iDAKTO fournit aux états et aux entreprises des solutions de pointe en matière de gestion des identités numériques de niveau élevé, assurant des parcours utilisateurs simples dans la création et dans l’usage de l’identité numérique. \niDAKTO est le partenaire technologique de France Identité Numérique, et déploie sa solution à l’international, pour des gouvernements et des grandes organisations publiques et privées.", "siren": "851352823"}, {"name": "Snowpack", "description": "Depuis son lancement en 2021, Snowpack a réussi à démontrer le potentiel de l’invisibilité réseau pour la cybersécurité comme l’atteste notamment l’obtention en 2024 des deux meilleurs prix d’innovation cyber nationaux (Forum InCyber et Assises de la cybersécurité) remis par des jurys composés pour moitié de RSSI d’opérateurs d’infrastructures critiques de tous secteurs.", "siren": "900526716"}, {"name": "OMINI", "description": "OMINI développe la première plateforme de tests sanguins multiplex adaptée à la gestion personnalisée des maladies complexes. La plateforme repose sur des biocapteurs brevetés. Elle combine un dispositif de lecture portable avec des bandelettes de test multiplex pouvant mesurer simultanément plusieurs biomarqueurs sanguins à partir d’une goutte de sang.", "siren": "847931318"}, {"name": "Ariana Pharmaceuticals", "description": "Ariana Pharmaceuticals a été fondée en 2003, spin off de l’Institut Pasteur, pour développer des systèmes d’aide à la décision thérapeutique basés sur l’IA. \nAriana accompagne ses partenaires (principalement des entreprises pharmaceutiques et biotechnologiques) introduisent la médecine personnalisée dans la conception de leurs essais cliniques et protocoles par l’analyse de leur données complexes, afin d’optimiser les endpoints cliniques, d’identifier les biomarqueurs de réponse thérapeutique et les thérapies synergiques potentielles", "siren": "449727205"}, {"name": "La Tannerie Végétale", "description": "La Tannerie Végétale accompagne la filière cuir dans sa transition circulaire grâce à Phyli, une matière souple 100% naturelle, recyclable et compostable. \nL’activité se centre aujourd’hui sur le développement et la production de prototypes de Phyli avec les acteurs du luxe. Phyli doit répondre aux exigences techniques et sensorielles du haut de gamme tout en ayant une empreinte carbone 12 fois inférieure à celle du cuir.", "siren": "887887636"}, {"name": "Clever Cloud", "description": "Clever Cloud édite un service de Platform as a Service (PaaS) basé en Europe. Son objectif est d’aider les équipes de développement à mettre en production des applications et des services numériques sur une infrastructure fiable, scalable, sécurisée et avec une tarification transparente.", "siren": "524172699"}, {"name": "PRIVACY CHAMBERS", "description": "La société développe une plateforme de données destinée aux établissements de santé, qui centralise, sécurise et valorise les données hospitalières. Elle optimise ainsi leur exploitation tout en assurant une conformité réglementaire rigoureuse. Sa solution transforme les données en leviers stratégiques pour améliorer la qualité des soins et accélérer la recherche.", "siren": "891329351"}, {"name": "The Cross Product", "description": "The Cross Product est une deeptech proposant des logiciels de traitement automatique de données Lidar 3D d’infrastructures ferroviaires et autoroutières et de sites industriels. Les solutions développées permettent d’automatiser les inspections, inventaires, mesures et autres études spécifiques à partir d’un nuage de points 3D. La combinaison du Lidar 3D avec l’IA permet de réaliser ces traitements à grande échelle, de manière automatique, rapide et précise.", "siren": "895253276"}, {"name": "Cycle Farms", "description": "Cycle Farms est une société spécialisée dans l’alimentation animale issue de l’élevage d’insectes. Grâce à son centre de R&D français et son usine au Ghana, Cycle Farms commercialise ses produits auprès des pisciculteurs africains. En France, Cycle Farms propose de nouvelles technologies afin d’améliorer les rendements des productions d’insectes.", "siren": "818492639"}, {"name": "PERARD", "description": "Basée dans la Meuse à VERDUN, la société PERARD est une entreprise familiale de fabrication de matériel agricole. Elle propose une large gamme de produits dans le domaine du transport, de la récolte et de l’élevage à destination d’une agriculture de pointe soucieuse d’améliorer sa productivité en conservant sa qualité.", "siren": "409936309"}, {"name": "ARYBALLE Technologies", "description": "Le projet NeOse F3 (NEw Olfactory SEnsor applied to Fermentation Flavor & Food) a pour objectif de développer un capteur pour le contrôle objectif de l’odeur relative aux aliments fermentés. Il s’agit d’évaluer l’empreinte gazeuse, qui chez l’Homme est évaluée grâce a son espace olfactif retro- nasal.\nL’analyse réalisée par le capteur s’appuie sur des nanotechnologies, l’optiques et des algorithmes valorisant des bases de données spécifiques par process et/ou produit.", "siren": "800742405"}, {"name": "SEAVIEWS", "description": "SEAVIEWS est une PME spécialisée en cartographie sous-marine par méthode acoustique et par photogrammétrie. Les domaines d’actions de SEAVIEWS concernent principalement les habitats marins naturels et artificiels ainsi que les aménagements côtiers.", "siren": "809267578"}, {"name": "CYTHELIA ENERGY", "description": "Entreprise pionnière dans le secteur photovoltaïque depuis 1994, Cythelia Energy opère deux activités complémentaires, Bureau d’études et Editeur de logiciels (suite Archelios), en couvrant l’ensemble du cycle de vie des projets photovoltaïques.", "siren": "393290937"}, {"name": "DEEPKI", "description": "Deepki est une jeune entreprise de haute technologie, positionnée sur le marché de la Transition énergétique, qui utilise la puissance des statistiques et de leur analyse informatisée s’appuyant notamment sur des techniques d’apprentissage automatisé (machine learning) pour transformer les données existantes de ses clients en plan d’action d’Efficacité Énergétique.", "siren": "804763670"}, {"name": "Entech smart energies", "description": "ENTECH-SE développe et commercialise des solutions de gestion de l’énergie électrique basées sur les architectures de conversion et pilotage, grâce à ses activités de R&D de solutions d’électronique de puissance, d’électronique embarquée, de systèmes de supervision via le développement d’algorithmes et le dimensionnement énergétique lié aux smartgrids.", "siren": "818246316"}, {"name": "Voltinov", "description": "VOLTINOV possède une expertise dans les domaines du photovoltaïque tels que les procédés de fabrication, la caractérisation des composants, la conception de nouveaux produits.\nLa société développe également une activité de bureau d’étude et de conseil pour le développement technique et le montage de projets photovoltaïques.", "siren": "523571990"}, {"name": "H-PreC SAS", "description": "H-PreC fabrique des composites grâce à un procédé primé au JECWORLD2017. Les composites sont très demandés mais il faut optimiser leur fabrication pour rendre ces matériaux aussi compétitifs que les métaux. Fort de ce constat nous avons développé une technologie de rupture apportant une nouvelle génération de composites à l’industrie.", "siren": "813058070"}, {"name": "GO TOUCH VR", "description": "GO TOUCH VR propose des solutions et dispositifs haptiques (du toucher) pour des applications à la réalité virtuelle et à la réalité augmentée.\nGO TOUCH VR se concentre sur les secteurs de la formation, de l’ingénierie, du show casing et de l’interaction entre les données.", "siren": "828963710"}, {"name": "OWNEST SAS", "description": "Ownest propose une solution blockchain de transfert de responsabilité permettant de visualiser en temps réel les responsables des biens physiques sur tous les réseaux logistiques.\nCette solution se compose du moteur blockchain OWNEST, d’une Application mobile et d’un Dashboard de gestion et de suivi des produits.", "siren": "833796022"}, {"name": "SKILLUP (PLATEFORM SAS)", "description": "Skillup est une solution numérique innovante pour accélérer le développement des talents via la formation. Afin d’impliquer les collaborateurs, améliorer la qualité des formations proposées et simplifier la charge administrative des RH, Skillup a développé la première marketplace de formations professionnelles, adossée à des outils de gestion de la formation.", "siren": "820463750"}, {"name": "VEKIA", "description": "Start-up technologique française, VEKIA fournit des solutions logicielles pour la Supply Chain utilisant des algorithmes d’intelligence artificielle. Installées sur plus de 2500 sites en France et 70 pays dans le monde, les solutions VEKIA équipent des grandes enseignes (MR BRICOLAGE, BUT, OKAïDi, UNDIZ, RENAULT, ENGIE) pour l’optimisation des chaînes d’approvisionnement.", "siren": "503225716"}, {"name": "MagIA Diagnostics", "description": "La société MagIA Diagnostics propose un dispositif innovant d’analyse biologique portable. Grâce à sa technologie immuno-magnétique innovante, elle développe un dispositif dédié au dépistage simultané de multiples maladies infectieuses à partir d’une seule goutte de sang prélevé au bout du doigt en 15 minutes.", "siren": "831351796"}, {"name": "MilliDrop Instrument SAS", "description": "MilliDrop développe des instruments scientifiques pour la microbiologie. En utilisant la microfluidique, MilliDrop propose de cultiver les micro- organismes dans des réacteurs miniaturisés. Le débit d’analyse peut être multiplié par dix. Après validation de la technologie avec un produit pour la Recherche, MilliDrop va développer une solution de diagnostic in vitro.", "siren": "808749873"}, {"name": "MC2 Technologies", "description": "MC2-Technologies est spécialisée dans la caractérisation, modélisation et conception de composants et dispositifs hyperfréquences destinés aux applications civiles et militaires. En parallèle, l’entreprise propose et des systèmes plus complexes qui ont fait récemment sa notoriété, comme la caméra passive MM-Imager qui permet de détecter des objets cachés potentiellement dangereux.", "siren": "452386121"}, {"name": "Everysens SAS", "description": "Everysens se donne pour mission d’organiser la tranquillité logistique des chargeurs et autres utilisateurs de supply chain complexes. L’entreprise propose à ces acteurs industriels une solution logicielle dédiée et innovante de gestion de parc et de flux, en exploitant les technologies de l’Internet des objets et du Big Data.", "siren": "808684443"}, {"name": "UV BOOSTING", "description": "UV Boosting développe une solution de stimulation des défenses naturelles des plantes par flash UV. Fruits de cinq années de recherche, et ayant déjà démontré l’efficacité du procédé en conditions réelles, UV Boosting souhaite maintenant engager une phase de conception industrielle pour commercialiser ses produits d’ici 24 mois.", "siren": "824904569"}, {"name": "ALKION BIO INNOVATIONS", "description": "Le projet NeGenSweet, porté par la société Alkion Bio Innovations, vise le développement et la production d’additifs alimentaires végétaux dotés d’un pouvoir sucrant élevé pour les marchés de l’agroalimentaire. Ces additifs seront obtenus par stimulation des plantes en bioréacteurs, et leur production sera traçable par blockchain.", "siren": "828176784"}, {"name": "Linkednutri", "description": "Le projet vise à proposer un programme pour délivrer des compléments alimentaires sur-mesure à domicile à l’aide de la première technologie microfluidique grand public associée à un programme d’accompagnement personnalisé utilisant les dernières avancées de la recherche en micro nutrition et en intelligence artificielle.", "siren": "839647989"}, {"name": "Technologies de France", "description": "Technologiesde France, sociétés spécialisée dans l’ingénierie environnementale, développe des procédés dans les secteurs liés au développement durable, et plus particulièrement dans le recyclage.", "siren": "824767982"}, {"name": "TRYON", "description": "TRYON déploie une solution innovante de méthanisation à échelle locale pour valoriser les biodéchets de manière simple et économique. Locale car son dimensionnement est adapté à l’échelle d’un territoire. Simple et économique car l’installation est standard, modulaire, industrialisable et évolutive.", "siren": "810884668"}, {"name": "Intent – Drone Interactive", "description": "INTENT développe les premières attractions multijoueur associant pilotage de drones et jeux vidéo en réalité mixte pour les parcs de loisirs. L’objectif est d’offrir des expériences immersives et interactives révolutionnaires pour le grand public et des solutions clés en main avec un retour sur investissement élevé aux exploitants de parcs.", "siren": "834814394"}, {"name": "Mac-Lloyd", "description": "Mac-Lloyd est une entreprise innovante concevant des systèmes de tracking haute précision pour le sport professionnel. Leader sur le marché français, Mac-Lloyd ambitionne de devenir la référence mondiale et de révolutionner les usages de diffusion des données pour le sport en proposant des contenus immersifs de réalité virtuelle et augmentée.", "siren": "790862544"}, {"name": "SMART CAST", "description": "Smart Cast conçoit et fabrique un système novateur de panneaux coffrants permanents sur mesure pour la construction de bâtiments résidentiels (logements collectifs, Ehpads…).", "siren": "813547429"}, {"name": "OKEENEA", "description": "Acteur-clef de l’accessibilité en France depuis 25 ans, OKEENEA met aujourd’hui son expérience et ses compétences au service de la mobilité pour TOUS pour créer une ville plus INCLUSIVE.\nDans un milieu urbain toujours plus complexe, plus riche comptant près de 20 % de personnes handicapées, la mobilité est un enjeu clef pour les villes et ses acteurs. Comment guider, informer pour permettre à chacun de mieux vivre cet espace ?", "siren": "848981809"}, {"name": "Wheeliz", "description": "Notre activité consiste à mettre en relation les propriétaires de véhicules adaptés aux personnes en fauteuil roulant avec des locataires désireux d’effectuer un déplacement via une plateforme Internet.", "siren": "805383213"}, {"name": "EOLINK SAS", "description": "Eolink développe un concept innovant d’éolienne flottante. Son activité d’ingénierie est focalisée à 100% sur l’éolien flottant, allant jusqu’à l’industrialisation et le déploiement de parcs éoliens flottants. L’enjeu est le coût de production électrique, avec une cible à 50€/MWh après installation du premier GW.", "siren": "823946595"}, {"name": "SEREEMA SA", "description": "Sereema conçoit, réalise et commercialise des solutions d’optimisation du fonctionnement des installations de production d’énergie renouvelable en utilisant les technologies de l’Internet des Objets (IoT). Windfit, système de diagnostic connecté, est embarqué dans chaque éolienne. Il s’agit de la première application IoT entièrement conçue pour l’éolien.", "siren": "433386554"}, {"name": "ATEME", "description": "ATEME conçoit et commercialise des équipements et logiciels de compression vidéo à destination des opérateurs de télévision dans le monde entier : chaînes hertziennes, bouquets satellitaires, IPTV ou câble, ainsi que leurs sous-traitants dans l’acheminement des programmes.", "siren": "382231991"}, {"name": "bMotion Technologies", "description": "Développement de solutions technologiques musicales pour le bien-être, l’éducation et la santé.", "siren": "844691337"}, {"name": "MaaT Pharma", "description": "MaaT Pharma développe des médicaments innovants de correction des dysbioses, chez les patients exposés à des traitements lourds comme une chimiothérapie ; une antibiothérapie ; une immunothérapie ou encore une transplantation de cellules souches. Nous utilisons le principe du Transfert de Microbiote Fécal pour améliorer le pronostic de ces patients.", "siren": "808370100"}, {"name": "Smart Immune", "description": "Développement et validation d’une technologie de thymus ex vivo automatisé pouvant être utilisée et commercialisée pour produire les médicaments de biothérapies en Immuno-oncologie capitalisant sur le compartiment T (MTI Smart Immune, CAR T cell autologue ou allogénique, MTI de thérapie génique utilisant le compartiment T, Orchard, etc…).", "siren": "830784062"}, {"name": "TREEFROG THERAPEUTICS", "description": "TreeFrog Therapeutics (TFT) est une startup dans le domaine des cellules souches qui facilitera l’accès pour des millions de patients à la révolution médicale des thérapies cellulaires en résolvant les problèmes de production majeurs auxquels cette industrie fait face.", "siren": "844370320"}, {"name": "everysens", "description": "Everysens propose une plateforme SaaS collaborative, spécialisée dans la planification  prédictive  et  la  visibilité  en  temps  réel  du  transport de marchandises. Nous offrons une suite complète de fonctionnalités permettant d’automatiser les processus et d’optimiser l’utilisation des capacités de transport des acteurs de la supply chain ferroviaire et routière", "siren": "808684443"}, {"name": "NATURAL GRASS", "description": "Natural Grass développe des terrains de sport innovants de haut niveau à la fois performants, sûrs et durables. Après 4 ans de R&D, la technologie pelouse hybride AirFibr est mise sur le marché et Natural Grass devient un expert français des pelouses hybrides. L’entreprise a aujourd’hui équipé des terrains sur 4 continents et dans les plus grandes compétitions sportives mondiales.", "siren": "513852640"}, {"name": "ENOSIS", "description": "ENOSIS conçoit et commercialise des équipements de production de méthane synthétique, injectable dans les réseaux gaziers en substitution au gaz fossile. Basés sur le recyclage du CO2 par des micro-organismes, ces équipements permettent d’enrichir le biogaz en biométhane et de traiter les syngas produits par gazéification de matières de récupération.", "siren": "804578359"}, {"name": "Greenbig", "description": "GreenBig est une société développant des solutions innovantes qui répondent aux enjeux de l’économie circulaire. Après 3 ans de R&D, elle a conçu sa solution b:bot : à la fois une machine et un écosystème digital dédié à la collecte des bouteilles plastiques en PET qui trie et broie les bouteilles plastiques en début de chaîne simplifiant ainsi le recyclage.", "siren": "833953631"}, {"name": "HESUS", "description": "Experte en valorisation et dépollution des terres et déchets de chantier, HESUS propose une solution clé-en-main : fiable, au meilleur prix, garantissant la traçabilité et la conformité réglementaire.\nEngagée dans l’économie circulaire, sa plateforme numérique HESUS STORE centralise les besoins des chantiers pour fournir des terres et des matériaux recyclés.", "siren": "509101929"}, {"name": "KHEOOS", "description": "L’entreprise développe son activité autour de la gestion de pièces de maintenances. Elle propose la création et la gestion d’une plateforme web communautaire pour les sociétés industrielles. Cette plateforme permet l’achat, la revente et la remise en état en pièces de maintenance.", "siren": "838448181"}, {"name": "Cap Collectif", "description": "Pionnière des Civic-Tech françaises et actuel leader du marché, Cap Collectif occupe une place référente dans le domaine de la consultation publique numérique.", "siren": "803377571"}, {"name": "SAS Consilium", "description": "Les services proposés par CONSILIUM sont regroupés autour de 3 principaux groupes d’activités de prestations. Le cœur d’activité de la startup est le déploiement d’applications business distribuées sur la technologie NeuroChain (Licensing), premier blockchain scalable.  CONSILIUM propose également des accompagnements,  des  conseils  techniques et technologiques dans le développement d’applications basées sur NeuroChain et de façon plus générale en architecture Blockchain.", "siren": "840239271"}, {"name": "DAVI", "description": "DAVI édite RETORIK, la plateforme d’IA conversationnelle et émotionnelle dédiée  aux  agents  conversationnels  animés,  malins  et  sensibles. Notre mission : Humaniser la relation digitale.\nDAVI dispose de compétences en web sémantique (TALN, Deep Learning…) pour les domaines de l’IA, en ingénierie cognitive et dans le développement 3D pour le domaine de l’IHM.", "siren": "433940194"}, {"name": "BULANE", "description": "Bulane conçoit et fabrique des électrolyseurs hydrogène innovants permettant aux professionnels d’utiliser, dans leurs applications (soudage, brasage, chauffe, etc.), une flamme haute température sans bouteilles de gaz, sans émission de carbone et dans des conditions de sécurité optimale. Ayant fait ses preuves auprès de grands comptes industriels, et après plusieurs années de R&D, Bulane s’apprête à lancer la version mobile de sa technologie, à destination des artisans.", "siren": "509460325"}, {"name": "DeepOR S.A.S", "description": "DeepOR développe une Intelligence Artificielle vocale pour le monde de la santé. Intégrées au dossier patient informatisé (DPI), les solutions de DeepOR interprètent les questions et phrases du médecin et les transforment en données structurées.", "siren": "821875705"}, {"name": "LATTICE MEDICAL", "description": "LATTICE MEDICAL conçoit et développe des bioprothèses MATTISSE couplant implant résorbable avec une reconstruction tissulaire pour la reconstruction mammaire après mastectomie en alternative aux prothèses et techniques actuelles ne répondant pas aux besoins des médecins et des patientes. Ce dispositif médical permet également de réaliser des chirurgies d’augmentation mammaire esthétique.", "siren": "832698153"}, {"name": "MASTOR", "description": "MastOR, startup française d’innovation en robotique chirurgicale conçoit, fabrique et commercialise des robots de co-manipulation pour faciliter les gestes des chirurgiens et rendre la cœlioscopie plus accessible.", "siren": "851436188"}, {"name": "VIRTUALISURG", "description": "VirtualiSurg est une société spécialisée dans la production de simulateurs de chirurgie multi-sensoriels pour la formation des équipes médicales dans l’ensemble des disciplines médicales et chirurgicales. Les simulateurs de VirtualiSurg se caractérisent par une expérience immersive dans un bloc opératoire virtuel avec la manipulation physique des véritables équipements et instruments chirurgicaux.", "siren": "829843770"}, {"name": "COSMIAN TECH", "description": "COSMIAN met à profit les techniques cryptographiques les plus avancées pour développer des solutions logicielles B2B de sécurité des données pour entreprises. COSMIAN permet à de multiples entités (intra-entreprises ou entreprises différentes) de mutualiser leurs données sensibles, confidentielles afin d’exploiter les résultats de calculs collaboratifs – sans jamais accéder aux données sous-jacentes.", "siren": "840903447"}, {"name": "Watt&Well", "description": "Watt&Well est une PME spécialisée dans la conversion de puissance. L’expérience industrielle pour des applications exigeantes (pétrole et gaz, mobilité électrique, spatial), son succès commercial à l’export (filiale US depuis 2016), ainsi que l’expertise technologique de W&W l’ont conduit à se diversifier vers la mobilité depuis plusieurs années.", "siren": "501934939"}, {"name": "IDMOG", "description": "Avec FieldBox.ai, les industriels améliorent radicalement leur efficacité opérationnelle, grâce à l’Intelligence Artificielle (IA). La plateforme de FieldBox.ai permet de déployer l’IA au coeur des sites industriels. Ces IA optimisent en permanence et de façon autonome, le fonctionnement des machines et des opérations.", "siren": "529981318"}, {"name": "BIOSCO", "description": "BioSCO propose des outils d’aide à la décision destinés aux entreprises travaillant dans le secteur des agro-ressources. Les outils développés, utilisant des technologies avancées de recherche opérationnelle et d’intelligence artificielle, permettent à nos clients de simplifier la gestion de leur supply- chain pour la rendre plus agile et plus performante économiquement et écologiquement.", "siren": "824370399"}, {"name": "Green Impulse", "description": "GREEN IMPULSE est une start-up qui développe de nouvelles solutions innovantes pour l’agriculture. Elle possède une expertise technique et scientifique dans le domaine de la santé du végétale et s’appuie sur une Technologie Brevetée par l’Université d’Angers. GREEN IMPULSE s’engage dans le développement de bio-intrants agricoles innovants permettant de réduire l’usage des produits phytosanitaires conventionnels et ainsi stopper la dépendance de notre Agriculture aux pesticides", "siren": "847746997"}, {"name": "AUREA TECHNOLOGY", "description": "AUREA est une société Française de technologies innovantes spécialisée dans la conception et la fabrication d’instruments optiques hautes performances destinées aux applications quantiques. AUREA Technology est aujourd’hui un leader mondial dans la détection de photons uniques.", "siren": "524990942"}, {"name": "DAWEX", "description": "Dawex, leader technologique de plateforme d'échange de données et opérateur de la plus grande place de marché de données, permet aux entreprises et organisations d'orchestrer la circulation des données en sourçant, monétisant et échangeant des données en toute sécurité et dans le respect des réglementations en vigueur.", "siren": "810307207"}, {"name": "GRAPHEAL", "description": "Grapheal est une entreprise de dispositifs médicaux spécialisée dans la réalisation de biocapteurs souples et connectés pour un usage diagnostic sur le terrain. En essaimage du CNRS de Grenoble, elle valorise le savoir-faire technologique dans des matériaux d’électronique de nouvelle génération (graphène sur polymère).", "siren": "850364423"}, {"name": "GAUSSIN SA", "description": "GAUSSIN est une société d’engineering qui conçoit, assemble et commercialise des produits et services innovants dans le domaine du transport et de la logistique.\nSon savoir-faire englobe les transports de marchandises et de personnes, les technologies autonomes permettant un usage sans chauffeur, et l’intégration de tous les types de batteries, notamment électriques et hydrogènes.", "siren": "676250038"}, {"name": "vorteX.io", "description": "vorteX.io propose un service de prévention temps  réel  des  populations dans le cadre des risques inondations/ sécheresses, basé sur une nouvelle génération de solutions de télédétection intelligentes & innovantes.", "siren": "850904202"}, {"name": "Be Energy", "description": "Créée en Janvier 2014, Be Energy est issue de la volonté de développer des technologies de régénération afin de favoriser le réemploi plutôt que le recyclage des déchets industriels.", "siren": "799666367"}, {"name": "SDS logistique", "description": "Gestion spécifique de stockage, logistique, négoce et approvisionnement spécialisée dans la pièce détachée gros et petits électroménagers domestique pour toutes les marques.", "siren": "819218892"}, {"name": "CES WORKS", "description": "Son métier est l’innovation. CES WORKS réalise la recherche appliquée [RA] pour l’ensemble du groupe et pour des clients. Cette activité permet d’avoir une forte valorisation. Une fois un sujet issu de la RA et son marché analysé, la création d’une fille dédiée portera ce projet jusqu’à son industrialisation.", "siren": "853796779"}, {"name": "HOMIWOO", "description": "Homiwoo est une start-up spécialisée dans la donnée immobilière résidentielle. Nous utilisons les dernières techniques de Data Science (Machine Learning et Big Data) pour fournir à nos clients, une information immobilière résidentielle “fiable et pertinente”.", "siren": "829725498"}, {"name": "Visionairy", "description": "Visionairy transforme les usines grâce à l’intelligence artificielle. Nous accompagnons nos clients dans la transition vers une industrie plus intelligente et propre. Notre solution est un game-changer pour les industriels car elle rend possible l’automatisation de tâches visuelles complexes, insolvables pour les systèmes de vision classiques.", "siren": "838801876"}, {"name": "EQUIUM", "description": "EQUIUM développe des pompes à chaleur thermoacoustique 100% écologiques pour faire du froid à partir de chaleur fatale pour l’efficacité énergétique des systèmes ou de la chaleur HT (80°C) pour la rénovation énergétique des bâtiments.", "siren": "824867477"}, {"name": "SMARTCATCH", "description": "SmartCatch développe des dispositifs médicaux micro/nanotechnologiques s’apparentant à des outils de métrologie en oncologie. Son objectif est de mettre à disposition des centres de recherche clinique et des centres hospitaliers, des instruments de capture performants permettant d’utiliser les cellules tumorales circulantes comme marqueurs diagnostiques et pronostiques en routine clinique.", "siren": "822393013"}, {"name": "Emissive", "description": "Fondée en 2005, Emissive est un pionnier des expériences en réalité virtuelle. La société conçoit des installations immersives à destination des institutions culturelles et des marques pour impliquer physiquement et émotionnellement leurs publics.", "siren": "485080733"}, {"name": "Fairbrics SAS", "description": "L’industrie textile représente 10% des émissions mondiales de gaz à effet de serre. La mission de Fairbrics est de réduire son impact environnemental en utilisant le CO2 comme matière première au lieu de produits pétrosourcés.", "siren": "853194629"}, {"name": "France Autopartage", "description": "L’activité principale de France Autopartage est la fourniture de services (notamment marketing et informatique) auprès des opérateurs de service d’autopartage du réseau Citiz. Pour certains cas spécifiques, l'entreprise assure également la gestion en direct de services d’autopartage.", "siren": "441965043"}, {"name": "HOOMANO", "description": "Hoomano développe des technologies uniques d’interaction Homme-Machine, reposant sur l’engagement, l’émotion et l’apprentissage. Ses équipes de spécialistes en Intelligence Artificielle développent l’interface logicielle de référence dans le domaine des services à forte valeur interactive pour faciliter la relation entre les humains et les machines.", "siren": "808321814"}, {"name": "KAIKO", "description": "Kaiko est un agrégateur et distributeur de données de marché dans l'industrie des actifs numériques. Notre mission est de récupérer et organiser toutes les informations de marché des actifs numériques, les rendre accessibles et utilisables pour tous les acteurs du secteur Blockchain et financier.", "siren": "807388376"}, {"name": "Left Angle", "description": "LEFT ANGLE développe le logiciel Autograph, spécialisé dans la génération de vidéos et de graphismes animés adressés aux graphistes professionnels dit motion-designer. La technologie développée dans Autograph lui permet de fournir des fonctionnalités plus ergonomiques et plus productive permettant à l’artiste de se concentrer sur sa créativité.", "siren": "878675198"}, {"name": "Luos Robotics", "description": "Décentralisation, conteneurisation, agilité et outils pour systèmes embarqués", "siren": "840964902"}, {"name": "Neurallys", "description": "Neurallys est une start-up deeptech qui développe une solution unique pour améliorer le confort de vie des patients touchés par l’hydrocéphalie. L’objectif est de proposer une meilleure prise en charge de la maladie et de développer une médecine personnalisée pour restaurer une qualité de vie aux patients.", "siren": "818407959"}, {"name": "Nxo engineering", "description": "NXO Engineering oeuvre au développement de procédés innovants dans le secteur de l’eau. Elle conçoit des technologies disruptives telle la bioremédiation micro-algale pour l’assainissement collectif ou la potabilisation en conteneur pour l’aquaculture.", "siren": "823601778"}, {"name": "POPS France", "description": "POPS propose un service e-commerce d’impression et de livraison de produits photos 3D. Les utilisateurs sélectionnent leurs propres photos via les plateformes en ligne POPS (applications Smartphone et site internet) afin de les recevoir imprimées en 3D directement chez eux.", "siren": "789369220"}, {"name": "Seamless Waves", "description": "Seamless Waves est une société française localisée à Paris, spécialisée dans la conception et la réalisation d’une architecture innovante d’émetteurs-récepteurs Radio Fréquence (RF) reconfigurables, notamment pour les communications sans fil dédiées à la 5G et à l’internet des objets connectés (Internet of Things, IoT).", "siren": "823062609"}, {"name": "SUB C MARINE", "description": "SubC-Marine réalise des levés cartographiques par imagerie 3D et des inspections subaquatiques robotisés pour le génie civil et les dispositifs hydrauliques au service des grands donneurs d’ordre du secteur hydroélectrique français (EDF, CNR, VNF, SCP…) et permettant de répondre aux nouvelles exigences réglementaires de maintenance et de sécurité des ouvrages.", "siren": "453969065"}, {"name": "Ze energy", "description": "ZE Energy est la 1ère société à développer en France Métropolitaine un nouveau modèle d’actif de production électrique renouvelable hybride (couplage d’une centrale de production électrique photovoltaïque et d’un actif de stockage) ainsi qu’un système de gestion, de pilotage et d’optimisation de ces actifs hybrides en temps réel.\nZE Energy a pour objectif de développer une solution qui permet d’abaisser jusqu’à 30% la puissance de raccordement des centrales de production électrique hybrides (PV+ stockage) en comparaison aux centrales PV seules et de déplacer jusqu’à 15% de la production PV des heures méridiennes d’été, ceci réduisant le besoin de flexibilité dans les réseaux.", "siren": "852197763"}, {"name": "FEBUS Optics", "description": "La mission de FEBUS OPTICS est de fournir des solutions de détection par fibres optique hautes performances, économiques et robustes, faciles à installer et à utiliser. Les produits de FEBUS OPTICS permettent des prises de mesures acoustiques (DAS), thermiques (DTS, DSTS) et mécaniques (DTS, DSS, DSTS).", "siren": "811377613"}, {"name": "Pando2", "description": "PandO2 est une société éditrice d’un logiciel dédié à la supervision et gestion de la qualité de l’air. Une première application interopérable et paramétrable dont l’objectif est de garantir un air de qualité tout en participant à l’effort de transition énergétique par le pilotage efficient du bâtiment est développée.", "siren": "841677461"}, {"name": "UPCYCLEA SAS", "description": "UPCYCLEA a pour objet la conception, le développement et la commercialisation d’applications et de plateformes numériques pour accélérer la transition des entreprises et des territoires vers l’économie circulaire.", "siren": "820645091"}, {"name": "BHEALTHCARE", "description": "BHealthCare développe et commercialise des dispositif médicaux robotiques autonomes pour l’accès vasculaire.", "siren": "822241915"}, {"name": "FIBERMETRIX", "description": "Fibermetrix développe et commercialise des solutions autonomes et connectées de mesure des rayonnements dans le domaine médical et les environnements complexes. La gamme de produits et services proposés permettent d’améliorer la gestion des risques patients et travailleurs liés aux rayonnements ionisants.", "siren": "808239495"}, {"name": "DAREWISE ENTERTAINMENT", "description": "Darewise développe et édite des jeux-vidéos multijoueur en ligne. L’entreprise recherche et développe des technologies liées à la production de jeux-vidéos", "siren": "810907428"}, {"name": "Dark Matters Solutions", "description": "Dark Matters Solutions est une société spécialisée dans des procédés de tournages et des logiciels innovants qui révolutionne la production de contenus audiovisuels : la startup développe des studios et des services de production virtuels basés sur des murs LED pour la production de décors de tournage.", "siren": "893900647"}, {"name": "Infinite Square", "description": "Infinite Square est l’éditeur du logiciel inwink, plateforme SaaS de gestion d’événements BtoB présentiels et digitaux. inwink permet aux entreprises d’orchestrer leurs événements : depuis le Back-Office, jusqu’au site de l’événement, en permettant la récolte de l’ensemble des données événementielles en temps réel.", "siren": "521915637"}, {"name": "PICTIA", "description": "Pictia est une solution permettant la certification blockchain d’images, la vente de licences, la surveillance des utilisations frauduleuses, l’établissement de constats numériques, et la gestion de litige amiable.", "siren": "880152251"}, {"name": "Jimmy Energy", "description": "Jimmy met au point et exploite des générateurs thermiques industriels afin de fournir de la chaleur moins chère et décarbonée aux industriels. Les générateurs s’installent directement sur les installations thermiques des industriels et remplacent les bruleurs à énergies fossiles (charbon/gaz) traditionnellement utilisés.", "siren": "892884099"}, {"name": "OBIOSEED", "description": "OBIOSEED fabrique des produits d’hygiène et de désinfection, se situe dans le Var, et emploie plus de 50 personnes. Entreprise engagée dans la réduction de ses impacts environnementaux, elle est certifiée ISO 14001, et plus de la moitié de ses références sont certifiées par ECOCERT.", "siren": "842497612"}, {"name": "ORPIA Innovation", "description": "ORPIA Innovation conçoit de nouvelles molécules chimiques biosourcées et développe des procédés de production innovants répondant aux contraintes industrielles. Les solutions développées s’intègrent dans une chimie verte et durable en utilisant une matière première renouvelable issue de déchets de l'agriculture de l’anacardier (arbre fruitier de la noix de cajou) en Afrique.", "siren": "841538077"}, {"name": "ENTENT", "description": "ENTENT conçoit et développe des machines à cycle organique de Rankine de nouvelle génération qui valorisent les déchets thermiques basse température des industriels (60-150°C) en électricité, à partir d’une technologie de rupture brevetée, le PULSE. La société est train de développer son produit standard le PULSE50 qui produira 50kW.", "siren": "834504862"}, {"name": "Nimble One", "description": "Nimble One conçoit et commercialise Aru, un robot de service à l’attention des industriels et des universités. Aru est capable de répondre à de nombreux cas d’usages. Les premières ventes sont prévues 2023 avec une accélération en 2024. Aru est commercialisé par les équipes Nimble One et par l’intermédiaire d’un réseau d’intégrateurs grâce à une API de programmation afin de spécialiser Aru sur des cas d’applications spécifiques.", "siren": "892418708"}, {"name": "CGX AERO", "description": "Positionnée sur le domaine de l’information aéronautique et ses composantes dédiées aux aéroports et aux opérateurs de navigation aérienne, CGX AERO, entreprise française indépendante à fort potentiel de R&D et d’innovation, propose une offre de services et de produits experts s’inscrivant dans la dynamique des enjeux mondiaux du transport aérien ( AIM [Aeronautical Information management], Opérations aéroports, ETOD [Electronic Terrain Obstacle Data], Conception de trajectoires de vol aux instruments...).", "siren": "451998470"}, {"name": "Expéditions Spectacles", "description": "Expéditions Spectacles propose à travers la marque Sensory Odyssey un concept novateur d’expositions immersives et multisensorielles. Au croisement des sciences naturelles, des arts du spectacle et de l’innovation technologique. La marque incarne une nouvelle génération de divertissements qualitatifs, aux valeurs durables, qui fait écho aux enjeux environnementaux de notre époque.", "siren": "883293631"}, {"name": "COHESIVES", "description": "COHESIVES est une start-up dans la med-tech spécialisée dans le traitement des plaies. Depuis sa création, la société développe le premier véritable adhésif sur les tissus biologiques humides grâce à la technologie anCore. COHESIVES est une plateforme technologique qui a l’ambition de collaborer avec les acteurs majeurs du marché pour en assurer la commercialisation.", "siren": "807497771"}, {"name": "DAMAE Medical", "description": "DAMAE Medical réinvente l’imagerie de la peau et redéfinit ainsi le dépistage, la prise en charge et le suivi des cancers de la peau (mélanomes et carcinomes) grâce à sa solution deepLive™ qui permet un examen optique précis, rapide et fiable, sans faire de biopsie.", "siren": "804599710"}, {"name": "Basecamp Vascular", "description": "Basecamp Vascular – BCV développe une gamme innovante de dispositifs médicaux pour les thérapeutiques mini-invasives.\nEnjeu de santé publique majeur, l'AVC est la première cible du système Gecko. Cette solution active et robotisée est basée sur la technologie des Activateurs à Mémoire de Forme, technologie unique sur le marché. BCV est le premier acteur mondial à développer une solution de cathéters mécatroniques compatible avec des systèmes robotisés et un guidage imagerie temps-réel. Un premier essai clinique en 2022 a validé la sécurité du premier dispositif développé par BCV.", "siren": "819927179"}, {"name": "HDSI APPLICATION", "description": "HDSI Application développe des dispositifs médicaux d’aide au diagnostic de l'endométriose, certifiés CE, ainsi que des dispositifs de suivi et d'analyse hors des établissements de santé pour les femmes et une plateforme d’échange patiente médecin et solution de compte rendu assisté pour les médecins.", "siren": "839757333"}, {"name": "HEPHAISTOS-Pharma", "description": "HEPHAISTOS-Pharma est une société de biotechnologie qui développe la prochaine génération de traitements contre le cancer basés sur une stimulation du système immunitaire des patients. ONCO- Boost, le produit phare de la plateforme d’HEPHAISTOS-Pharma, permet de traiter les cancers sans option thérapeutique et d’augmenter l’efficacité des immunothérapies actuelles au-delà de 60-80%.", "siren": "840990402"}, {"name": "I.Ceram", "description": "Créée en 2005 à Limoges, I.Ceram développe et commercialise des implants en biocéramique se distinguant par une biocompatibilité unique. Elle est l’auteur de plusieurs premières mondiales, grâce notamment à la proposition d’implants sternaux chargés en antibiotique. I.Ceram est labellisée « entreprise innovante », certifiée ISO 13485 et ISO 14001.", "siren": "487597569"}, {"name": "Alice&Bob", "description": "Alice&Bob construise le premier ordinateur quantique universel et sans erreur pour résoudre certains des problèmes les plus difficiles à résoudre aujourd'hui. Notre technologie basée sur les qubits de chat autocorrecteurs apporte une solution au plus grand obstacle auquel sont confrontés les ordinateurs quantiques aujourd'hui : les erreurs de calcul.", "siren": "881729156"}, {"name": "Antescofo SAS", "description": "La société Antescofo est créée en 2016 comme spin-off de la recherche publique par trois chercheurs et un serial entrepreneur. Elle développe l’application mobile Metronaut qui accompagne et fait progresser les musiciens amateurs grâce à l’intelligence artificielle.", "siren": "821738515"}, {"name": "PERPETUAL EMOTION", "description": "Réseau social / métavers spécialisé dans l’évènementiel culturel", "siren": "834566580"}, {"name": "RebrAIn", "description": "RebrAIn est une startup (lauréate du concours i-Lab en 2021) qui développe des outils d’IA permettant d’identifier les zones cérébrales pour traiter chirurgicalement les patients présentant un tremblement essentiel sévère ou une maladie de Parkinson évoluée.", "siren": "892511866"}, {"name": "My Family Up", "description": "My Family Up se positionne aujourd’hui comme une référence en dématérialisation de la psychologie et des solutions d’accompagnement psycho-éducatives personnalisées, expertes et innovantes. Elle se place sur le marché de l’expertise psychologique numérique et sur le marché des simulateurs de comportement.", "siren": "803748730"}, {"name": "Therapanacea", "description": "TheraPanacea est une entreprise française HealthTech, spinoff de CentraleSupelec, qui utilise l’intelligence artificielle pour transformer la pratique de la médecine en développant des logiciels permettant d’optimiser les diagnostics, de pronostiquer les réactions aux traitements, et d’améliorer les thérapies contre le cancer (notamment via radiothérapie) ou certaines maladies neurologiques.\nL’ensemble des acteurs de l’industrie de la santé et plus particulièrement de l’oncologie se dirigent vers la « médecine de précision » : une médecine dans laquelle les parcours de soins sont différenciés pour chaque patient. L’approche holistique permise par l’intelligence artificielle ouvre la voie à une médecine réellement personnalisée.", "siren": "828335174"}, {"name": "NEWCLIP TECHNICS", "description": "Fondée en 2002, NEWCLIP TECHNICS, est un groupe industriel français du MedTech qui fabrique des dispositifs médicaux innovants (implants d'ostéosynthèse pour la chirurgie orthopédique et traumatologique). Les produits et services sont commercialisés dans 45 pays, grâce au réseau de distributeurs partenaires et filiales internationales en Europe, USA, Australie et Japon.", "siren": "441810603"}, {"name": "CORSICA SOLE", "description": "CORSICA SOLE est un producteur indépendant d’énergie solaire et leader du stockage d’énergie en Europe. En pleine croissance, l’entreprise compte aujourd’hui plus de 100 MWc de centrales photovoltaïques et plus de 150 MWh de centrales avec stockage d’énergie en exploitation et développe un portefeuille de projets de plus de 1,5 GW. Elle se développe aussi dans le domaine de la production d’hydrogène renouvelable. Spécialiste des zones insulaires depuis 2009, Corsica Sole développe, construit, finance, exploite ses propres projets, en France et dans l’Europe entière. Corsica Sole déploie son savoir-faire pour apporter par les énergies renouvelables et l’innovation technologique une réponse pertinente à la transition énergétique pour la lutte contre le changement climatique.", "siren": "509986030"}, {"name": "Digital4better", "description": "Data4Impact va permettre d’aider à réduire les impacts environnementaux liés à la gestion de la data d’une entreprise, de la collecte à l’usage, en passant par le calcul et le stockage. \nDigital4better est une entreprise experte des impacts environnementaux et sociaux du numérique. Au-delà de ses activités de conseil et de développement, Digital4better a conçu la plateforme Saas fruggr. Outil de pilotage dynamique de la performance numérique, l’outil permet une mesure automatisée de l’empreinte environnementale et sociale de l’IT d’une entreprise.", "siren": "884195884"}, {"name": "Aleph- Networks", "description": "Aleph souhaite rendre accessible aux TPE/PME la maîtrise de leurs risques cyber, grâce à une solution très simple d’utilisation, alliant l’intelligence artificielle à une technologie éprouvée par l’État, au service des petites entreprises. \nALEPH édite des solutions de Cyber Sûreté et d’Intelligence Stratégique pour garantir l’intégrité des individus, des entreprises et des États. Aleph propose deux solutions d’analyse des données OSINT sur les Clear, Deep & Dark Webs et d’EASM – External Attack Surface Management.", "siren": "749906525"}, {"name": "Find&Order SAS", "description": "Le projet MIPS 2 veut rendre industrialisable une solution de géolocalisation indoor fonctionnant sans infrastructure pour terminaux mobiles grand-public et professionnels. \nFind & Order est éditeur d’une solution d’optimisation de flux à destination des acteurs de la logistique et de la grande distribution. La société s’appuie sur la modélisation précise de ces bâtiments et de l’optimisation algorithmique pour augmenter l’efficacité de leurs opérations courantes.", "siren": "812982478"}, {"name": "Carthera", "description": "Avec SonALS, Carthera développe un dispositif de rupture (SonoCloud Extended) qui offre des perspectives de traitement curatif pour les patients atteints de la maladie de Charcot (SLA) \nCarthera® est une société de medtech en phase d’évaluation clinique qui développe des dispositifs médicaux innovants basés sur l’utilisation des ultrasons pour traiter un large éventail de pathologies cérébrales graves. La société a notamment conçu SonoCloud®, un implant révolutionnaire pour le traitement des cancers du cerveau et des maladies neurodégénératives.", "siren": "520004607"}, {"name": "DEKI", "description": "L’enjeu du projet e-cologistic est de créer un moteur IA de gestion et d’optimisation de livraison urbaine 100% décarbonée basé sur la réduction d’impact. \nDEKI développe des outils numériques innovants au service de la logistique urbaine au service des donneurs d’ordre et des sociétés de logistique urbaine émission de Gaz à Effet de Serre (GES), pour garantir la livraison ayant le moins d’impact.", "siren": "884747361"}, {"name": "Menta", "description": "Fruit de la recherche française, Menta est le leader mondial des eFPGA, technologie qui permet à ses clients de créer des circuits intégrés reconfigurables après production, dans le champ d’application. Menta apporte une réponse d’une extrême fiabilité à l’ensemble des acteurs de l’innovation, grâce à une technologie hautement personnalisable.", "siren": "498271907"}, {"name": "KURAGE", "description": "Kurage rétablit la mobilité des individus touchés par une perte partielle ou totale de mobilité en concevant des dispositifs qui renforcent ou substituent aux fonctions motrices du cerveau. La Solution NeuroSkin est une neuroprothèse équipée de capteurs et d’électrodes neuromusculaires, pilotée par une IA qui diagnostique puis pilote les muscles paralysés. Initialement destinée aux centres de santé, elle vise ensuite une distribution directe aux utilisateurs pour une solution adaptée.", "siren": "882480056"}, {"name": "SURGAR", "description": "SURGAR développe des logiciels d’assistance à la chirurgie coelioscopique capables d’afficher pendant la chirurgie et en temps réel la structure interne des organes en réalité augmentée. Nous proposons une solution plug&play complète composée d’une plateforme hardware associée à un software (coeur de notre technologie basée sur la vision par ordinateur et l’intelligence artificielle).", "siren": "878322155"}, {"name": "GEOVELO", "description": "Geovelo est une entreprise à mission qui développe une application de calcul d’itinéraires vélo gratuite et sans pub. \nEn complément, Geovelo développe Cycling Insights, un tableau de bord d’analyse destiné à aider les villes à concevoir de meilleurs aménagements cyclables grâce aux données des trajets provenant des 300 000 utilisateurs actifs de l’application.", "siren": "521563742"}, {"name": "Papkot", "description": "Papkot, fondé en 2020, souhaite révolutionner le domaine des emballages à usage unique en remplaçant le plastique par du papier couché et ainsi réduire l’empreinte écologique de toute une filière.", "siren": "952740355"}, {"name": "Quantiq.io", "description": "Quantiq a pour objectif de transformer tout smartphone en Dispositif Médical pour la prise de constantes physiologiques. Nos clients sont les acteurs de la télémédecine, notamment pour le suivi régulier du patient et la téléconsultation.", "siren": "881527477"}, {"name": "Nanomakers", "description": "Nanomakers est une PME qui conçoit, produit et commercialise en quantités industrielles des poudres nanométriques brevetées à base silicium : nano silicium à 40 et 75 nm, nano carbure de silicium à 35 nm. Ces nanopoudres améliorent de manière disruptive de nombreux matériaux et composants les batteries Li-ion (+20% de capacité).", "siren": "519397442"}, {"name": "IDYLLIC TECHNOLOGY", "description": "Conception de systèmes d’identification radiofréquence sans puce.", "siren": "835003971"}, {"name": "HuntX Pharma", "description": "Développement de médicaments administrables par voie orale qui réparent à la normale la fonction de gènes mutés sans toucher à l’ADN. Notre stratégie s’applique à une cinquantaine de maladies neurodégénératives génétiques aboutissant toutes à un défaut de la communication des cellules du cerveau appelé transport axonal. Notre premier médicament est développé pour la maladie de Huntington, une maladie très sévère et fatale avec un cout de prise en charge important. Notre mission est de restaurer l’espérance de vie et la qualité de vie de ces patients tout en diminuant les couts de prise en charge.", "siren": "921853990"}, {"name": "Priothera", "description": "Priothera SAS développe le mocravimod, un immuno-modulateur innovant, ayant le potentiel d’améliorer l’efficacité anti-cancéreuse des thérapies cellulaires utilisées pour traiter les cancers hématologiques (allo-HCT ou greffe de cellules CAR-T), tout en diminuant leurs effets secondaires graves, qui limitent actuellement leur utilisation et les chances de survie des patients.", "siren": "889912531"}, {"name": "AUSTRAL Dx", "description": "AUSTRAL Dx a pour ambition, grâce au dispositif médical innovant qu’elle développe, de donner à tous les patients et leurs soignants (proches ou éloignés) l’opportunité d’évaluer et de suivre de façon simple, efficace et économique leur santé cardiaque et pulmonaire. \nIl a pour premier objectif de contribuer au désengorgement des services d’urgence.", "siren": "904821485"}, {"name": "TEMO SAS", "description": "TEMO propose une gamme de moteurs électriques, portatifs et faciles d’installation pour tous types d’embarcations légères : annexes, voiliers, barques. \nFabriqués en France, dans une démarche de qualité, les moteurs TEMO sont fiables, durables et très simples d’utilisation.", "siren": "844724021"}, {"name": "Arcom", "description": "Arcom propose des solutions innovantes et sur-mesure en automatisme, régulation, pour les bâtiments, pour la gestion de l’éclairage public et la gestion de ventilation. Arcom se positionne sur le marché de l’éclairage public au travers de sa marque CITYLONE et sur le marché du smart building au travers de la marque ARCOM.", "siren": "488795345"}]$json$
  ) AS (name TEXT, description TEXT, siren TEXT)
)
INSERT INTO organizations (id, name, slug, organization_type, description, status, country, legacy_source, legacy_id, created_at, updated_at)
SELECT uuid_generate_v4(), s.name,
  lower(regexp_replace(regexp_replace(unaccent(s.name), '[^a-zA-Z0-9\s-]', '', 'g'), '\s+', '-', 'g')),
  'startup'::organization_type, s.description, 'active'::organization_status, 'France', 'inov', s.siren, NOW(), NOW()
FROM source s
ON CONFLICT (slug) DO UPDATE SET
  description = COALESCE(organizations.description, EXCLUDED.description),
  updated_at = NOW();


